INSERT INTO exercises (name, category, primary_muscles, secondary_muscles, equipment, description, instructions, is_custom)
VALUES
('Step-ups', 'strength', '{}', '{}', '{"Bench"}', 'Starting position: Stand facing a chair. Steps: - Step up onto the chair. - Step off the chair. - Repeat.', NULL, false),
('1/2 Kneeling Thoracic Rotation', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Begin in a half kneeling position with the leg away from the wall stabilized against the wall with a ball. - With both hands directly in front of you, rotate one arm open attempting to reach the wall behind you. - Exhale as you rotate, inhale as you return to neutral and repeat.', NULL, false),
('lento avanti seduto', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', 'slow controlled seated forward exercise with dumbbells', NULL, false),
('Single-arm dumbbell shoulder press', 'strength', '{"Anterior deltoid"}', '{"Rectus abdominis","Serratus anterior","Trapezius","Triceps brachii"}', '{"Dumbbell"}', 'Press the dumbbell vertically overhead in a controlled motion until your arm is fully extended, without locking the elbow. Slowly lower the dumbbell back to the starting position at shoulder height.', NULL, false),
('Kettlebell sumo high pull', 'strength', '{"Trapezius"}', '{"Anterior deltoid","Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Kettlebell"}', 'A compound exercise combining elements of a sumo deadlift and a high pull. It targets the posterior chain, particularly the glutes, hamstrings, and upper back. The sumo stance increases hip engagement, while the high pull adds an explosive element, promoting power development. - Stand upright overtop of a kettlebell with your feet wider than shoulder-width apart angled out slightly. - Maintain a braced core and neutral spine throughout the exercise. - Hinge your hips backward and extend your arms to grab ahold the kettlebell with a double overhand grip. - With you lower legs nearly vertical to the ground, extend your hips to raise the kettlebell with your elbows high keeping it close to your body. - Once the kettlebell has reached shoulder height, lower back to the starting position.', NULL, false),
('Mentzer Pulldown', 'strength', '{"Biceps brachii"}', '{"Latissimus dorsi"}', '{"Incline bench"}', 'Close grip front facing Pull down, while focusing on Biceps, Increases activation of biceps over the whole range, Avoid activating Lats.', NULL, false),
('Single-Arm Lat Pulldown', 'strength', '{"Latissimus dorsi","Trapezius"}', '{"Biceps brachii","Brachialis"}', '{}', 'Sit at the lat pulldown machine and grab the single handle with a neutral grip. Keep your torso stable, your chest lifted, and your shoulder blades slightly retracted. Start with your arm fully extended overhead, then pull the handle down toward your upper chest following a controlled, slightly diagonal path. Focus on engaging the latissimus dorsi while keeping the shoulder depressed and avoiding any torso rotation. Slowly return to the starting position, maintaining full control throughout the movement.', NULL, false),
('Single Arm Plank to Row', 'strength', '{"Anterior deltoid","Biceps brachii","Brachialis","Latissimus dorsi","Obliquus externus abdominis","Rectus abdominis","Serratus anterior"}', '{}', '{"Kettlebell"}', 'Start position as row, extend to plank and back. Finish with row and repeat', NULL, false),
('Hip Airplane', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris","Gastrocnemius","Soleus"}', '{"Kettlebell"}', 'Stand on one leg and lean your upper body slightly forward while keeping your back straight. Extend the free leg behind you so that your torso and leg form roughly one line. Slowly open your hip to the side by rotating your pelvis and upper body in a controlled way. Then close the hip again and return to the starting position. The movement should mainly come from the hip. Keep your standing foot stable and avoid letting your knee collapse inward.', NULL, false),
('Press De Banca Con Mancuernas', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{"Biceps brachii","Serratus anterior"}', '{"Bench","Dumbbell"}', '- Setup and Starting Position: Sit at the end of a flat bench with a dumbbell resting vertically against each thigh. Carefully lean back while driving the dumbbells toward your chest with your knees. - The "Leg Drive" and Posture: Plant your feet firmly on the floor. Retract your shoulder blades (press them together against the bench) and maintain a slight natural lumbar curve. - Starting Position: Push the dumbbells toward the ceiling. Your wrists should be aligned with your elbows. Rotate the dumbbells slightly inward (about 45 degrees) so that your elbows do not splay out too far to the sides, thereby protecting your shoulders. - Eccentric Phase (Lowering): Lower the dumbbells in a controlled manner toward the sides of your chest. Your elbows should lower at an angle of about 45-60 degrees relative to your body. Feel the stretch in the lower part of your chest. - Concentric Phase (Lift): Push the weight upward in a slight arc (toward the center), without letting the dumbbells collide at the top or fully locking out your elbows to maintain muscle tension. Exhale as you lift. 
('Press Inclinado Con Mancuernas', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{"Serratus anterior","Triceps brachii"}', '{"Dumbbell","Incline bench"}', 'This is a variation of the flat bench press designed to emphasize the clavicular head of the pectoralis major (the upper portion). By tilting the torso, the angle of the push changes, shifting more tension to the upper chest and shoulders, which helps achieve a more aesthetic, balanced, and three-dimensional development of the torso. - Bench Adjustment and Preparation: Set the bench to an incline of between 30 and 45 degrees (an incline greater than 45 degrees will place too much strain on the shoulders and reduce the stimulus to the chest). Sit down with a dumbbell on each thigh. - Starting position: Lean back, resting your back against the bench, while using your knees one after the other to push the dumbbells upward to shoulder height. - Anatomical Stabilization: Plant your feet firmly on the floor. Retract your scapulas (bring your shoulder blades together and press them into the bench) to protect your shoulders and stabilize the load. - Eccentric Phase (Lowering): Lower the dumbbells slowly and in a controlled manner toward the upper part of your chest. Your elbows should not splay out to the sides (90 degrees); maintain a safe angle of about 45 to 60 degrees relative to your torso. - Concentric Phase (Lift): Push the dumbbells vertically upward as you exhale. Follow a slightly converging path (without letting them touch at the top). Stop the movement just before locking out your elbows to maintain muscle tension in the upper pectoral.', NULL, false),
('Suspended crossess', 'cardio', '{"Pectoralis major"}', '{}', '{"none (bodyweight exercise)"}', 'Suspension exercise with trx for chest training', NULL, false),
('High knees', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting positionStand straight. Steps: - Run in place, putting knees as high up as is comfortable and switching legs at a quick pace.', NULL, false),
('Push-up rotations', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Get into the starting push-up position, with your hands and toes touching the ground and back, arms and legs straight. To get to this position, you can lie down on your stomach, place your hands facing down next to your head, and lifting your arms up until they are straight. Steps: - Perform a standard push-up: 1.a Bend arms until chest almost touches the ground, making sure the back is straight.1.b Use your arms to lift yourself back up to starting position. - Rotate your body to the side so that the back is straight, the bottom hand supporting the body is fully extended, and only the bottom hand and foot touch the floor. - Repeat, changing sides at step 2 each time.', NULL, false),
('Kneeling kickbacks', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Get down on all fours. Steps: - Push one foot back until fully extended, concentrating on the gluteus muscles. - Stay for one second, then return to the initial position. - Repeat, alternating feet.', NULL, false),
('Jump rope: basic jumps', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Put your feet close together, bend the knees a bit, keep your head and body straight, keep elbows in, open your arms. Steps: - Spin only your wrists with enough force to make the rope spin. - Jump just high enough to pass the rope below your feet. - Repeat. Notes: This exercise requires a jump rope. Make sure the rope length is adjusted to your height. One way to check is to grab both handles with one hand and stand on the middle of the rope hanging on the ground with one foot. If the rope (excluding the handles) reaches just below your chest, its length is right. A shorter rope would be hazardous, as you might hit yourself, and a longer rope would make for bad form.', NULL, false),
('Mountain climbers', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start in the upright push-up position, aka. the high plank position.Hands should be directly under your shoulders.Keep your head in line with your back, facing the floor.Feet should be about hip-width apart. Steps: - Move one knee toward the center of your body, towards your elbows, keeping the other leg extended. - In a quick jumping movement, straighten the bent leg out and pull the other knee toward your body. - Keep repeating step 2, alternating legs. Notes: Throughout the exercise, your back should remain as straight as possible - avoid a hump or a sagging back.', NULL, false),
('4-count burpees', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand straight, feet hip-width apart. Steps: - Squat low and support yourself on the floor with your hands between the knees and in front of your feet, your back straight. - Keeping your hands on the floor, jump your legs backward into high plank position. - Jump your feet forward to return to the squat position. - Repeat.', NULL, false),
('Axe Hold', 'strength', '{}', '{}', '{"Dumbbell"}', 'Grab dumbbells and extend arms to side and hold as long as you can', NULL, false),
('Tricep Pushdown on Cable', 'strength', '{"Triceps brachii"}', '{}', '{}', 'The cable rope push-down is a popular exercise targeting the triceps muscles. It''s easy to learn and perform, making it a favorite for everyone from beginners to advanced lifters. It is usually performed for moderate to high reps, such as 8-12 reps or more per set, as part of an upper-body or arm-focused workout.', NULL, false),
('commando pull-ups', 'strength', '{"Anterior deltoid","Biceps brachii","Latissimus dorsi","Trapezius"}', '{}', '{"Pull-up bar"}', 'variation of the pull-up exercise, it is performed with a grip of one hand supine and one hand prone, do not twist the torso to get back to the front, the head passes once to one side, once to the other.', NULL, false),
('Fingerboard 20 mm edge', 'strength', '{}', '{}', '{}', 'Hang for 10 seconds on a fingerboard with a 20 mm edge', NULL, false),
('Incline Bench Reverse Fly', 'strength', '{"Anterior deltoid","Trapezius"}', '{}', '{"Dumbbell"}', 'The incline dumbbell reverse fly is an upper-body exercise targeting the posterior or rear deltoids, as well as the postural muscles of the upper back. Because it targets such small muscles, this exercise is usually performed with light weight for high reps, such as 10-15 reps per set or more.', NULL, false),
('Handstand Push Up', 'strength', '{"Anterior deltoid","Triceps brachii"}', '{"Pectoralis major"}', '{}', 'Handstands Push Up which demand high level of skill', NULL, false),
('Zone 2 Running', 'cardio', '{}', '{}', '{}', 'Zone two Cardio for endurance, you should be able to speak while running', NULL, false),
('LYING DUMBBELL ROW SS SEATED SHRUG', 'strength', '{"Latissimus dorsi"}', '{}', '{"Dumbbell"}', 'laying on the stomach on a bench with slight angle', NULL, false),
('Biceps with TRX', 'strength', '{"Biceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Grab the handles of the TRX straps, lean your body back, arms and legs extended, with your body positioned in a single straight line. (This is an arm exercise, not an abdominal one.)', NULL, false),
('Kettlebell Swing', 'strength', '{"Anterior deltoid","Gluteus maximus"}', '{"Quadriceps femoris","Rectus abdominis","Trapezius"}', '{"Kettlebell"}', 'While kettlebell swings are a full-body workout, they mostly target the muscles along the posterior chain (back of the body). The main muscles used are the glutes, hamstrings, spinal erectors, and muscles of the upper back.', NULL, false),
('Swimming 50m sprints', 'cardio', '{}', '{}', '{}', '50m swimming sprints at 1min', NULL, false),
('Bear Walk 2', 'strength', '{"Anterior deltoid","Gastrocnemius","Pectoralis major","Rectus abdominis","Serratus anterior","Soleus","Triceps brachii"}', '{"Gluteus maximus","Latissimus dorsi","Obliquus externus abdominis","Quadriceps femoris","Trapezius"}', '{"none (bodyweight exercise)"}', '-Rest your weight on your palms and the balls of your feet, not dissimilar to normal pushup position -Move by stepping with your R palm and L foot, then your L palm and R foot. Basically, walk like a lumbering bear. -Move as fast as you can. Measure your reps/sets in either distance (i.e. 40 yards) or time (i.e. 45 seconds) -Works your Pecs, Deltoids, Triceps, Traps, Lats, Abs and Lower Back, Hip Flexors, Quads, Glutes and Calves', NULL, false),
('one-handed kettlebell curls', 'strength', '{"Biceps brachii"}', '{}', '{"Kettlebell"}', 'Standing with the kettlebell in one hand and bent at the elbow, start from a fully extended position until your hand reaches shoulder height. To perform the movement correctly, try not to push with your back or body.', NULL, false),
('Medicine ball booklet crunch', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Using a medicine ball as an overload will make the exercise heavier.', NULL, false),
('Box squat', 'strength', '{"Gluteus maximus","Quadriceps femoris","Soleus"}', '{}', '{"none (bodyweight exercise)"}', '- Set up the box: Position the box behind you, about 3 feet from a squat rack if you''re using a barbell. Choose a height that allows you to squat down and gently tap your glutes on the box with your back straight. - Stand with proper form: Stand with your feet shoulder-width apart, toes pointed slightly outward. Engage your core and keep your back neutral. If using a barbell, rack it at shoulder height. - Lower down: Sit back as if going to sit on a chair, bending your knees and lowering your hips towards the box. Keep your core tight and back straight throughout the movement. - Controlled descent: Descend in a controlled manner until your glutes gently touch the box. Don''t plop down. - Pause and press up: Briefly pause at the bottom with your back straight and core engaged. Then, press through your heels to drive yourself back up to the starting position. Improvements in coordination, balance and endurance, toning of the leg and buttock muscles and an overall increase in bone density eliminating the risk of osteoporosis.', NULL, false),
('Knee Raises', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"Pull-up bar"}', 'The 90 degrees leg raise on the bar is a very intense exercise that involves all the abdominal muscles.', NULL, false),
('Sloper hanging', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Hanging on sloper holds of a fingerboard for a amount of seconds', NULL, false),
('Barbell Ab Rollout', 'strength', '{"Obliquus externus abdominis"}', '{}', '{"Barbell"}', 'Place a barbell on the floor at your feet. Bending at the waist, grip the barbell with a shoulder with overhand grip. With a slow controlled motion, roll the bar out so that your back is straight. Roll back up raising your hips and butt as you return to the starting position.', NULL, false),
('Elliptical', 'cardio', '{"Gluteus maximus","Quadriceps femoris","Trapezius"}', '{"Biceps brachii","Rectus abdominis","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'It improves muscle toning, strengthens the leg muscles (quads, glutes, calves), helps vascularisation and increases resistance. The elliptical is also very useful if you aim to lose weight. Teste', NULL, false),
('Pullup on fingerboard', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Pullup on a choosen edge of a fingerboard / hangboard', NULL, false),
('Reverse Nordic Curl', 'strength', '{"Quadriceps femoris"}', '{"Gluteus maximus","Rectus abdominis"}', '{}', 'Natural Leg Extension is alternative to Leg Extension machine with no equipment.', NULL, false),
('Straight Bar Cable Curls', 'strength', '{"Biceps brachii"}', '{}', '{}', 'Standing upright in front of Cable Tower using a straight bar', NULL, false),
('Cable Fly', 'strength', '{"Pectoralis major"}', '{}', '{}', 'cable machine, two steps forward, straight back', NULL, false),
('TRX Rows', 'strength', '{"Anterior deltoid","Biceps brachii","Latissimus dorsi"}', '{}', '{"none (bodyweight exercise)"}', 'This exercise serves as a lead-up to Pull Ups.', NULL, false),
('Leg raises pull up bar', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis","Quadriceps femoris"}', '{"Pull-up bar"}', 'with a firm grip with both hands on the bar, raise your outstretched legs, until you reach a 90 degrees angle with your torso.', NULL, false),
('Body-Ups', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position. - Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement. - Slowly lower your forearms back to the ground by allowing the elbows to flex. - Repeat as needed.', NULL, false),
('Bent High Pulls', 'strength', '{"Trapezius"}', '{}', '{"Dumbbell"}', 'Bend over slightly while holding two dumbbells. Pull the dumbbells up to your chest, keeping your elbows as high as you can.', NULL, false),
('Blaze', 'cardio', '{"Anterior deltoid","Gluteus maximus","Pectoralis major","Quadriceps femoris"}', '{"Biceps brachii","Biceps femoris","Latissimus dorsi","Rectus abdominis"}', '{"Bench","Dumbbell","Kettlebell","none (bodyweight exercise)"}', 'BLAZE is a full-body HIIT workout. Designed to supercharge your cardio fitness and strength. Delivered in its own purpose-built studio, BLAZE is a unique mix of martial arts, intense cardio and strength training.', NULL, false),
('Single-arm cable pushdown', 'strength', '{"Triceps brachii"}', '{"Rectus abdominis"}', '{}', 'Single-arm cable pushdown is a unilateral isolation exercise that targets the triceps brachii. By working one arm at a time, it helps correct strength imbalances between sides while also engaging the core for stability. Starting position: Stand facing the cable machine with your feet shoulder-width apart. Attach a single handle to the high pulley. Grab the handle with one hand using an overhand grip (pronated), with your elbow bent at approximately 90 degrees and tucked close to your body. Keep your core braced and your back straight. Execution: Push the handle downward in a controlled motion by extending your elbow until your arm is fully extended. Hold the contraction for 1 second at the bottom, then slowly return to the starting position.', NULL, false),
('Reverse Clamshell', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'Lie on your side with your hips and knees bent, keeping your knees stacked on top of each other. Keep your feet together at first, then keep your knees touching while lifting your top foot upward. Slowly lower the foot back down with control. Move only through the hip and avoid rolling your pelvis backward. The movement should be small, controlled, and focused on hip rotation.', NULL, false),
('No push-up burpees', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand straight, feet hip-width apart. Steps: - Squat low and support yourself on the floor with your hands between the knees and in front of your feet, your back straight. - Keeping your hands on the floor, jump your legs backward into high plank position. - Jump your feet forward to return to the squat position. - Jump up. - Repeat.', NULL, false),
('Floor dips', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit with your arms behind you, supporting your back.Your fingers should point forward.Your knees should be bent, feet together. Steps: - Raise your hips off the ground, straightening your arms. - Bend your elbows, bringing your hips down. - Straighten your arms, returning to the previous position. - Repeat steps 2 and 3. Notes: The exercise''s difficulty depends on how high you bring your hips.', NULL, false),
('Child''s pose', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start on all fours, knees, toes, and hands touching the ground. Your two big toes should be touching. Steps: - Move your knees so that they''re about hip-width apart. - On an exhale, move your pelvis back to sit on your heels. Your hands should still be touching the ground. - Relax your upper body, lowering your forehead to the floor and letting your hands move forward naturally. - Stay in this pose. Tips: - To leave the pose, walk your arms back under your shoulders and move your upper body up into a seated position.', NULL, false),
('Kettlebell deadlifts', 'strength', '{}', '{}', '{"Kettlebell"}', 'Starting position: Stand hip-width apart, with your kettlebell centered between your ankles. Your back should be straight, your head facing forward. Steps: - Hinge at the hips and slightly bend at the knees to put your hands on the kettlebell handles. Your back should be straight as you perform the movement. - Grab the kettlebell handles, with your hands pushing in opposite directions as if to pull the handle apart. - While contacting your abs and glutes, stand straight up. - Hinge at the hips again to bring the kettlebell back down, similarly to step 1. - Repeat from step 3. Tips: - Be sure you''re performing the movements correctly, as doing otherwise can lead to injury. For example, do not squat instead of hinging at the hips, do not round your back while reaching for the kettlebell, and do not lean back while standing up.', NULL, false),
('Chin tuck', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Use fingers on your chin to slowly tuck your chin in, moving your head back to align it with your spine. - Hold for 5 seconds. - Go back to normal head position and repeat.', NULL, false),
('Head turns', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight and shoulders down. Steps: - Sit or stand up straight, shoulders dropped. - Turn your head to the side as far as possible. Stop when you hit a barrier and hold for 5 seconds. - Return to center position and repeat, changing sides.', NULL, false),
('Back neck stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit upright on a chair or a firm pillow. Steps: - Breathe out and tilt your head forward, chin to chest, putting hands behind your head. - Use your hands to pull your head down lightly and press against your hands with your head to balance out the force. - Hold for a bit. - Relax your arms and head, opening up a bit with your shoulders. - Keep repeating this from step 2 onward.', NULL, false),
('Alternating bicep curls', 'strength', '{}', '{}', '{"Dumbbell"}', 'Starting position: Start standing up with dumbbells in each hand, your back straight and feet hip-width apart. Your arms should be relaxed, pointing down. Your knees should be slightly bent, your abs contracted, and your shoulders down. Steps: - Bend one arm at the elbow, bringing the dumbbell up to your shoulder. Your upper arm should remain motionless during this movement. - Bring the dumbbell back down until your arm is in its original relaxed position. - Repeat, switching arms.', NULL, false),
('Head tilts', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Tilt your head to one side and hold for a bit.2.Return your head to neutral position and hold for a bit. - Tilt your head to the other side and hold for a bit. - Return your head to neutral position yet again and hold for a bit. - Repeat.', NULL, false),
('Barbell Lunges Walking', 'strength', '{}', '{}', '{"Barbell"}', NULL, NULL, false),
('Lunges', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand with back straight. Steps: - Take a large step forward with your left leg. - Bring your pelvis down until you almost touch the floor with your right knee. - Bring your pelvis back up. - Return to the starting position by stepping back. - Repeat, switching legs each time.', NULL, false),
('Side split squats left', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: - Stand tall and take a wide lateral stride, just greater than shoulder width. Steps: - Bend one knee until your thigh is parallel to the floor. The bent knee must be in line with the foot. - Push back to the starting position. - Repeat.', NULL, false),
('Side split squats right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: - Stand tall and take a wide lateral stride, just greater than shoulder width. Steps: - Bend one knee until your thigh is parallel to the floor. The bent knee must be in line with the foot. - Push back to the starting position. - Repeat.', NULL, false),
('Bulgarian split squats left', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Stand tall in front of a chair and take a large step. Put the upper part of one of your feet on the chair. - Bend the front knee, balancing with arms until the back knee almost touches the ground. - Push back to the starting position and repeat.', NULL, false),
('Bulgarian split squats right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Stand tall in front of a chair and take a large step. Put the upper part of one of your feet on the chair. - Bend the front knee, balancing with arms until the back knee almost touches the ground. - Push back to the starting position and repeat.', NULL, false),
('Split squats left', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand with your back straight. Take a large step forward with your left leg. Steps: - Bring your pelvis down until you almost touch the floor with your right knee. - Bring your pelvis back up. - Repeat.', NULL, false),
('Split squats right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand with your back straight. Take a large step forward with your right leg. Steps: - Bring your pelvis down until you almost touch the floor with your left knee. - Bring your pelvis back up. - Repeat.', NULL, false),
('Forward arm circles', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand tall with your back straight. Steps: - Keeping your arms straight, bring them in front of you, move them down, behind your back, then over your head, and back to the initial position. - Keep circling your arms as described in step 1.', NULL, false),
('Backward arm circles', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand tall with your back straight. Steps: - Keeping your arms straight, bring them in front of you, raise them over your head, then continue the motion behind your back and down to the initial position. - Keep circling your arms as described in step 1.', NULL, false),
('Reverse lunges', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand straight, feet hip-width apart. Steps: - Step backward with one leg so it can bend comfortably to a 90 degree angle. - Slowly bend both knees to form 90 degree angles. - Return to the starting position. - Repeat, alternating legs.', NULL, false),
('High plank', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Get into the high plank position:your hands and toes should be touching the ground, your back, arms and legs should be straight.To get to this position, you can lie down on your stomach, place your hands facing down next to your head, and lifting your arms up until they are straight. Steps: - Maintain the starting position for the entire duration of the exercise.', NULL, false),
('Forward shoulder rotation', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Place your hands on your shoulders. - Repeatedly rotate both shoulder joints in a circular motion at a moderate pace.', NULL, false),
('Backward shoulder rotation', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Place your hands on your shoulders. - Repeatedly rotate both shoulder joints in a circular motion at a moderate pace.', NULL, false),
('Left neck stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Tilt your head to the side. - Take the hand closer to your head and use it to grab your head from the other side. - Push with your hand against your head and with your head against your hand so that the forces balance out and your head stays still. - Maintain this tension until the end of the exercise.', NULL, false),
('Right neck stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Tilt your head to the side. - Take the hand closer to your head and use it to grab your head from the other side. - Push with your hand against your head and with your head against your hand so that the forces balance out and your head stays still. - Maintain this tension until the end of the exercise.', NULL, false),
('Left levator scapulae stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start standing up or sitting down. Turn your head to the left, around 45 degrees or just above your nipple. Place your right hand behind your back or sit on it. Take your left hand and use it to hold the back of your head. Lean your head down slightly. Steps: - After assuming the starting position, press your head against your left hand with slight force. Your hand should press back with equal force, so that your head doesn''t move. Hold this position.', NULL, false),
('Right levator scapulae stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start standing up or sitting down. Turn your head to the right, around 45 degrees or just above your nipple. Place your left hand behind your back or sit on it. Take your right hand and use it to hold the back of your head. Lean your head down slightly. Steps: - After assuming the starting position, press your head against your right hand with slight force. Your hand should press back with equal force, so that your head doesn''t move. Hold this position.', NULL, false),
('Nordic Curl', 'strength', '{"Biceps femoris"}', '{"Gluteus maximus"}', '{}', 'The Nordic hamstring curl is one of the best lower-body exercises to build posterior leg strength, improve knee health, and prevent injury.', NULL, false),
('Reverse Preacher Curl (Close Grip)', 'strength', '{"Biceps brachii"}', '{}', '{"SZ-Bar"}', 'Sitting reverse on a Biceps Bench with a close grip', NULL, false),
('SMITH MACHINE SLIGHT INCLINE PRESS', 'strength', '{"Pectoralis major"}', '{}', '{}', 'laying under smith machine, with slight incline', NULL, false),
('Chin-ups', 'strength', '{"Latissimus dorsi"}', '{}', '{"Pull-up bar"}', 'The chin-up (also known as a chin or chinup) is a strength training exercise. People frequently do this exercise with the intention of strengthening muscles such as the latissimus dorsi and biceps, which extend the shoulder and flex the elbow, respectively. In this maneuver, the palms are faced towards the body. It is a form of pull-up in which the range of motion is established in relation to a person''s chin.', NULL, false),
('Burpees', 'strength', '{}', '{}', '{}', 'Jump, lay down on your chest, do a pushup then jump, repeat', NULL, false),
('Chest Press', 'strength', '{"Pectoralis major"}', '{}', '{}', NULL, NULL, false),
('Cross-Bench Dumbbell Pullovers', 'strength', '{"Latissimus dorsi","Pectoralis major","Serratus anterior"}', '{}', '{"Dumbbell"}', 'Grasp a moderately weighted dumbbell so your palms are flat against the underside of the top plates and your thumbs are around the bar. Lie on your back across a flat bench so only your upper back and shoulders are in contact with the bench. Your feet should be set about shoulder-width apart and your head should hang slightly downward. With the dumbbell supported at arm''s length directly about your chest, bend your arms about 15 degrees and keep them bent throughout the movement. Slowly lower the dumbbell backward and downward in a semicircle arc to as low a position as is comfortably possible. Raise it slowly back along the same arc to the starting point, and repeat for the required number of repetitions.', NULL, false),
('Deadhang', 'strength', '{}', '{}', '{}', 'Deadhang performed on an edge either with or without added weight (adujst edge or weight to adjust difficulty)', NULL, false),
('Cycling', 'cardio', '{"Obliquus externus abdominis","Trapezius"}', '{"Biceps femoris","Brachialis","Gluteus maximus","Latissimus dorsi","Quadriceps femoris"}', '{"none (bodyweight exercise)"}', 'Cycling, also called bicycling or biking, is the use of bicycles for transport, recreation, exercise or sport. People engaged in cycling are referred to as cyclists, bicyclists, or bikers. Apart from two-wheeled bicycles, cycling also includes the riding of unicycles, tricycles, quadracycles, recumbent and similar human-powered vehicles.', NULL, false),
('Cable Woodchoppers', 'strength', '{"Obliquus externus abdominis"}', '{}', '{}', 'Set cable pulley slightly lower than chest height. Keep body facing forward with hips stable. Grab the pulley handle, fully extend your arms and bring your arms forward and across your body. Hold for 1 second at the end of the movement and slowly return to starting position.', NULL, false),
('Deadbug', 'strength', '{}', '{}', '{}', 'Lie on your back, with your hips and knees bent to 90 degrees. Raise both arms toward the ceiling. Pull your lower back to the floor to eliminate the gap. Start by pressing one leg out, and tapping the heel to the floor. "As you extend one leg, exhale as much as you can, keeping your lower back glued to the floor," Dunham says. When you can't exhale any more, pull your knee back to the starting position. Make this more difficult by holding weight in your hands, or by lowering opposite arm and leg.', NULL, false),
('Chin Up', 'strength', '{}', '{}', '{"Pull-up bar"}', 'The chin-up (also known as a chin or chinup) is a strength training exercise. People frequently do this exercise with the intention of strengthening muscles such as the latissimus dorsi and biceps, which extend the shoulder and flex the elbow, respectively. In this maneuver, the palms are faced towards the body. It is a form of pull-up in which the range of motion is established in relation to a person''s chin.', NULL, false),
('Facepull', 'strength', '{"Trapezius"}', '{}', '{}', 'Attach a rope to a pulley station set at about chest level. Step back so you''re supporting the weight with arms completely outstretched and assume a staggered (one foot forward) stance. Bend the knees slightly for a stable base. Retract the scapulae (squeeze your partner''s finger with your shoulder blades) and pull the center of the rope slightly up towards the face. A good cue is to think about pulling the ends of the rope apart, not just pulling back. As you near your face, externally rotate so your knuckles are facing the ceiling. Hold for one second at the top position and slowly lower.', NULL, false),
('Reverse EZ Bar Cable Curls', 'strength', '{"Biceps brachii"}', '{}', '{"SZ-Bar"}', 'Standing in front of cable tower using a SZ Bar', NULL, false),
('Machine chest fly', 'strength', '{"Pectoralis major"}', '{}', '{}', 'seated machine, straight back, slow exercise', NULL, false),
('Dumbbells on Scott Machine', 'strength', '{"Biceps brachii"}', '{}', '{}', NULL, NULL, false),
('Hyperextensions', 'strength', '{"Trapezius"}', '{}', '{}', 'Lie on the hyperextension pillow with your navel at the front edge, allowing your upper body to hang freely. Tighten all your back muscles and raise your torso until you''re horizontal, but no higher. Lower yourself slowly, maintaining a steady flow of muscles.', NULL, false),
('High Knee Jumps', 'cardio', '{"Biceps femoris","Gastrocnemius","Quadriceps femoris","Soleus"}', '{"Obliquus externus abdominis","Rectus abdominis","Serratus anterior"}', '{}', '- Start with legs slightly wider than shoulder width - Drop into a bodyweight squat - As you hit the bottom of the squat, explode upwards into a jump while simultaneously tucking your knees into your chest midflight. Remain tucked until the apex of your jump. - Land on both feet, making sure your knees are not locked so as to avoid excessive strain upon your joints. Collect yourself into the next rep as quickly but under control as possible.', NULL, false),
('Barbell Hip Thrust', 'strength', '{"Gluteus maximus"}', '{}', '{"Barbell"}', 'Sit on the ground with a bench behind you, bending your knees so your feet are planted on the ground and holding a barbell resting below your hips. If you have a padded bar, or anything you can slip in between the bar and your body, it will go a long way to making the exercise more comfortable.', NULL, false),
('BUS DRIVERS', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Sitting with a Weight Plate, used as wheel, in both hands; raised slightly below eye level', NULL, false),
('Hand Grip', 'strength', '{}', '{}', '{}', 'chrome Hand Flex Grip to build up forearms muscles', NULL, false),
('Hip Raise, Lying', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Lying down on your back, with your feet flat on the floor. Raise your hips up evenly as high as you can and hold for as long as you can.', NULL, false),
('Hercules Pillars', 'strength', '{"Biceps brachii","Brachialis","Triceps brachii"}', '{"Anterior deltoid"}', '{}', 'Grab two cables stand in the middle so both have tension and hold', NULL, false),
('Hip Thrust', 'strength', '{"Gluteus maximus"}', '{}', '{"Barbell","Bench"}', 'The bar should go directly on your upper thigh, directly below your crotch. Your feet should be directly under your knees. Push your hips up so that you form a straight line from your knees to your shoulders. Use a pad for comfort.', NULL, false),
('High Pull', 'strength', '{"Anterior deltoid"}', '{"Gluteus maximus"}', '{}', 'Use a light barbell, perform explosive lift up starting from underneath knee cap level. Lift/raise explosively using hips, at shoulder level. Tempo: 2111', NULL, false),
('Hollow Hold', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"Gym mat","none (bodyweight exercise)"}', 'Get on a mat and lie on your back. Contract your abs, stretch your arms and legs and raise them (your head and shoulders are also be raised). Make sure your lower back remains in contact with the mat.', NULL, false),
('Clamshell to Reverse Clamshell', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'Lie on your side with your hips and knees bent, keeping your legs stacked. Lift your top knee into a clamshell position and keep the leg elevated throughout the movement. From there, alternate between opening the knee upward and lifting the foot upward, moving through hip external and internal rotation. Keep the movement slow and controlled. Do not let the top leg rest on the bottom leg between repetitions.', NULL, false),
('Clockwise neck circles', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start sitting or standing. Drop your head down, bringing your chin toward your chest, but not pushing. Steps: In a slower fluid motion and with your head relaxed and not pushing in any direction: - lean toward your right shoulder. - then bring your head back, facing up. - then lean toward your left shoulder.4.and back toward the starting position. Keep repeating this as part of one slower fluid motion.', NULL, false),
('Counterclockwise neck circles', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start sitting or standing. Drop your head down, bringing your chin toward your chest, but not pushing. Steps: In a slower fluid motion and with your head relaxed and not pushing in any direction: - lean toward your left shoulder. - then bring your head back, facing up. - then lean toward your right shoulder.4.and back toward the starting position. Keep repeating this as part of one slower fluid motion.', NULL, false),
('Neck half circles', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start sitting or standing. Lean your head against one of your shoulders, but don''t push. Steps: In one slower fluid motion and with your head relaxed and not pushing in any direction: - bring your head down toward your chest. - then lean back aganst your other shoulder. - then back toward the chest again.4.and finally toward the starting position. Keep repeating this.', NULL, false),
('Side plank right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Lie down on your side, with your bottom elbow at a right angle, arm sticking out. Lift your pelvis off the floor by lifting your bottom shoulder up, keeping the forearm on the floor; your head, pelvis, and feet should be in a straight line. Steps: - Hold this position.', NULL, false),
('Pistol squats right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Stand on one leg, with your other leg straight and slightly forward. - Bend one knee slowly, descending into a squat and keeping your back and your other leg straight. - Slowly raise yourself from the squat, straightening the bent knee and keeping the other leg straight. - Repeat.', NULL, false),
('Calf raises, right leg', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Stand on the floor or on the edge of a step to increase the range of movement. - Raise one foot. - Lift your heel until you''re standing on your toes. - (variable) Stay in this position for three seconds - Slowly lower your foot until you almost touch the ground with your heel - don''t slam your foot!', NULL, false),
('Rope Pullover/row', 'strength', '{"Latissimus dorsi"}', '{}', '{"Incline bench"}', 'Set up bench in front of cable row machine. Lean over bench to do a row/pullover with rope that targets lats. See picture.', NULL, false),
('Single arm row', 'strength', '{"Latissimus dorsi"}', '{}', '{"Incline bench"}', 'Sitting on the ground, use a high cable in a single grip, to do lat pulldowns with a focus on a long stretch in the lats.', NULL, false),
('Barbell Clean and press', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{}', '{"Dumbbell"}', 'This exercise involves lifting a barbell from the ground to the shoulders, then pressing it overhead. It is a compound movement that targets multiple muscle groups, including the legs, back, shoulders, and arms. It is often used in strength and conditioning programs to improve overall power and athleticism.', NULL, false),
('Incline Dumbbell Row', 'strength', '{}', '{"Latissimus dorsi"}', '{"Dumbbell","Incline bench"}', '- Using a neutral grip, lean into an incline bench. - Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position. - Retract the shoulder blades and flex the elbows to row the dumbbells to your side. - Pause at the top of the motion, and then return to the starting position.', NULL, false),
('Good Mornings', 'strength', '{"Biceps femoris"}', '{}', '{}', NULL, NULL, false),
('Front Plate Raise', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'The plate front raise is a variation of the dumbbell front raise where the lifter holds a weight plate between two hands, rather than using a dumbbell, barbell, or other weight. It can provide variety in a shoulder-focused muscle-building workout, or as part of an upper body or full-body circuit. - While standing straight, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended and locked with a slight bend at the elbows and the plate should be down near your waist in front of you as far as you can go. Tip: The arms will remain in this position throughout the exercise. This will be your starting position. - Slowly raise the plate as you exhale until it is a little above shoulder level. Hold the contraction for a second. As you inhale, slowly lower the plate back down to the starting position. - Repeat for the recommended amount of repetitions.', NULL, false),
('Smith Press', 'strength', '{"Anterior deltoid"}', '{}', '{"Incline bench"}', 'Sitting almost 90 degree angle, smith machine', NULL, false),
('Isometric Wipers', 'strength', '{"Pectoralis major"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Assume push-up position, with hands slightly wider than shoulder width. Shift body weight as far as possible to one side, allowing the elbow on that side to flex. Reverse the motion, moving completely over to the other side. Return to the starting position, and repeat for the desired number of repetitions.', NULL, false),
('Jumping Jacks', 'strength', '{"Quadriceps femoris"}', '{}', '{}', 'A jumping jack or star jump, also called side-straddle hop in the US military, is a physical jumping exercise performed by jumping to a position with the legs spread wide and the hands going overhead, sometimes in a clap, and then returning to a position with the feet together and the arms at the sides', NULL, false),
('Landmine press', 'strength', '{"Anterior deltoid"}', '{"Pectoralis major","Triceps brachii"}', '{"Barbell"}', NULL, NULL, false),
('Cable Cross-over', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{}', 'Begin with cables at about shoulder height, one in each hand. Take a step forward so that one foot is in front of the other, for stability, and so that there is tension on the cables. Bring hands together in front of you. Try to make your hands overlap (so that the cables cross) a few inches.', NULL, false),
('Jogging', 'cardio', '{}', '{}', '{}', 'Get your shoes on, go outside and start running at a moderate pace.', NULL, false),
('Long-Pulley, Narrow', 'strength', '{"Latissimus dorsi"}', '{"Biceps brachii","Brachialis"}', '{}', 'The exercise is the same as the regular long pulley, but with a narrow grip: Sit down, put your feet on the supporting points and grab the bar with a wide grip. Pull the weight with a rapid movement towards your belly button, not upper. Keep your arms and elbows during the movement close to your body. Your shoulders are pulled together. Let the weight slowly down till your arms are completely stretched.', NULL, false),
('Straight Bar Cable Front Raise', 'strength', '{"Anterior deltoid"}', '{}', '{"SZ-Bar"}', 'Back to cable tower, cable between legs, SZ Bar', NULL, false),
('Quadriped Arm and Leg Raise', 'strength', '{"Anterior deltoid","Gluteus maximus","Serratus anterior","Trapezius"}', '{"Latissimus dorsi"}', '{"none (bodyweight exercise)"}', 'In this exercise, the back muscles and the muscles of the back of the leg and back of the arm are activated by lifting the crossed arm and leg at the same time in the crawling position. It also improves balance and proprioception. The movement is done symmetrically. - Get into a crawling posture.2. Draw your abdomen in, then raise your right leg and left arm.3. You should keep your abdomen in for 8 seconds.4. After 8 seconds, slowly lower your arm and leg.5. Then release your muscle.', NULL, false),
('Long-Pulley (low Row)', 'strength', '{"Latissimus dorsi"}', '{"Biceps brachii","Brachialis"}', '{}', 'Sit down, put your feet on the supporting points and grab the bar with a wide grip. Pull the weight with a rapid movement towards your belly button, not upper. Keep your arms and elbows during the movement close to your body. Your shoulders are pulled together. Let the weight slowly down till your arms are completely stretched.', NULL, false),
('Lying Rotator Cuff Exercise', 'strength', '{}', '{}', '{"Dumbbell"}', 'This is an excercise for problems with the rotator cuff. Primary Infraspinatus, secondary Teres Minor. Lying on side. Keep elbow on waist and in 90 dgr angle. Rotate towards stomach. Add weight as fit.', NULL, false),
('Muscle up', 'strength', '{"Biceps brachii","Biceps femoris"}', '{}', '{"Pull-up bar"}', 'The body is then explosively pulled up by the arms in a radial pull-up, with greater speed than a regular pull-up. When the bar approaches the upper chest, the wrists are swiftly flexed to bring the forearms above the bar. The body is leaned forward, and the elbows are straightened by activating the triceps. The routine is considered complete when the bar is at the level of the waist and the arms are fully straight. To dismount, the arms are bent at the elbow, and the body is lowered to the floor, and the exercise can be repeated. As a relatively advanced exercise, muscle-ups are typically first learned with an assistive kip. The legs swing (kip) up and provide momentum to assist in the explosive upward force needed to ascend above the bar. More advanced athletes can perform a strict variation of the muscle-up which is done slowly, without any kip. This variation begins with a still dead hang and uses isometric muscle contraction to ascend above the bar in a slow, controlled fashion.', NULL, false),
('L Hold', 'strength', '{}', '{}', '{}', 'Hold the L position for as long as possible', NULL, false),
('Prone Scapular Retraction - Arms at Side', 'strength', '{"Trapezius"}', '{}', '{}', 'Lying on stomach with head on towel. Stretch arms straight out to your sides. Slowly lift your arms, pulling your shoulderblades together, hold for 3 seconds.', NULL, false),
('Pike Push Ups', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"none (bodyweight exercise)"}', 'Push Up performed from a pike position (optional to have feet elevated).', NULL, false),
('Seated Dumbbell Side Lateral', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', 'seated slightly leaned forward at beginning of exercise', NULL, false),
('Overhand Cable Curl', 'strength', '{"Biceps brachii"}', '{}', '{}', 'Hands at shoulder height, curl arms in toward head, then back out.', NULL, false),
('Reverse Curl', 'strength', '{"Biceps brachii","Brachialis"}', '{"Biceps brachii"}', '{"Barbell","Dumbbell"}', 'The reverse-grip barbell curl is a variation on the biceps curl where the palms face downward. The switch from an underhand to an overhand grip brings the forearm and brachialis muscles more into the exercise.', NULL, false),
('T-Bar row', 'strength', '{"Latissimus dorsi","Trapezius"}', '{}', '{"Barbell"}', 'bent over with triangle grip, slightly bent knees', NULL, false),
('Front Wood Chop', 'strength', '{}', '{}', '{}', NULL, NULL, false),
('Roman Chair Crunch', 'strength', '{}', '{}', '{}', 'Crunches on roman chair. Keep your torso straight, abs tight, and don''t come up all the way vertical or lie flat to keep constant tension on your abs.', NULL, false),
('Modified pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{"Incline bench"}', 'With an inclined bench in front of the pulldown machine, use a close-grip to do latfocused pulldowns.', NULL, false),
('Quadruped thoracic rotation right', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start kneeling on all fours, knees shoulder-width apart. Place your right hand behind your head while keeping your left hand outstretched and touching the floor. Steps: - On inhale, move your right elbow toward your left hand, keeping your right hand behind your head. - On exhale, move your right elbow to point up toward the ceiling. - Repeat.', NULL, false),
('Dumbbell Bent Over Face Pull', 'strength', '{"Anterior deltoid","Latissimus dorsi"}', '{"Trapezius"}', '{"Dumbbell"}', 'This exercise involves using dumbbells to perform a bent over face pull, which targets the upper back and shoulders. The movement involves pulling the weights towards the face while keeping the elbows high and squeezing the shoulder blades together.', NULL, false),
('Curl with kettlebell two hands', 'strength', '{"Biceps brachii"}', '{}', '{"Kettlebell"}', 'Stand upright and grip the kettlebell with both hands. Perform the elbow flexion motion, starting from a fully extended position until your hand reaches shoulder height. Spread your legs a little for stability and, to perform the exercise correctly, try not to push with your back or body in general. Change the weight of the kettlebell to adjust the difficulty.', NULL, false),
('Doorway Pectoral Stretch', 'strength', '{"Pectoralis major"}', '{}', '{"none (bodyweight exercise)"}', '- Place the forearm vertically on a door frame or stationary object at head height - Step forward past the arm, keeping it still against the object to stretch the chest', NULL, false),
('Run', 'cardio', '{}', '{}', '{}', 'Running or jogging outside in a park, on the tracks,...', NULL, false),
('Incline Bench Press - MP', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{}', NULL, NULL, false),
('Reverse Plank', 'strength', '{}', '{}', '{}', 'Plank with stomach towards ceiling', NULL, false),
('Side Dumbbell Trunk Flexion', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"Dumbbell"}', 'AKA dumbbell side bends. Stand in line with the hips with slightly bent knees, maintain the natural curvature of the spine, hand stretched by the body, grip the barbell with one hand. Make slow and controlled torso side flexions till you reach the angle of approximately 45 degrees.', NULL, false),
('Side-lying External Rotation', 'strength', '{}', '{}', '{}', 'With a weight in one hand, lie on your side opposite the weight. Keep your knees slightly bent. Hold your elbow against your side, and extend your upper arm straight ahead of you. While continuing to hold your elbow against your side, rotate your upper arm 90 degrees upwards. It is helpful to place a towel under your armpit to help with the form on this exercise. Placing a support under your head for the duration of the exercise is also a good idea.', NULL, false),
('Skipping - Standard', 'cardio', '{"Gastrocnemius"}', '{}', '{}', 'Do a single, double footed jump for each swing of the rope. Work on a smooth, rhythmical movement, bouncing lightly on the balls of your feet.', NULL, false),
('Side Bends on Machine', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"Dumbbell"}', NULL, NULL, false),
('Stationary Bike', 'cardio', '{}', '{}', '{}', 'Ride a Stationary Bike with various tensions.', NULL, false),
('Tricep Dumbbell Kickback', 'strength', '{"Triceps brachii"}', '{}', '{"Dumbbell"}', '- Start with a dumbbell in each hand and your palms facing your torso. Keep your back straight with a slight bend in the knees and bend forward at the waist. Your torso should be almost parallel to the floor. Make sure to keep your head up. Your upper arms should be close to your torso and parallel to the floor. Your forearms should be pointed towards the floor as you hold the weights. There should be a 90-degree angle formed between your forearm and upper arm. This is your starting position. - Now, while keeping your upper arms stationary, exhale and use your triceps to lift the weights until the arm is fully extended. Focus on moving the forearm. - After a brief pause at the top contraction, inhale and slowly lower the dumbbells back down to the starting position. - Repeat the movement for the prescribed amount of repetitions. Variations: This exercise can be executed also one arm at a time much like the one arm rows are performed. Also, if you like the one arm variety, you can use a low pulley handle instead of a dumbbell for better peak contraction. In this case, the palms should be facing up (supinated grip) as opposed to the torso (neutral grip).', NULL, false),
('Superman', 'strength', '{"Gluteus maximus","Latissimus dorsi"}', '{}', '{"Gym mat"}', 'Lay flat on your stomach with your arms extended in front of you on the ground as your legs are lying flat. Lift both your arms and legs at the same time, as if you were flying, and contract the lower back. Make sure that you are breathing and, depending on your fitness level, hold the movement for at least two to five seconds per repetition.', NULL, false),
('Triceps on Machine', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Sit down and hold the bar firmly with your hands. Now press the weight upwards (don''t fully extend your arms) and lower it slowly again. As with other triceps exercises, it''s important not to move your upper arms.', NULL, false),
('Standing Rope Forearm', 'strength', '{}', '{}', '{}', 'Grab a wrist roller tool with both hands while standing with your feet about shoulder width apart. If your gym does not have a wrist roller tool, you can easily put one together. All you need is a 5 or 10 pound weight plate, a strong thin rope about 3 feet long and a 6-8 inch stick or bar. Securely fasten the rope to the middle of the bar/stick and tie the other end of the rope to the weight plate. To begin this exercise, grab the bar/stick with both hands using an overhand grip. Extend both arms straight out in front of you, parallel to the floor. Next, roll the weight up from the floor by rapidly twisting the bar/stick with your hands and wrists. Once the weight reaches the top, slowly lower the plate back to the floor by reversing the motion of your hands and wrists. Repeat (if you can!).', NULL, false),
('Turkish Get-Up', 'strength', '{"Anterior deltoid","Gluteus maximus","Obliquus externus abdominis","Serratus anterior"}', '{"Anterior deltoid","Gluteus maximus","Obliquus externus abdominis","Serratus anterior"}', '{"Dumbbell"}', 'Starting on back, move to the standing position with dumbbell in one hand. Switch hands between reps.', NULL, false),
('SEATED CABLE MID TRAP SHRUG', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'seated straight back, slight hold at top', NULL, false),
('Power Clean', 'strength', '{"Pectoralis major"}', '{}', '{"Barbell"}', 'Olympic weight lifting', NULL, false),
('Weighted Step-ups', 'strength', '{}', '{}', '{}', 'box step ups w/ barbell and 45''s on each side', NULL, false),
('Upper External Oblique', 'strength', '{"Obliquus externus abdominis"}', '{}', '{"Pull-up bar"}', 'Exercise for upper external oblique muscles', NULL, false),
('Trunk Rotation With Cable', 'strength', '{"Obliquus externus abdominis"}', '{"Latissimus dorsi"}', '{}', 'Seated trunk rotation with cable', NULL, false),
('Wall Slides', 'strength', '{"Biceps brachii","Biceps femoris","Pectoralis major","Trapezius","Triceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Stand with heels, shoulders, back of head, and hips touching the wall. Start with biceps straight out and elbows at a 90 degree angle. Straighten the arms while remaining againstthe wall without arching the back off of the wall, mimicking a shoulder press movement.', NULL, false),
('Overhead Press', 'strength', '{"Anterior deltoid"}', '{}', '{"Barbell"}', NULL, NULL, false),
('Elevated prayer stretch', 'strength', '{"Latissimus dorsi"}', '{}', '{"Bench"}', 'Starting position: Kneel in front of a bench, far enough so that your torso can fit between your knees and the bench. With your back straight, place your elbows on the bench, with palms together, hands pointing up. Steps: - On exhale, stretch your chest down toward the floor without moving your lower back. At the same time, bring your hands toward your shoulders, keeping palms together and elbows on the bench. - Hold for a few seconds. - On inhale, relax your back to return to the starting position. - - Repeat.', NULL, false),
('Quadruped thoracic rotation left', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Start kneeling on all fours, knees shoulder-width apart. Place your left hand behind your head while keeping your right hand outstretched and touching the floor. Steps: - On inhale, move your left elbow toward your right hand, keeping your left hand behind your head. - On exhale, move your left elbow to point up toward the ceiling. - Repeat.', NULL, false),
('Hindu Pushups', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{"Triceps brachii"}', '{}', 'Exercise to strengthen the shoulders and pectorals. Its name is due to the fact that it begins in the Yoga position "Dog Facing Down", passing to "Cobra" but without resting the legs or torso on the ground to finally end with a normal flexion. The exercise can also be performed backwards (back to the starting position). As a variation, after doing the push-up, the hip can be raised to return to downward facing dog.', NULL, false),
('Shoulder dislocates', 'strength', '{}', '{}', '{}', 'Starting position: Stand up with your back straight and a resistance band, towel, or broomstick handle in hand. With your hands straight in front of your body and the band between your hands, push your hands apart to both be at around 45 degrees from your body, thumbs facing down. If using a towel or broomstick handle instead, grab it with an overhand grip. Steps: - Keeping your arms outstretched, rotate at the shoulders to bring your arms overhead and then down toward your glutes. - Rotate at the shoulders in the opposite direction - overhead and then toward your groin. - Repeat.', NULL, false),
('Bent over row to external rotation', 'strength', '{}', '{}', '{}', 'Starting position: Stand behind a chair or in front of a table. Bend at the waist to put your forehead on the chair''s headrest or table, keeping your back straight. Your arms should be hanging straight down, pointed at the floor. Steps: - Bring your elbows up to shoulder height. Your forearms should be pointing down, perpendicular to your biceps. Your biceps should be at the same height as your back and perpendicular to your spine. - Hold for a bit. - Rotate at your elbows to bring your hands as far up as you can. - Hold for a bit. - Rotate at your elbows back to the previous position. - Bring your arms down to the original position. - Repeat.', NULL, false),
('YWTs', 'strength', '{}', '{}', '{}', 'Starting position: Lie down, preferably on a mat. Stretch your arms above your head in a "Y" position (arms pointing up diagonally at around 45 degrees). Your thumbs should be pointing up. Steps: - With arms in the Y position, lift your chest slightly from the ground, creating a pull tension in your arms upward. - Hold this position for several seconds (15-30 is ideal). - Keeping your chest up, bend at your elbows to move from a Y position to a "W" position, with arms bent at the elbows and maintaining the upward tension. - Hold for around as long as with the Y position. - Still with your chest up, move to a "T" position, straightening your arms out to the side to be perpendicular to your body. - Hold for around as long as you held the W position. - Move from the T position to the W position, then from the W position to the Y position. - Repeat.', NULL, false),
('Close-grip Press-ups', 'strength', '{"Brachialis","Latissimus dorsi","Pectoralis major","Trapezius"}', '{"Anterior deltoid","Biceps brachii","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'Drop into a strong plank position, bringing your hands close together until they''re almost touching. (picture 1)Bend your elbows to slowly bring your chest to the floor (picture 2). Keep your elbows close to your body as you push back up explosively. Repeat. Ensure you take your time lowering on each rep, keeping your form sharp.', NULL, false),
('Dumbbell Hang Power Cleans', 'strength', '{}', '{}', '{"Dumbbell"}', 'On your feet, stand tall with your dumbbells, holding them at your sides. Hinge at the hips to lower them to your knees (picture 1). Stand back up with a slight jump, using the momentum to pull the dumbbells up on to your shoulders (picture 2). Stand up straight, then lower under control to your sides and repeat. Keep this fast and explosive; if your heart rate doesn't hit the roof, you're doing them wrong.', NULL, false),
('Dumbbell sumo deadlift', 'strength', '{}', '{}', '{"Dumbbell"}', 'Lower your dumbbell to the ground between your legs. Assume a wide stance and with a straight back squat down. With the dumbbell standing upright, grip it by the top of the 'head' (picture 1).Keeping your chest up and core braced, push the floor away, driving back upwards to a standing position (picture 2). Repeat. If you can easily achieve 20-30 reps, use two dumbbells.', NULL, false),
('Medicine ball twist', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"Swiss Ball"}', 'In a seated position, the torso is rotated from side to side without forcing, approaching the knees and making the ball touch the ground from time to time', NULL, false),
('Vpushup', 'strength', '{"Pectoralis major","Quadriceps femoris","Rectus abdominis","Triceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Lift your body off the ground by pushing your arms upwards', NULL, false),
('Plank Shoulder Taps', 'strength', '{"Anterior deltoid","Gluteus maximus","Rectus abdominis"}', '{"Latissimus dorsi"}', '{"Gym mat"}', 'In the correct plank position, place your feet slightly wider than shoulder-width apart. alternately lift and touch the opposite shoulder with one hand.', NULL, false),
('Unilateral Cable row', 'strength', '{"Latissimus dorsi"}', '{}', '{"Incline bench"}', 'With an inclined bench in front of the cable row machine, do onehanded rows with focus on a big stretch in the lats.', NULL, false),
('Dumbbell Front Squat', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Anterior deltoid","Rectus abdominis"}', '{"Dumbbell"}', 'This exercise involves holding a dumbbell in each hand at shoulder height and performing a squat. It targets the lower body muscles, including the quads, hamstrings, and glutes, while also engaging the core and upper body.', NULL, false),
('Walking', 'cardio', '{"Biceps femoris","Gastrocnemius","Gluteus maximus","Latissimus dorsi","Obliquus externus abdominis","Quadriceps femoris","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Walking outdoor or indoor, try keeping a pace of at list 100 steps per minute.', NULL, false),
('Kettlebell One Legged Deadlift', 'strength', '{"Gluteus maximus"}', '{}', '{"Dumbbell","Kettlebell"}', 'This exercise involves holding a kettlebell in one hand and standing on one leg while bending forward to touch the kettlebell to the ground. It targets the hamstrings, glutes, and lower back while also improving balance and stability.', NULL, false),
('Dumbbell Hip Thrust', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{}', '{"Dumbbell"}', 'This exercise involves sitting on the ground with a dumbbell resting on the hips, then thrusting the hips upward while squeezing the glutes. It is a great exercise for strengthening the glutes and improving hip mobility.', NULL, false),
('Dumbbell Shrug', 'strength', '{}', '{}', '{"Dumbbell"}', 'This exercise involves holding a dumbbell in each hand and shrugging your shoulders up towards your ears, then lowering them back down. It primarily targets the trapezius muscles in the upper back and can help improve posture and shoulder stability.', NULL, false),
('Weighted Crunch', 'strength', '{"Obliquus externus abdominis"}', '{}', '{"Dumbbell"}', 'The Weighted Crunch is a variation of the classic crunch exercise that involves adding resistance (a weight) to increase the intensity of the abdominal work. - Lay down - (Optional) Bend your knees to add difficulty - (Optional) Bend your knees and let your feet rest on a bench or a box or something (90 degree angle on knees) - Lift your head and torso while bending your back forward (if you don''t it''s a sit-up and also involves some back muscles). The higher you go, the more you should feel your abs contracting. - Go back to starting position an repeat', NULL, false),
('Front neck stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit or stand with your back straight. Steps: - Open mouth wide. - Slowly tilt head back with mouth opened. If you feel the need for support, clasp your hands behind your head. - Very slowly close and open your mouth. - At the end, slowly return to starting position and close mouth.', NULL, false),
('Dumbbell Side Bend', 'strength', '{"Obliquus externus abdominis"}', '{}', '{"Dumbbell"}', 'This exercise involves holding a dumbbell in one hand and bending sideways to work the oblique muscles on the side of the body. It can be done standing or seated and is often used as a core strengthening exercise.', NULL, false),
('Dumbbell Rear Lunge', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Soleus"}', '{"Dumbbell"}', 'This exercise involves holding a dumbbell in each hand and stepping back into a lunge position, then returning to standing. It primarily targets the glutes, hamstrings, and quadriceps.', NULL, false),
('Dumbbell Side Squat', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Biceps femoris"}', '{}', 'This exercise involves holding a dumbbell in one hand and performing a squat while stepping to the side. It targets the legs, glutes, and core muscles.', NULL, false),
('Machine Lateral Raise', 'strength', '{"Anterior deltoid"}', '{}', '{"Gym mat"}', 'The machine lateral raise is an isolation exercise that targets the medial (side) deltoid muscle to build wider, more defined shoulders. The machine''s fixed path of motion provides greater stability than dumbbells, making it ideal for beginners or those who want to focus solely on muscle activation.', NULL, false),
('Machine Chest Press Exercise', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"Gym mat"}', '. It provides an effective but straightforward way to work your upper body. With no weights to balance and no tricky techniques to master, the chest press leaves you free to focus on your training.', NULL, false),
('Cycling cardio session', 'cardio', '{}', '{}', '{}', 'Cardio session on a Technogym Bike Excite 1000 stationary bike.', NULL, false),
('Dumbbell Romanian Deadlift', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{}', '{"Dumbbell"}', 'This exercise involves holding a dumbbell in each hand and bending forward at the hips while keeping the back straight, then returning to a standing position. It primarily targets the hamstrings and glutes.', NULL, false),
('Incline Skull Crush', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Siting in a 45 Degree Angle, using DB to do Incline Skull Crush', NULL, false),
('Rear Delt Raise', 'strength', '{"Anterior deltoid","Trapezius"}', '{"Latissimus dorsi"}', '{"Dumbbell"}', 'Seated on a bench with the dumbbells on the floor bend over at 45 Degrees and then slowly raise each dumbbell to shoulder height and hold for a couple seconds before lowering to the starting position.', NULL, false),
('2 Handed Kettlebell Swing', 'strength', '{}', '{}', '{"Kettlebell"}', 'Two Handed Russian Style Kettlebell swing', NULL, false),
('Rowing Machine', 'cardio', '{"Anterior deltoid","Biceps brachii","Biceps femoris","Brachialis","Gastrocnemius","Gluteus maximus","Latissimus dorsi","Obliquus externus abdominis","Quadriceps femoris","Rectus abdominis","Serratus anterior","Soleus","Trapezius"}', '{}', '{"none (bodyweight exercise)"}', 'Sit on a rowing machine with your back straight.', NULL, false),
('Seated Bench Press', 'strength', '{"Pectoralis major"}', '{}', '{"Bench"}', 'Set up the chest press machine so that the grips are aligned with your lower chest when you sit down. Make sure you''re sitting with your back flat against the seat. Grab a handle in each hand, stick your chest out, and keep your head against the headrest. Breathe deeply and slowly push the handles forward until your arms are almost fully extended. Pause just before the lockout, then slowly return the handles to the starting position. Pause just before the handles come to a complete stop and perform another repetition.', NULL, false),
('Bent Over Rowing Reverse', 'strength', '{"Latissimus dorsi"}', '{"Anterior deltoid","Biceps brachii"}', '{"Barbell"}', 'The same as regular rowing, but holding a reversed grip (your palms pointing forwards): Grab the barbell with a wide grIp (slightly more than shoulder wide) and lean forward. Your upper body is not quite parallel to the floor, but forms a slight angle. The chest''s out during the whole exercise. Pull now the barbell with a fast movement towards your belly button, not further up. Go slowly down to the initial position. Don''t swing with your body and keep your arms next to your body.', NULL, false),
('Abduction while standing', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Training a stable stance, predominantly on one leg, is crucial for both sides. On the one hand, it prevents discomfort and, on the other, it establishes a stable foundation. The practitioner assumes the usual standing position and, with a stable upper body, attempts to repeatedly lift the unloaded leg, bend it at the hip and knee, and then lower it again. The movement is also repeated on the other side. The exercise trains the stability of the hip-surrounding muscles.', NULL, false),
('Seated rear delt rise', 'strength', '{"Latissimus dorsi"}', '{}', '{"Dumbbell"}', 'Seated, bent 45 deg forward. Arms fully stretched out, raise arms up to shoulder height and back down', NULL, false),
('Dynamic side hold', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"Kettlebell"}', 'Sling a rubber band on a kettlebell and lift the kettlebell by the rubber band. Let it hang by your side and stand on one leg, switch leg while continuing hold. Repeat with other hand', NULL, false),
('Wall balls', 'strength', '{"Anterior deltoid","Gluteus maximus","Quadriceps femoris"}', '{"Biceps brachii","Pectoralis major","Rectus abdominis","Trapezius"}', '{"Swiss Ball"}', 'Get a medicine ball, shoulder width stance, squat, thrust the ball as high as possible against the wall and catch', NULL, false),
('Horizontal traction isometry', 'strength', '{"Latissimus dorsi","Pectoralis major"}', '{"Anterior deltoid","Biceps brachii"}', '{"Pull-up bar"}', 'Perform a timed isometric pull-up on the bar', NULL, false),
('Alternate back lunges', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'The posterior muscles of the buttocks, hamstrings, soleus and gastrocnemius are trained more', NULL, false),
('walking bridge', 'strength', '{"Rectus abdominis"}', '{"Anterior deltoid","Biceps brachii","Gluteus maximus","Latissimus dorsi"}', '{"none (bodyweight exercise)"}', 'from a standing position with knees slightly bent and hands resting on the floor. From here, proceed forward with your hands keeping your buttocks contracted and without losing control of your lower back.', NULL, false),
('Seated Knee Tuck', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"none (bodyweight exercise)"}', 'Sit on floor or mat. Place arms slightly behind you. Raise legs. Now extend your legs and pull them back.', NULL, false),
('Cable Concentration Curl', 'strength', '{"Biceps brachii","Brachialis"}', '{}', '{}', 'The concentration curl is a classic exercise for building the biceps one arm at a time. It can be performed bent over or kneeling, but is more often performed seated on a bench. It''s great for emphasizing the biceps peak and is often used to finish a biceps workout', NULL, false),
('Push-Ups | Incline', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"Bench","Incline bench"}', 'Inclined push-ups primarily target the chest muscles (pectoralis major and minor), but also work the triceps, shoulders, and core to a lesser extent. Because the upper body is elevated, the incline push-up places less emphasis on the triceps compared to regular push-ups, which may be beneficial for individuals looking to specifically target their chest muscles.', NULL, false),
('Push-Ups | Decline', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{"Bench","Incline bench"}', 'Decline push-ups are another modified version of the traditional push-up that target the upper body muscles in a different way. To perform a decline push-up, elevate your feet on an elevated surface, such as a bench, chair, or step, while placing your hands on the ground in a push-up position. Lower your body towards the ground while maintaining a straight line from your shoulders to your ankles, and then push back up to the starting position. Unlike the inclined push-up, the decline push-up places more emphasis on the shoulders and triceps, while still engaging the chest muscles to a lesser extent. By elevating your feet, you increase the difficulty of the exercise by placing more weight on your upper body, forcing your shoulders and triceps to work harder to push your body back up. The decline push-up can be a great way to challenge your upper body strength and improve your ability to perform other push-up variations. As with any exercise, be sure to use proper form and start with a height that is appropriate for your strength and fitness level.', NULL, false),
('Push-Ups | Parallettes', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{}', 'Parallettes push-ups are a variation of the traditional push-up that are performed with the hands on parallel bars, known as parallettes. To perform a parallettes push-up, assume a push-up position with your hands on the parallettes and your feet on the ground. Lower your body towards the ground while keeping your elbows close to your sides, and then push back up to the starting position. Parallettes push-ups place more emphasis on the chest and shoulders compared to traditional push-ups, as they allow for a greater range of motion in the shoulder joint. This increased range of motion can also help to improve shoulder stability and mobility. Additionally, parallettes push-ups engage the core muscles more than traditional push-ups, as the instability of the parallettes requires greater activation of the core muscles to maintain proper form. The added challenge of balancing on the parallettes also requires greater upper body strength and control, making parallettes push-ups a more advanced variation of the traditional push-up. They can be a great way to challenge yourself and add variety to your upper body workout routine. As always, be sure to use proper form and start with a level that is appropriate for your strength and fitness level.', NULL, false),
('Rest (for timed workouts)', 'strength', '{}', '{}', '{}', 'When creating a workout based on time, add this to add rest time in the program', NULL, false),
('3D lunge warmup', 'cardio', '{}', '{}', '{"Dumbbell"}', 'As a warmup, use light dumbbells, one in each hand. Lunge in alternating directions, forward, sideways, backwards and 45 degree angles.', NULL, false),
('Dumbbell farmer''s carry', 'strength', '{}', '{}', '{"Dumbbell"}', 'Grab half your body weight in each hand and walk.', NULL, false),
('Wide-grip lat pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Downward movement - Pull the bar down so that it passes close to your chin and touches the upper part of your chest. - Keep the rest of your body still. Upward movement - Allow your elbows to extend so the bar rises back to the starting position. - Keep the rest of your body still.', NULL, false),
('Wide-grip supinated lat pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Downward movement - Pull the bar down so that it passes close to your chin and touches the upper part of your chest. - Keep the rest of your body still.', NULL, false),
('Close-grip lat pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Downward movement - Pull the bar down so that it passes close to your chin and touches the upper part of your chest. - Keep the rest of your body still.', NULL, false),
('Close-grip supinated lat pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Downward movement - Pull the bar down so that it passes close to your chin and touches the upper part of your chest. - Keep the rest of your body still.', NULL, false),
('Cable glute extension', 'strength', '{"Gluteus maximus"}', '{}', '{}', 'This exercise lets you work the upper, or larger, part of the glutes. For that reason, it should never be missing from your routine of isolated exercises for training the glutes. Stand in front of a cable machine and locate the low pulley. Then attach the ankle strap to work on the low pulley. As for your posture, you should stay upright at all times. Pay special attention to your back to keep it straight and avoid injury. It is advisable to hold on to the machine for better balance. With the leg that is holding the weight of the cable, perform a slow stretch backward without bending the knee.', NULL, false),
('Machine glute extension', 'strength', '{"Gluteus maximus"}', '{}', '{}', 'A GHD hip extension is one of the best exercises for the glutes. While the exercise mainly targets the glutes, it is also excellent for the lower back, the calves and the hamstrings.', NULL, false),
('Neutral-grip chest pulldown', 'strength', '{"Biceps brachii","Latissimus dorsi","Serratus anterior"}', '{}', '{}', 'The lat pulldown is an important exercise for strengthening the back and improving posture, which can contribute to a healthier life. To perform this exercise correctly and avoid injury, it is important to follow a few key steps: - Position yourself in front of the cable machine with your knees slightly bent and your feet on the floor. - Grip the cable handle with your palms facing each other and your hands shoulder-width apart. - Pull the handle down until it touches or comes close to your chest, holding the position for one or two seconds. - Slowly raise the handle back to the starting position, making sure to keep your arms and hands straight and your back straight throughout the movement.', NULL, false),
('High-pulley pullover', 'strength', '{"Latissimus dorsi","Serratus anterior"}', '{}', '{}', 'Stand facing the machine, feet slightly apart, gripping the bar with an overhand grip, arms extended, hands shoulder-width apart. - Keeping your back fixed and your abdominal muscles contracted, inhale and bring the bar down to your thighs while keeping your arms extended (or your elbows slightly bent). Exhale at the end of the movement.', NULL, false),
('Incline bench pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Lying face down on the incline bench facing the cable machine, perform the pulldown.', NULL, false),
('Arabesque', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'Take all your weight onto one leg and you''re going to maintain that position, keeping your hips and pelvis level the whole time. With your back in a neutral position you want to tilt yourself forward kicking your leg back up and then slowly with your glutes bring yourself back up to neutral.', NULL, false),
('Triceps Pushdown', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Triceps pushdown on cable using lat bar.', NULL, false),
('One Arm Bent Row', 'strength', '{}', '{}', '{}', 'One arm bent over row on cable with a machine', NULL, false),
('Reverse-grip barbell curl', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'STARTING POSITION: Select the appropriate weight on a barbell. Stand holding the barbell with an overhand grip and your hands shoulder-width apart. Engage your pelvic floor and core while keeping your chest lifted. EXECUTION: Contracting your biceps, bend your elbows fully as you exhale. Return to the starting position with a smooth movement as you inhale.', NULL, false),
('Alternating Biceps Curls With Dumbbell', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Hold two dumbbells, the arms are streched, the hands are on your side, the palms face inwards. Bend one arm at a time and bring the weight with a fast movement up. At the same time, rotate your arms by 90 degrees at the very beginning of the movement. At the highest point, rotate a little the weights further outwards. Without a pause, bring the arm back down, slowly, and do the same with the other arm. Don''t allow your body to swing during the exercise, all work is done by the biceps, which are the only mucles that should move (pay attention to the elbows).', NULL, false),
('Russian Twist', 'strength', '{"Latissimus dorsi","Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"Dumbbell","Gym mat","Swiss Ball"}', '- Hold a dumbbell, barbell weight or something else that is heavy with both hands, but make sure it is not too heavy and you are able to keep in form. - Lean back to a 45-degree angle from the floor. For an extra challenge, lift your feet off the floor. - Rotate your arms to one side to the same level as your chest, touch the floor for a little extra challenge, and then do the same to the other side. When you''re back in your original position after doing both sides it will count as 1 rep.', NULL, false),
('PALLOF PRESS', 'strength', '{"Anterior deltoid","Gluteus maximus","Obliquus externus abdominis","Rectus abdominis","Serratus anterior","Trapezius"}', '{"Pectoralis major","Triceps brachii"}', '{}', 'The Pallof press is an anti-rotation exercise that trains the larger and smaller muscles around the spine to resist rotation. - Stand parallel to the cable machine or to the anchor point to the resistance band and clasp with the handle or band with both hands. - Make sure your torso is front on and bring your hands to the center of your chest and slowly press out. - Slowly return your hands to the chest and repeat.', NULL, false),
('Side Slides + Squats', 'strength', '{"Quadriceps femoris"}', '{"Gastrocnemius","Gluteus maximus"}', '{"none (bodyweight exercise)"}', 'With feet a little wider than shoulder-width apart and staying low to mimic a defensive position, you should step with their lead leg and push off with their plant leg. After three slides, rotate your body for 180 degree on the guiding (/outer) leg and do a squat. Continue.', NULL, false),
('Wall Drills', 'strength', '{"Quadriceps femoris"}', '{"Gastrocnemius"}', '{"none (bodyweight exercise)"}', 'Exercises for strengthening knee and leg musculature. - Lateral Wall Drills March - https://youtu.be/9RiTlJ6Mmek - Lateral Wall Drills OPEN - https://youtu.be/ADRlN8-Wfdg - Lateral Wall Drills CROSS - https://youtu.be/hGH2sj0Tzu4', NULL, false),
('Inverted Rows', 'strength', '{"Biceps brachii","Latissimus dorsi"}', '{"Pectoralis major","Rectus abdominis","Trapezius"}', '{"none (bodyweight exercise)"}', 'Maintain a straight body, retract your shoulder blades, and pull your chest to the bar for an effective back and upper body workout.', NULL, false),
('Tibialis raises', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Stand up straight - Lift the balls of your feet, resting on your heels.', NULL, false),
('Dragon squat', 'strength', '{"Quadriceps femoris"}', '{"Biceps femoris","Gastrocnemius","Gluteus maximus"}', '{"none (bodyweight exercise)"}', 'Start standing with your feet hip-width apart. Cross your right foot behind you to the left corner and back of the room while bending both knees. Return and repeat, alternating sides. Keep your hips and shoulders forward as you cross your feet and bend your knees.', NULL, false),
('Side Lying Hip Abduction', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Begin by lying down on your side with your top leg straight and your bottom leg bent for support. - Lift your top leg off the ground - (optional) - Hold position at the top Resources: - 40 seconds YouTube video: https://www.youtube.com/watch?v=g9FtnmsIYgI', NULL, false),
('Calf raises, left leg', 'strength', '{"Gastrocnemius"}', '{}', '{"none (bodyweight exercise)"}', '- Stand on the floor or on the edge of a step to increase the range of movement. - Raise one foot. - Lift your heel until you''re standing on your toes. - (variable) Stay in this position for three seconds - Slowly lower your foot until you almost touch the ground with your heel - don''t slam your foot!', NULL, false),
('Wrist curl, dumbbells', 'strength', '{}', '{}', '{"Dumbbell"}', '- Sitting on a bench, grab the dumbbell with your palms facing up and your hands shoulder-width apart. Rest your forearms on your thighs and allow your wrists to hang over your knees. - Perform the movement by curling your palms and wrists towards your face. - (optional/variable) Pause at the top. - Slowly return to the starting position.', NULL, false),
('Scorpion Kick', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Get into the push-up position with your shoulders directly above your hands and your feet hip-width apart. Make sure that your body forms a straight line from your head to your heels. Now pull your right knee towards your chest. While keeping your knee bent, lift your right leg as high as possible with your lower right leg pointing straight up. Now rotate your hips so that your right foot swings over your left leg. Continue to rotate and move your right foot towards the floor until you are forced to roll onto the outside of your left standing foot. Make sure that you do not rotate your upper body. Now return to the starting position and repeat the exercise with your left leg.', NULL, false),
('Prisoner Squat', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Stand upright with your chest slightly raised, your feet hip-width apart and your toes pointing straight ahead. Bring your hands to the back of your head with your fingers slightly interlaced and your elbows pointing to the side. Push your hips back and bend your knees, keeping your upper body as upright as possible. Push your knees outwards, they must never point towards each other. If your upper body moves slightly forward, make sure that it does not bend. Always keep your elbows level with your ears by tensing the muscles between your shoulder blades. If you are flexible enough, you can sink down until your buttocks touch your calves. However, make sure that you do not bend your spine. Before this happens, reverse the movement and use your heels and glutes to push yourself upwards with so much momentum that your feet lift off briefly and you do a little hop. If necessary, correct the position of your feet, arms and upper body before you move on to the next repetition. Translated with www.DeepL.com/Translator (free version)', NULL, false),
('Skydiver with arms in T-position', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Lie on your stomach with your legs more than shoulder-width apart and your feet up. Your arms are stretched out to the side and form a T with your upper body, your palms are on the floor. Now raise your upper body, arms and legs as high as you can while keeping your body under tension. Turn your thumbs towards the ceiling and pull your shoulder blades together. While keeping your upper body and all limbs in the air, bring your legs together and then spread them again, keeping them constantly in the air. For the remaining repetitions, only move your legs open and closed.', NULL, false),
('Full Sit Outs', 'strength', '{"Gluteus maximus","Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', '(A) Get in high plank position on your hands and toes.(B) Shift your weight to your left hand as you turn your body to the right; bend your right leg behind you and extend your right arm up. Return to the center and repeat on the opposite side. Continue, alternating sides.Make it easier: Don't raise your arm after you bend your leg behind you.Make it harder: Balance with your arm and leg extended for two counts.', NULL, false),
('Reverse Snow Angel', 'strength', '{"Trapezius"}', '{"Anterior deltoid","Biceps femoris","Gluteus maximus","Obliquus externus abdominis","Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Lay flat on your stomach with your arms extended in front of you on the ground as your legs are lying flat. Lift both your arms and move them to your side slowly. Then, move them back.', NULL, false),
('knee push-ups', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{"Serratus anterior","Triceps brachii"}', '{"none (bodyweight exercise)"}', '- Start by kneeling on the floor, keeping your knees together. Place your hands on the floor in front of you, slightly wider than shoulder-width apart. - Make sure your body forms a straight line from head to knees. Hands should be positioned below shoulders. - Lower your torso towards the ground, bending your elbows while keeping your trunk stable. Keep your knees in contact with the floor. - Push through your hands to return to the starting position. Be sure to maintain contraction of chest, shoulder and arm muscles at the top of the movement. - Perform the desired number of repetitions, controlling the movement and maintaining good form.', NULL, false),
('Australian pull-ups', 'strength', '{"Anterior deltoid","Biceps brachii","Latissimus dorsi"}', '{"Trapezius"}', '{"none (bodyweight exercise)"}', '- Lie down under a high bar or suspension bar, positioned at an appropriate height. - Position yourself on your back under the bar, gripping the bar with a supinated grip (palms facing you). - Adjust your position so that your body is aligned straight from head to toe. Arms should be fully extended, shoulders stabilized, and legs aligned with the rest of the body. - Bend your elbows and pull your chest towards the bar, contracting your back muscles. Imagine you''re trying to bring your shoulder blades together. - Hold the contraction at the top of the movement for a moment to maximize muscle activation. - Slowly return to the starting position, extending your elbows.', NULL, false),
('Cable Chest Press - Decline', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{}', 'Single arm chest press done with the cable machine. Use the other arm to brace bodyweight to focus on strength of the press, rather than balancing of the body. Start with the hand as close to the chest as possible, and then press against the cable at a slight decline and aiming towards the center of your chest.', NULL, false),
('Shoulder Dumbbell Pendular Exercise', 'strength', '{"Anterior deltoid","Latissimus dorsi","Pectoralis major","Trapezius"}', '{}', '{"Dumbbell"}', '- Lean forward to rest your hand on a chair or other object, holding a dumbbell in the other hand - Gently swing the dumbbell in a circular motion', NULL, false),
('Shoulder External Rotation with Dumbbell', 'strength', '{"Anterior deltoid","Brachialis"}', '{"Trapezius"}', '{"Dumbbell"}', '- Lie on your side holding a dumbbell in your upper hand - Tuck your elbow into your side and rest the hand in front of you - Rotate the shoulder so the hand raises up - Lower the hand down', NULL, false),
('Claps over the head', 'strength', '{"Anterior deltoid"}', '{}', '{"none (bodyweight exercise)"}', 'Stand with your feet shoulder width apart. Raise your arms and clap over your head', NULL, false),
('Dumbbell drag curls', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Hold a dumbbell in each hand with your palms facing forward. Pull your elbows back and lift the dumbbells to your chest height. Slowly lower the dumbbell and repeat the exercise.', NULL, false),
('Leg Extension', 'strength', '{"Quadriceps femoris"}', '{}', '{}', 'The leg extension is a resistance weight training exercise that targets the quadriceps muscle in the legs. The exercise is done using a machine called the Leg Extension Machine. There are various manufacturers of these machines and each one is slightly different. Most gym and weight rooms will have the machine in their facility. The leg extension is an isolated exercise targeting one specific muscle group, the quadriceps. It should not be considered as a total leg workout, such as the squat or deadlift. The exercise consists of bending the leg at the knee and extending the legs, then lowering them back to the original position.', NULL, false),
('Incline Shoulder Press Up', 'strength', '{"Anterior deltoid","Pectoralis major"}', '{}', '{"Bench"}', '- Place your hands on the bench in a press up position - Push your chest away from the bench to separate your shoulder blades - Keeping your elbows straight, lower your chest towards the bench so your shoulder blades move closer together - Push your chest away from the bench again', NULL, false),
('Dumbbell wide bicep curls', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Hold a dumbbell in each hand with your hands slightly wider than shoulder-width apart and palms facing forward. Bend your elbows and lift the dumbbells to your shoulders. Slowly return and repeat.', NULL, false),
('Neck extension', 'strength', '{"Biceps brachii"}', '{}', '{"SZ-Bar"}', 'Unilateral triceps exercise with your back to the pulley, with the pulley at the top', NULL, false),
('Dumbbell bicep curl to press', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Bend your elbows and lift the dumbbells to your shoulders. Push the dumbbells over your head while rotating your arms to make your palms face forward. Reverse it to lower down. Repeat the exercise.', NULL, false),
('Dumbbell rear delt row', 'strength', '{"Anterior deltoid","Brachialis","Trapezius"}', '{}', '{"Dumbbell"}', 'Hold a dumbbell in each hand. Bend at your hips to make your back almost parallel to the floor. Let your arms hang down. Keep your arms in line with your shoulders. bend and lift your elbows out to the sides until your upper arms are parallel to the floor. Slowly return and repeat', NULL, false),
('Dumbbell close grip bench press', 'strength', '{"Pectoralis major","Triceps brachii"}', '{}', '{"Dumbbell"}', 'Lie down with your back on a flat bench. Hold a dumbbell in each hand. Raise your arms towards the ceiling with your palms facing each other and dumbbells pressed together. Slowly lower the dumbbells to your chest, then slowly push them back. Repeat the exercise.', NULL, false),
('Snatch', 'strength', '{"Anterior deltoid"}', '{}', '{"Barbell"}', 'Stand with your feet at hip width and your shins against the bar. Grasp the bar at double shoulder width and, keeping your lower back flat, drive your heels into the floor to begin lifting the bar. When it''s above your knees, explosively extend your hips and shrug your shoulders. Let the momentum carry the weight overhead.', NULL, false),
('Recruitment Pulls', 'strength', '{}', '{}', '{}', 'Find a few specific edge sizes on a hangboard, get fixed underneath them with the board overhead, and pull with max effort, 1 arm at a time, for 3-5 seconds. When positioning for this get set up with a large elbow angle (120-150 degrees) and not in full extension.', NULL, false),
('Triceps stretch left', 'strength', '{"Triceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Put your left hand on your back, use your right hand to grab your left elbow and gently pull it. Hold this position for a few seconds.', NULL, false),
('Seated Cable Rows', 'strength', '{"Latissimus dorsi"}', '{}', '{}', '"Stay leaned forward - tuck elbows in on the negative"', NULL, false),
('Triceps stretch right', 'strength', '{"Triceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Put your right hand on your back, use your left hand to grab your right elbow and gently pull it. Hold this position for a few seconds.', NULL, false),
('Standing biceps stretch left', 'strength', '{"Anterior deltoid","Biceps brachii","Pectoralis major"}', '{}', '{"none (bodyweight exercise)"}', 'Stand with your left arm close to a wall. Extend your left arm and put your left hand on the wall, then gently turn your body to the right.', NULL, false),
('Standing biceps stretch right', 'strength', '{"Anterior deltoid","Biceps brachii","Pectoralis major"}', '{}', '{}', 'Stand with your right arm close to a wall. Extend your right arm and put your right hand on the wall, then gently turn your body to the left.', NULL, false),
('Dumbbell Single-leg Hip Thrust', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris","Quadriceps femoris"}', '{"Barbell"}', 'The single-leg hip thrust is performed by placing your upper back on a weight bench, raising one leg, and extending the hip of the other leg to achieve an isolated contraction of the glute. By working each side separately, you can fully isolate your glutes unilaterally, providing maximal training stimulus.', NULL, false),
('Remo alto polea alta', 'strength', '{"Obliquus externus abdominis","Serratus anterior","Triceps brachii"}', '{}', '{"Barbell"}', 'High pulley row with support using a single grip', NULL, false),
('Finger Pushup', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Hand Positioning: - Start in a plank position with your hands directly beneath your shoulders. - Spread your fingers wide apart, placing them firmly on the ground. - Finger Placement: - Gradually lift your palms off the ground, shifting the weight onto your fingers. - Focus on distributing the load evenly across your fingertips and thumbs. - Body Alignment: - Maintain a straight line from head to heels to engage your core. - Keep your body in a controlled and stable position throughout the exercise. - Lowering Phase: - Slowly bend your elbows, lowering your chest towards the ground. - Ensure controlled movement, maintaining stability on your fingertips. - Pushing Up: - Press through your fingertips to straighten your arms, returning to the starting position. - Emphasize the engagement of your fingers and thumbs throughout the push-up.', NULL, false),
('Frog stand', 'strength', '{"Anterior deltoid","Biceps brachii","Brachialis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Stand with your feet shoulder-width apart and your toes pointing forward, facing a wall or bench for support if needed. Bend your knees into a squat position. Place your hands on the ground in front of you, shoulder-width apart, with your fingers spread wide. Make sure your elbows are under your shoulders and your body forms a straight line from your head to your heels. Upward phase: Push with your feet and hands to lift your body off the ground. Straighten your legs and arms, keeping your body aligned. Engage your core and glutes to maintain the position. If needed, rest your knees on the wall or bench for assistance.', NULL, false),
('Standing Calf Stretch', 'strength', '{"Gastrocnemius"}', '{}', '{"none (bodyweight exercise)"}', 'This stretch targets the gastrocnemius (the chief muscle of the calf of the leg, which flexes the knee and foot). It is easy to perform anywhere. All you need is a wall or a chair.', NULL, false),
('Bag training', 'cardio', '{"Anterior deltoid","Pectoralis major","Trapezius"}', '{"Biceps brachii","Biceps femoris","Gastrocnemius","Latissimus dorsi","Obliquus externus abdominis","Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Bag training improves muscle definition of: deltoids; rear deltoids; triceps; biceps, as well as being a great cardio exercise', NULL, false),
('Standing Soleus Stretch', 'strength', '{"Soleus"}', '{}', '{"none (bodyweight exercise)"}', 'This stretch targets the Soleus part of your calf. It may be performed with a wall or chair.', NULL, false),
('Exercise Band Dorsiflexion', 'strength', '{"Soleus"}', '{}', '{"none (bodyweight exercise)"}', 'This exercise uses an exercise band. It targets the Soleus and Tibialis anterior.', NULL, false),
('Seated Cable Row', 'strength', '{}', '{}', '{}', '- Take a seat on the machine with your feet planted, a little wider than shoulder width. Drive the heels, and squeeze the glutes. Grab onto the cable handle. - Sit up tall with a slight bend through the knees. Tighten up the abs and low back to maintain a perpendicular angle to the floor with your torso. - Roll the shoulders back and down. Squeeze them together as you row, thinking about pinching a pencil in between them. As you do this, pull the handle back towards you, landing right above your belly button. - Pause here for a moment before returning the handle, still squeezing the shoulder blades. Once you''ve returned the weight to the stack, then allow the shoulder blades to relax, without pulling the torso forward. - Repeat the movement.', NULL, false),
('Exercise Band Plantarflexion', 'strength', '{"Gastrocnemius"}', '{"Soleus"}', '{"none (bodyweight exercise)"}', 'Banded plantarflexion is a great way to bridge the gap between plantarflexion range of motion and the more strenuous calf raises in weight bearing. This can help strengthen the calf muscles, load the Achilles tendon, and improve plantarflexion range of motion.', NULL, false),
('Double Leg Calf Raise', 'strength', '{"Gastrocnemius","Soleus"}', '{}', '{"none (bodyweight exercise)"}', 'The double leg heel raise is important to strengthen and create control and stability around the ankle and knee, and provide balance and control for the hip and pelvis.', NULL, false),
('Yoga exercise: Cow-cat', 'strength', '{"Anterior deltoid","Latissimus dorsi","Trapezius"}', '{"Obliquus externus abdominis","Rectus abdominis"}', '{"Gym mat"}', 'First get into the four-footed stance. The hands are underneath the shoulders. The fingers are fanned out wide and ensure a stable stance. It is best to rest your front body weight on your thumbs and index fingers. Now place your legs hip-width apart on the yoga mat. Your thighs should be vertically below your hips. Make sure that your weight is evenly distributed between your hands and knees. Your head is an extension of your spine and you are looking down at your mat. Your back is in a neutral position. Breathe in deeply and start with the cat. With the next exhalation, round your back vertebra by vertebra. Try to pull yourself as far as possible towards the ceiling. Pull your head towards your chest and tilt your pelvis. Now inhale deeply and move into the opposite position, cow pose. Bend your back down, pull your shoulders back slightly and lift your head as far as is comfortable for you. Your gaze is directed upwards. Breathe out consciously and switch back to the cat. With the next exhalation, switch back to cow. Repeat the exercise a few times and make sure that you are in the flow.', NULL, false),
('Front Lever', 'strength', '{"Latissimus dorsi","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'The front lever is a figure where the body is kept in a horizontal position parallel to the floor.', NULL, false),
('Shoulder width three-point push-up', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Get into a push-up position with your shoulders directly above your hands and your feet hip-width apart. Draw your belly button in towards your spine and tighten your abdominal muscles. Lift your left foot about five centimetres off the floor. Point your toes straight down. Do not move your hips. Your body forms a straight line from your head to your heels throughout the exercise. Now bend your elbows, lower your chest to the floor and push yourself back up. Repeat the exercise on the other side.', NULL, false),
('TRX roll out', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis","Serratus anterior"}', '{"none (bodyweight exercise)"}', 'Hold the handles in your hands, extend your arms and keep them parallel at chest height. The movement you need to perform is to open your arms in line with your shoulders while leaning your body forward. Try not to extend your shoulders beyond 90 degrees, and keep your abdominal muscles and glutes contracted. Muscles involved: transverse abdominis, rectus abdominis and spinal erectors.', NULL, false),
('Ice cream maker', 'strength', '{"Latissimus dorsi"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'From the final phase of a pull-up, we push ourselves back with our shoulders until we reach the front lever position. From there, we pull ourselves back up to the starting position.', NULL, false),
('Front lever pull-up', 'strength', '{"Biceps brachii","Latissimus dorsi","Rectus abdominis"}', '{"Anterior deltoid"}', '{"Pull-up bar"}', 'in the front lever position, with legs extended or easier if collected, pull by bringing the chest closer to the bar.', NULL, false),
('Front lever tuck', 'strength', '{"Anterior deltoid","Biceps brachii","Latissimus dorsi"}', '{"Triceps brachii"}', '{"Pull-up bar"}', 'The muscles involved in the Front Lever, most subjected to stress, are mainly the extensors such as: the latissimus dorsi, the teres major, the posterior deltoid and the long head of the biceps.', NULL, false),
('TRX Obliques', 'strength', '{"Obliquus externus abdominis","Rectus abdominis","Serratus anterior"}', '{"Anterior deltoid","Pectoralis major"}', '{}', '- Place your feet in the stirrups and assume a high plank with your hands directly beneath your shoulders. - Pull your knees to your right elbow, then push them back out and to the centre.', NULL, false),
('TRX hammer curl', 'strength', '{"Biceps brachii"}', '{}', '{}', 'Place the grips as if they were a continuation of the straps. We will position our arms stretched forward and our body leaning back, completely straight. The biceps muscles will activate as you bend your elbows to bring your body towards the straps. The contraction movement will end with a slight outward movement of the hands, due to the grip we are using.', NULL, false),
('Cable External Rotation', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Steps: - Start off placing an extension band around a post or in a secure position where it will not release and is at elbow level. - Position yourself to the side of the band and with your hand that is opposite of the band, reach out and grab the handle. - Bring the band to your chest keeping your elbow bent in a 90 degree angle then slowly rotate your arm in a backhand motion so that the band externally rotates out - Continue out as far as possible so that you feel a stretch in your shoulders, hold for a count and then return back to the starting position. - Repeat for as many reps and sets as desired.', NULL, false),
('TRX gorilla biceps curl', 'strength', '{"Brachialis"}', '{"Biceps brachii"}', '{}', 'We''ll stand facing the TRX straps and grab them with our fists facing each other, facing forward, with our arms fully extended at about shoulder-width apart. We''ll keep our body straight, backward, as in the previous exercises, since we''ll be lifting our body toward the TRX straps by activating our biceps. Our body will be straight, with our feet flat on the floor. This time, we''ll place our arms open to the sides and at chest height. The movement we''ll perform is a contraction toward our chest. To achieve this, we''ll bend our elbows so that, by activating our biceps, we can pull our body toward the straps.', NULL, false),
('Trx Single Arm Bicep Curl', 'strength', '{"Biceps brachii","Brachialis"}', '{"Anterior deltoid","Trapezius"}', '{}', 'Step 1: Stand comfortably and grasp the handles of the suspension system. Step 2: Lean back resting your weight on one arm, keepng the spine neutral. Step 3: Slowly curl to pull your body weight to the up position. Supinate the arm and squeeze as you approach the end position. Step 4: Lower yourself back down and repeat.', NULL, false),
('Back bridge', 'strength', '{}', '{"Anterior deltoid","Biceps femoris","Gastrocnemius","Latissimus dorsi","Trapezius","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'Lie on the floor with your back resting on the floor and your legs bent, feet flat on the floor, leaving about 20 cm between your feet and your buttocks. Your hands remain flat on the floor, pressed against your ears, with your fingers pointing toward your toes. Your elbows are bent and pointing toward the ceiling. This is the starting position. Now push your hips as high as you can, raising your body off the floor, and continue pushing through your hands, extending your elbows and knees, until your back is fully arched (lumbar bridge). Your head also comes off the floor and should be level with your elbows, looking back. This is the final position. The descent should be slow and controlled. Your spine should be in a convex curve. It''s not good to lift your back off the floor; it should remain straight. It should be well rounded. You''ll also notice a feeling of increased oxygenation in your back. After lifting off the floor, your hips should be very high, even above the level of your head. Your arms and legs should remain straight. It seems easy, but it requires a good level of flexibility. Breathing should be deep. This posture stretches the rib cage and puts pressure on the diaphragm. If the posture is performed correctly, breathing will be perfect. Never hold your breath during the exercise.', NULL, false),
('TRX Tricep Extension', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Attach the TRX or other suspension system overhead, having the handles hanging at chest level or slightly lower. Experiment to see what height allows you to set up in the best way. Stand in front of the handles and grab them with your palms facing down. Engage your abs, squeeze your glutes, take a breath and lean forward, lifting your heels off the floor. Keep your elbows straight. Take another breath and lower yourself slowly by bending your elbows. Go down until your elbows are at a 90-degree angle (to the point where your wrists are above your elbows). Hold the position for a moment. Extend your arms by engaging your triceps and bring yourself to the starting position as you exhale.', NULL, false),
('TRX dips', 'strength', '{"Triceps brachii"}', '{"Pectoralis major"}', '{}', 'Start with the hands on the suspension trainer and feet on the ground. Your hands should be under your shoulders with the feet slightly in front. Lower yourself by bringing the hips between the handles and flexing the elbows. Extend the elbows to come back to the starting position and repeat.', NULL, false),
('Low Pulley Cable Fly', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{}', 'Adjust the cable machine: Set the pulley to the lowest setting possible. Choose your handles: You can use neutral grip handles (palms facing each other) or straight handles depending on your preference. Neutral grip might be easier on your wrists. Stand with proper form: Stand with your feet shoulder-width apart, knees slightly bent, and core engaged. Maintain a slight arch in your lower back throughout the exercise. Grip the handles: Grab the handles with your chosen grip and step back a small step or two until there''s slight tension on the cables. Initiate the movement: Keep your elbows slightly bent throughout the exercise. Imagine you''re giving someone a big hug. Squeeze your chest muscles as you bring your hands together in front of your chest. Control the movement: Focus on squeezing your chest muscles rather than using your arms to pull the handles. Peak contraction: Briefly hold the squeeze at the top of the movement with your hands together at chest level. Return slowly: Slowly release the tension and return the handles back down to the starting position with your arms slightly extended but not locked out.', NULL, false),
('Pullover', 'strength', '{"Pectoralis major"}', '{"Latissimus dorsi"}', '{"Dumbbell"}', 'Doubling as a back and chest exercise, the Dumbbell Pullover can train both your pecs and lats.', NULL, false),
('Sitting Calf Stretch (Dorsiflexion)', 'strength', '{"Gastrocnemius","Soleus"}', '{}', '{}', 'This is a light stretch for the calf that is great for rehab.', NULL, false),
('Plantarflexion Stretch with Band', 'strength', '{}', '{}', '{}', 'This stretch is for the ankles, as well as Tibialis anterior.', NULL, false),
('Incline Dumbbell Press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{"Dumbbell"}', 'The incline dumbbell press is a mixture of the dumbbell chest press and the shoulder press, and both the front deltoids and the upper portions of the chest muscles are worked in this exercise.', NULL, false),
('Biceps Close Grip Pull Down', 'strength', '{"Biceps brachii"}', '{"Anterior deltoid","Latissimus dorsi"}', '{}', 'On a lat pull down machine, hold the bar keeping your hands relatively close. Use an underhand grip (I.E.: the back of your hand must be facing the machine). Then pull down the bar in a straight line towards the ground. Make sure your biceps are the main drivers of the motion. You will probably feel your shoulders and lats working, but make sure your biceps are working more.', NULL, false),
('Isometria trazioni impugnatura inversa', 'strength', '{"Latissimus dorsi"}', '{"Biceps brachii","Trapezius"}', '{"Pull-up bar"}', 'Trazioni in isometria con impugnatura inversa', NULL, false),
('Incline Chest-Supported Dumbbell Row', 'strength', '{"Biceps brachii","Latissimus dorsi","Trapezius"}', '{}', '{"Bench","Dumbbell"}', 'Set up an adjustable bench at a 45-degree angle. Lay on your stomach with your head hanging just above the edge of the bench. Grab a dumbbell in each hand and set up with a good posture - core and lats engaged and shoulders neutral. Row the dumbbells toward the top of the stomach and squeeze the back at the top of the rep. Finally, lower the dumbbells back to the starting position and repeat until all reps are completed.', NULL, false),
('Pseudo Planche Push-up', 'strength', '{"Anterior deltoid"}', '{"Pectoralis major"}', '{"none (bodyweight exercise)"}', 'You should have the shoulder line in front of your wrists an perform a push-up, maintaining the shoulder in the same position', NULL, false),
('Talons fesses', 'cardio', '{"Gastrocnemius"}', '{"Biceps femoris"}', '{"none (bodyweight exercise)"}', 'Touch your heels to your buttocks, while remaining static or moving', NULL, false),
('Dynamic Planche', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"none (bodyweight exercise)"}', '- Start in a plank position, with your hands directly under your shoulders and your feet hip-width apart. - Engage your core to keep your body in a straight line from head to toe. - From this position, bend your knees slightly and jump with both feet inward, bringing them as close to your core as possible - As soon as your feet touch the ground, push off forcefully to jump again and return to the starting plank position. - Continue repeating this jumping motion, maintaining control and core stability throughout the exercise. - Make sure to keep your breathing steady while jumping, breathing deeply and controlling your breathing. - Keep your gaze fixed on the ground to maintain proper spinal alignment. - Repeat the jumps for the desired length of time or the number of repetitions recommended for your workout program. - To finish the exercise, rest by releasing the plank position, then stretch if necessary to loosen your muscles.', NULL, false),
('Reach ups', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'To perform this exercise, lie on your back with your arms extended overhead. Then, contract your abdominals and lift your torso off the floor while reaching your arms toward the ceiling to "reach" as high as possible. Slowly return to the starting position, controlling the movement. Reach ups strengthen the abdominal muscles and improve the flexibility of the spine. They can be incorporated into a variety of training routines to work on core strength and stability.', NULL, false),
('Dynamic side plank', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'The dynamic side plank involves positioning yourself on your side, supported on one elbow and the side of your foot, then dipping your hips up and down while keeping your body in a straight line.', NULL, false),
('Seated Dumbbell Curls', 'strength', '{"Biceps brachii"}', '{"Brachialis"}', '{"Dumbbell"}', 'Seated Dumbbell Curls are an effective bicep workout that isolates the muscles by stabilizing the upper body, reducing momentum that can detract from the exercise's effectiveness. This exercise is performed sitting down with a dumbbell in each hand, focusing on controlled movement to maximize engagement of the bicep muscles.', NULL, false),
('Reverse Grip Barbell Curls', 'strength', '{"Biceps brachii"}', '{"Brachialis"}', '{"Barbell"}', 'Hold the barbell with an overhand grip (palms facing down) approximately shoulder-width apart. Ensure your back is straight, shoulders slightly pulled back, and arms fully extended. Curl the barbell upwards towards your chest in a controlled motion, keeping your elbows close to your body. The motion should be smooth without any swinging or momentum use. Once the barbell is at chest level, pause briefly to maximize contraction in the biceps and forearms. Slowly lower the barbell back to the starting position with a controlled movement, fully extending your arms.', NULL, false),
('Reverse-grip pull-ups', 'strength', '{"Biceps brachii","Latissimus dorsi"}', '{"Rectus abdominis"}', '{"Pull-up bar"}', 'Pull-ups on the bar with your thumbs pointing outward.', NULL, false),
('One armed push-ups', 'strength', '{"Pectoralis major","Triceps brachii"}', '{"Anterior deltoid","Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Perform push-ups with one hand, alternating the sides', NULL, false),
('Single-leg hamstring curl', 'strength', '{"Gluteus maximus","Latissimus dorsi"}', '{}', '{"none (bodyweight exercise)"}', 'Specifically, the muscles involved are: biceps femoris, semimembranosus and semitendinosus.', NULL, false),
('Low-Cable Cross-Over - NB', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{}', 'The low-cable cross-over is an isolation movement that uses a cable stack to target the upper portion of the pectoral muscles. It is common in upper-body and chest-focused muscle-building workouts, often in combination with presses or flyes from other angles to target all portions of the chest.', NULL, false),
('High-Cable Cross Tricep Extention - NB', 'strength', '{"Triceps brachii"}', '{}', '{}', 'The high-cable cross tricep extension is an isolation exercise for targeting the triceps, particularly the long head. It utilizes cables and handles grasped with opposite hands, allowing for a unique pressing motion that can be effective for building tricep strength. Unlike exercises that use a straight bar or rope, this variation can be more comfortable on your wrists and elbows', NULL, false),
('Preacher Curl - Internally Rotated', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Single arm curl that can be done using a dumbbell and a preacher bench, or a preacher curl machine. Turn body towards the weight', NULL, false),
('Lat Pulldown - Cross Body Single Arm', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Sit at lat pulldown machine with body at a diagonal angle so that only one leg is under the pad. Pull the cable down with the opposite arm. this will force the cable to across your body while pulling down. Emphasises the stretch of the lat.', NULL, false),
('Cable Chest Press - Incline', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{}', 'Single arm chest press done with the cable machine. Use the other arm to brace bodyweight to focus on strength of the press, rather than balancing of the body. Start with the hand as close to the chest as possible, and then press against the cable at a slight incline and aiming towards the center of your chest.', NULL, false),
('JM Press', 'strength', '{"Triceps brachii"}', '{"Biceps brachii","Pectoralis major"}', '{"Barbell"}', 'The JM press keeps your shoulders stationary, relying on the elbow flexion and extension to move the weight using your triceps strength. That means you get all the benefits of the best triceps-strengthening exercises without overtaxing that delicate shoulder joint. Classic win-win!', NULL, false),
('Helms Row', 'strength', '{"Latissimus dorsi"}', '{"Trapezius"}', '{"Dumbbell"}', 'Setup: Place your chest on the end of a bench, using a towel or anything soft to keep your chest protected. You want your chest to be in contact with the bench around the nipple line. Your back should be almost parallel to the floor Execution: When you're starting the exercise, focus on pulling your elbows back until you feel maximum tightness in the lats. If you want to get some trap activation with the exercise, relax your shoulder blades when the weights are hanging down and then retract them as you start the rep.', NULL, false),
('Meadows Row', 'strength', '{"Latissimus dorsi","Trapezius"}', '{"Biceps brachii","Rectus abdominis"}', '{"Barbell"}', 'The Meadows row is a unilateral row performed with a landmine setup, overhand grip, and staggered stance. Lean your torso forward and grip the barbell. Rest the other forearm on the forward leg. Start this movement by driving the elbow behind you while retracting the shoulder-blade. Keep the working shoulder down. Pull toward your back hip until the elbow is level with your torso.', NULL, false),
('Cable Triceps Press', 'strength', '{"Triceps brachii"}', '{}', '{}', 'A single arm exercise that starts with the hand close to the chest with with the elbows bent, and the elbow flared out. Press forward and down against the cable straightening the elbow.', NULL, false),
('Cable Tri Extension - Internal Rotation', 'strength', '{"Triceps brachii"}', '{}', '{}', 'single arm exercise with cable held at opposite shoulder with elbow bent. Turn towards the cable, and the straighten the elbow across the body.', NULL, false),
('Front Plank', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis","Pectoralis major","Quadriceps femoris","Serratus anterior"}', '{"none (bodyweight exercise)"}', 'The plank is a bodyweight exercise. As a multi-functional movement, the plank not only targets your abdominal muscles but also the spine and hip. Plank strengthens and tightens your entire body, improves your posture and balance, reduces body fat, and can help boost your metabolism. Exercises such as the "plank pose" help strengthen the stamina of stabilizing abdominal muscles. It can also help relieve back pain associated with a weakening of the function of the stabilizing muscles of the body. Planks are a versatile exercise that targets many of the most important muscle groups in the body, so they can be applied by anyone to improve endurance and overall body strength.', NULL, false),
('Curl  - With Shoulder Elevated', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Place elbow so that it is about level with the shoulder. Curl the wieght to your shoulder. Focus on the stretch in the eccentric part of the curl', NULL, false),
('Lying Leg Raise', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"none (bodyweight exercise)"}', 'Leg raise is one of the most effective exercises for the lower abdominal muscles. Although this exercise targets the rectus abdominus and oblique muscles, it is particularly useful for burning and tightening the lower fat.', NULL, false),
('Jumping Jack HD', 'cardio', '{"Quadriceps femoris"}', '{"Gluteus maximus","Obliquus externus abdominis","Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Jumping jack are a plyometric exercise. Plyometrics are explosive aerobic moves that increase speed, quickness, and power and they work your whole body. Jumping jack target the arm, shoulder, abdominal muscles, hip muscles and hip flexors and also work on the thighs, knee tendons and quadriceps. Jumps are beneficial to your health because they combine cardiovascular conditioning with strength work. Since jumps elevate your heart rate, they can also improve your cardiovascular fitness.', NULL, false),
('Single Leg RDL', 'strength', '{"Biceps femoris"}', '{"Gluteus maximus"}', '{"none (bodyweight exercise)"}', '- Stand upright and hold weights in both hands if using loads. - Brace your core and lift one leg off the ground. - Keep your back straight, hinge at the hips while lowering your torso forward, ensuring you don't rotate your hips. - Lower until you feel a stretch in your standing leg''s hamstring, then return to standing position. Repeat on both sides.', NULL, false),
('High Knee Skips HD', 'cardio', '{"Obliquus externus abdominis","Rectus abdominis"}', '{"Biceps brachii","Gluteus maximus","Quadriceps femoris","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'You can use this exercise both as a dynamic warm-up before training and add it to your cardio training routine to burn fat. High knee skips are a plyometric exercise. Plyometrics are explosive aerobic moves that increase speed, quickness, and power and they work your whole body. High knee skips target the oblique, leg muscles, hip muscles and hip flexors and also work on the thighs, knee tendons, quadriceps and shoulders. Jumps are beneficial to your health because they combine cardiovascular conditioning with strength work. Since jumps elevate your heart rate, they can also improve your cardiovascular fitness.', NULL, false),
('Crunches HD', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Crunch movement is one of the most basic exercises designed to strengthen the core muscles of the body. Exercise helps to strengthen core muscles, improve posture, and increase muscle mobility and flexibility. Improves six pack muscles: When crunch exercise is done, the rectus abdominus and oblique muscles are tightened, so the upper abdominal muscles and six pack muscles develop. Increases the strength of the abdominal muscles: The primary role of your abdominal muscles is to stabilize your mid-section. It supports you while lifting heavy objects, allowing you to twist and rotate your body. These are all day long actions that you do not notice, so it is important that your abdominal muscles can sustain long hours of work. Crunch exercise helps build this important endurance in the abdominal muscles. Muscular endurance is the ability of these fibers to resist resistance for a long time.', NULL, false),
('Bench Dips On Floor HD', 'strength', '{"Biceps brachii","Brachialis","Triceps brachii"}', '{"Anterior deltoid","Pectoralis major","Soleus","Trapezius"}', '{"none (bodyweight exercise)"}', 'Triceps dips on floor are a compound exercise as they worked multiple muscle groups simultaneously. Although this bodyweight exercise mainly targets the triceps, it also hits your chest and front of your shoulder. Triceps dips on floor are one of the most effective exercises to increase arm strength and also build lean muscle in your upper arms. Triceps dips on floor are a closed kinetic chain exercise and express that you do the movements around a fixed point. It increases compression force on your joints thereby improving stability.', NULL, false),
('Reverse hyperextension', 'strength', '{"Rectus abdominis"}', '{}', '{"Kettlebell"}', 'This machine is next to the leg raise station. With your head forward, facing the floor, lift the weight.', NULL, false),
('Bodyweight lunge HD', 'strength', '{"Quadriceps femoris"}', '{"Gluteus maximus","Soleus"}', '{"none (bodyweight exercise)"}', 'Bodyweight lunges are an effective calisthenic exercise for strengthening the lower body, improving balance and stability, and developing functional strength. They are a popular choice for bodyweight workouts, home workouts, and can also be included as part of a larger strength training routine.', NULL, false),
('Lateral Push Off', 'strength', '{"Gastrocnemius"}', '{"Biceps femoris"}', '{"none (bodyweight exercise)"}', 'Push off the ground and land on one leg and regain balance before jumping to the other leg', NULL, false),
('One Arm Overhead Cable Tricep Extension', 'strength', '{"Triceps brachii"}', '{}', '{"Resistance band"}', 'Set the pulley at the bottom of the cable machine and grab onto it without using any attachments. Extend the cable directly overhead. While keeping your back straight and upper arm stationary, lower the cable behind your head until you feel a good stretch in your triceps, and then extend it back upward until your elbow is locked out.', NULL, false),
('Seated Hip Abduction', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'Starting Position: - Adjust the seat height so that your knees are aligned with the pivot point of the machine. - Sit with your back flat against the backrest, maintaining good posture. - Place the outside of your thighs against the machine''s padded levers. - Position your feet flat on the footrests or platform of the machine. - Grasp the handles or sides of the seat for stability. - Ensure your spine is neutral and your core is slightly engaged. Movement: - Exhale as you slowly push your legs outward against the resistance pads. - Focus on initiating the movement from your hips, not your knees. - Continue opening your legs until you feel a strong contraction in your outer hips and thighs. - Hold the fully abducted position briefly (1-2 seconds) to maximize muscle engagement. - Inhale as you slowly control the return of your legs to the starting position, resisting the weight throughout the movement. - Avoid allowing the weight stack to touch down between repetitions to maintain constant tension on the muscles. - Repeat for the desired number of repetitions, maintaining control throughout the set.', NULL, false),
('Forearm Curls (underhand grip)', 'strength', '{}', '{}', '{"Dumbbell"}', '- Engage the muscles - Don''t use momentum - Controlled movement - Slow movement', NULL, false),
('Triceps Overhead (Dumbbell)', 'strength', '{"Triceps brachii"}', '{}', '{"Dumbbell"}', '- Keep the elbows fixed - Engage the muscles - Don''t use momentum - Controlled movement - Slow movement - Don''t overextend', NULL, false),
('Shoulder Raise (Dumbbell)', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', '- Engage the muscles - Don''t use momentum - Controlled movement - Slow movement - Always keep the arms bent - Don''t overextend', NULL, false),
('Wall Angels', 'strength', '{"Trapezius"}', '{"Anterior deltoid"}', '{}', 'The Wall Angels exercise primarily targets the upper back and shoulder muscles, helping improve posture, shoulder mobility, and scapular control.', NULL, false),
('seated figure four', 'strength', '{"Gluteus maximus"}', '{}', '{"Bench"}', 'Seat on a bench. Feet flat on the ground. Place your left ankle over your right knee. Your right knee stays flat. Keep your back straight. Gently push your left knee down.', NULL, false),
('Lower Back Extensions', 'strength', '{}', '{}', '{}', '- Engage the muscles - Lift your bottom slightly - Controlled movement - Slow movement - Don''t use momentum - Keep your upper body straight', NULL, false),
('Dumbbell Hex Press', 'strength', '{}', '{}', '{"Dumbbell"}', '- Engage the muscles - Position your feet wide - Controlled movement - Slow movement - Bring the weights toward your lower chest/stomach', NULL, false),
('Double Kettlebell Clean and Press', 'strength', '{"Anterior deltoid","Biceps brachii","Brachialis","Quadriceps femoris","Trapezius","Triceps brachii"}', '{"Biceps femoris","Gluteus maximus","Latissimus dorsi","Rectus abdominis"}', '{"Kettlebell"}', 'Full-body muscles building exercise. This exercise provides a huge range of benefits in terms of strength & size and is extremely functional.', NULL, false),
('Double Kettlebell Front Squat', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Biceps femoris","Gastrocnemius","Rectus abdominis"}', '{"Kettlebell"}', 'The kettlebell front squat is a compound, multi-joint exercise that works several muscle groups.', NULL, false),
('Blackroll', 'strength', '{}', '{}', '{}', '- Controlled movements - Slow movements - Don''t use momentum', NULL, false),
('Dumbbell Split Squat', 'strength', '{}', '{}', '{"Dumbbell"}', '- Controlled execution - No momentum - Execute slowly', NULL, false),
('Dumbbell Deadlift', 'strength', '{}', '{}', '{"Dumbbell"}', '- Controlled execution - Don''t use momentum - Slow execution', NULL, false),
('box jumps', 'cardio', '{"Gluteus maximus"}', '{"Gastrocnemius"}', '{"none (bodyweight exercise)"}', 'Jump from a standing position onto the box, stretch your body, then step down again (do not jump)', NULL, false),
('Rotary Torso Machine', 'strength', '{"Rectus abdominis"}', '{}', '{}', '- Slow and Steady - Not too much weight', NULL, false),
('Recumbent Bike', 'cardio', '{"Biceps femoris","Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{}', '{}', 'For this exercise Recumbent Bike is needed. You just sit on it, set level and time and start the workout', NULL, false),
('TORSO TWIST', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Standing Torso Twist WorkoutTarget your core and improve flexibility with this dynamic standing exercise! The Standing Torso Twist Workout involves twisting your torso while keeping your feet and hips stable, engaging your obliques, and stretching your entire upper body. This movement helps to:Strengthen core musclesIncrease flexibility in the spine and torsoImprove posture and balanceEnhance overall athletic performancePerform 3 sets of 10-15 reps, twisting to each side, to feel the benefits of this effective and efficient workout!', NULL, false),
('Band pull-aparts', 'strength', '{}', '{}', '{}', '- Hold the band with your arms extended in front of you at shoulder height. - Keep your elbows slightly bent but fixed throughout the movement. - Pull the band apart by spreading your arms until the band touches or comes close to your chest. - Slowly bring your arms back to the starting position, controlling the tension on the band.', NULL, false),
('Upper Back', 'strength', '{"Anterior deltoid","Trapezius"}', '{"Biceps brachii","Latissimus dorsi"}', '{}', 'Upper Back is suitable for building up the core muscles with a special focus on the deltoid and rhomboid muscles and the upper back muscles', NULL, false),
('Bodyweight Squat HD', 'strength', '{"Quadriceps femoris"}', '{"Gastrocnemius","Gluteus maximus","Obliquus externus abdominis","Rectus abdominis","Soleus"}', '{"none (bodyweight exercise)"}', 'Squat is a type of bodyweight exercise. It is one of the most popular exercises for strength and muscle growth. Squat is particularly effective for focusing on the muscles of the leg and hips. Squat are an easy exercise for beginners to do. It can help strengthen leg muscles, tighten hip muscles and burn calories to lose weight. It tightens the butt and legs. Squats are very effective for firming and strengthening your legs by acting on the gluteus,hip flexors, quadriceps, hamstrings and inner thigh muscles. Also, bodyweight squats can help shape your glutes and butt.', NULL, false),
('Pullover Machine', 'strength', '{"Latissimus dorsi"}', '{"Pectoralis major","Triceps brachii"}', '{}', 'Pullover machine, sitting, elbows on pads', NULL, false),
('Zottman curl', 'strength', '{"Biceps brachii","Brachialis"}', '{}', '{"Dumbbell"}', 'With your palms facing forward, curl the weights up to your shoulders. Turn your hands so that that your palms downwards and slowly return the weights back down. Finally face your palms back forward.', NULL, false),
('Thruster', 'strength', '{"Anterior deltoid"}', '{"Trapezius"}', '{"Barbell"}', '- Start by doing a front squat - At the top position, push the bar above your head (similar to a press) - Lower the bar to the shoulders', NULL, false),
('Hamstring Kicks', 'strength', '{"Biceps femoris"}', '{"Gluteus maximus"}', '{"none (bodyweight exercise)"}', 'Stand with your feet hip-width apart and extend one arm in front of you. Swing that leg up in front of you and back down while keeping your leg as straight as possible and your toes pointed up.Repeat with the other leg.', NULL, false),
('Toe Touch', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{"Gastrocnemius"}', '{"none (bodyweight exercise)"}', 'Stand with your feet closer together. Hinge at your hips and lower your upper body towards your toes. Reach your hands towards your feet, try to touch your toes, the ground, or as far down your legs as you can comfortably go.', NULL, false),
('Dumbbell Thruster', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Anterior deltoid"}', '{"Dumbbell"}', 'Start with the dumbbells resting on your shoulders and squat down. Push into standing and raise the dumbbells into an overhead position. Bring the dumbbells back to your shoulders and repeat.', NULL, false),
('Glute Bridge Single-Arm Press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Biceps brachii","Biceps femoris","Gluteus maximus","Triceps brachii"}', '{"Dumbbell"}', 'With one dumbbell in hand, perform a glute bridge. Now hold the dumbbell above your chest, this is the rep starting position. Lower the dumbbell so that your elbow touches the floor or is roughly 45 degrees below your shoulder if using a bench. Push the dumbbell back into the starting position.', NULL, false),
('Bear crawl pull through', 'strength', '{"Anterior deltoid","Gluteus maximus","Quadriceps femoris","Rectus abdominis"}', '{"Biceps femoris","Gastrocnemius","Trapezius"}', '{"Dumbbell"}', 'Place a dumbbell at around hip level and assume a bear crawl position. Push the knees off the floor and hold. With the opposite hand reach for the dumbbell and pull it to the other side. Place your hand back on the floor and repeat with your other hand.', NULL, false),
('Triceps Dips (Assisted)', 'strength', '{"Triceps brachii"}', '{"Pectoralis major"}', '{}', 'Assisted triceps dips is a gym work out exercise that targets triceps and also involves chest.', NULL, false),
('Cable Lateral Raises (Single Arm)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'The single arm cable lateral raise is a variation of the lateral raise and an exercise used to build the muscles of the shoulders. - Position a cable at the lowest position possible and attach a single handle. - Reach across your body and grab the handle with a neutral grip. - Keep the elbow slightly bent and pull the handle across your body and raise laterally. - Slowly lower the handle back to the starting position under control.', NULL, false),
('Elephant Walks', 'strength', '{"Biceps femoris"}', '{"Gastrocnemius"}', '{"none (bodyweight exercise)"}', 'Hinge at your hips until you feel a stretch behind your knees. Bend one leg while the other is straight then fluidly bend the other knee while straightening the first knee.', NULL, false),
('Good Morning', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'Stand with your feet more than shoulder-width apart (wider stance) and place your hands on your hips. Hinge at your hips and lower your upper body towards the ground while keeping your back straight then come back up.', NULL, false),
('Single Leg Hamstring Stretch', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'Sit on the ground with one leg straight out in front of you and the other leg bent in toward you. Reach forward with both hands, trying to touch the toes of your straight leg.', NULL, false),
('Sit & Reach', 'strength', '{"Biceps femoris"}', '{}', '{"Gym mat"}', 'Sit on the ground with your legs extended straight in front of you. Reach both hands forward, trying to reach past your toes or as far as you can go. Return to the starting position and repeat.', NULL, false),
('Crossbody Leg Swings', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'Hold onto a wall or something near you for support. Swing one leg across the front of your body, then back and out to the side. Repeat while slowly increasing your range of motion.', NULL, false),
('Standing Pancake', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'Stand and open your legs as wide as possible into a straddle position. Then bend at the hips, pushing them back while keeping your back straight.', NULL, false),
('Hamstring Chokes', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'Sit on the ground and bend one leg, bringing your knee toward you. Place your hand behind your hamstring and gently pull your leg toward your chest, feeling a stretch in the back of your thigh. Straighten your leg, extending up toward the ceiling.', NULL, false),
('Roll Down', 'strength', '{}', '{"Biceps femoris"}', '{"none (bodyweight exercise)"}', 'Stand with your feet hip-width apart and slowly roll your upper body forward, one vertebra at a time, until your hands touch the ground or as far as you can comfortably go. Roll back up to the starting position in the same controlled manner.', NULL, false),
('Crossbody Hamstring Stretch', 'strength', '{"Biceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'While standing, cross one leg behind the other (keep this leg straight). Reach downward and try to touch the toes of that leg. Slightly bend the other leg so that you can bend down.', NULL, false),
('Preacher Curl - Externally Rotated', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Single arm curl that can be done using a dumbbell and a preacher bench, or a preacher curl machine. Turn body away from the weight', NULL, false),
('Plank-to-Elbow Extension', 'strength', '{"Anterior deltoid","Rectus abdominis","Triceps brachii"}', '{"Obliquus externus abdominis","Pectoralis major"}', '{}', 'The Plank-to-Elbow Extension is a dynamic exercise that combines the plank with an elbow extension movement', NULL, false),
('Cossack squat', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Gastrocnemius","Rectus abdominis"}', '{}', 'The Cossack Squat is a multi-joint exercise that works mainly on the legs and buttocks, but also involves stabilizing muscles. It is an excellent exercise for improving strength, mobility and stability in a functional way.', NULL, false),
('Wall-sit', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Gastrocnemius","Rectus abdominis"}', '{}', 'The Wall Sit (or wall chair) is an isometric exercise that mainly involves the leg muscles, improving muscular endurance and stability. Here are the main and secondary muscles activated during the exercise.', NULL, false),
('Dragon-flag', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{"Anterior deltoid","Gluteus maximus","Latissimus dorsi","Triceps brachii"}', '{}', 'Keep your body completely rigid throughout the movement, avoiding sagging in your lower back. Use a firm grip to stabilize your upper body. Start with simpler versions (such as with bent knees) to build strength and control.', NULL, false),
('Plank with Alternating Leg Lift', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'In a plank position, lift one leg alternately.', NULL, false),
('Heel Touches', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', '- Starting Position: - Lie on your back on an exercise mat. - Bend your knees, keeping your feet flat on the floor and hip-width apart. - Place your arms along your sides, palms facing inward, just off the floor. - Engage Core: - Lift your head, shoulders, and upper back slightly off the ground. - Keep your neck neutral and chin slightly tucked. - Perform the Movement: - Side-bend to the right, reaching your right hand toward your right heel. - Return to the center, then side-bend to the left, reaching your left hand toward your left heel. - Continue alternating sides in a controlled manner. - Breathing: - Exhale as you reach toward your heel and inhale as you return to the center.', NULL, false),
('bicycle crunches', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"none (bodyweight exercise)"}', 'Bicycle crunches are a core exercise performed on the floor. Lie on your back with your hands behind your head and legs extended. Lift your shoulders off the ground, bring one knee toward your chest, and twist your torso so your opposite elbow meets the knee. Alternate sides in a pedaling motion, ensuring controlled movements and engaging your core throughout the exercise.', NULL, false),
('Hack Squats', 'strength', '{"Quadriceps femoris"}', '{"Biceps femoris","Gastrocnemius","Gluteus maximus"}', '{}', 'Hack squats target the lower body and are performed on a hack squat machine or with a barbell. For the machine variation, position yourself on the platform with your shoulders under the pads and feet slightly forward. Push through your heels to lift the weight, then bend your knees to lower the platform in a controlled motion until your thighs are parallel to the ground. Push back up to the starting position. For the barbell variation, hold the bar behind your legs with your arms extended and perform a squat-like motion.', NULL, false),
('Dumbbell Crunches', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis"}', '{"Dumbbell"}', 'Dumbbell crunches are a weighted variation of traditional crunches designed to target the abdominal muscles more intensely. Lie flat on your back with your knees bent and feet flat on the floor. Hold a dumbbell with both hands close to your chest or above your head. Lift your shoulders and upper back off the ground in a crunching motion, engaging your core. Slowly lower yourself back to the starting position. Ensure controlled movements throughout the exercise to prevent strain.', NULL, false),
('Biceps Curl Machine', 'strength', '{"Biceps brachii"}', '{"Brachialis"}', '{}', 'The biceps curl machine is designed to isolate the biceps muscles and provide a controlled range of motion. Sit on the machine with your back against the pad and adjust the seat so your arms are aligned with the machine''s handles or pads. Grip the handles firmly, keeping your elbows fixed in place, and curl the handles upward by contracting your biceps. Slowly lower the handles to the starting position, maintaining control throughout the movement.', NULL, false),
('Toe Taps', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Toe taps are a core-focused exercise performed lying on your back. Lie flat with your arms by your sides and your legs raised to a tabletop position (knees bent at 90 degrees). Slowly lower one foot to gently tap the floor, keeping your core engaged and your lower back pressed into the ground. Return to the starting position and alternate legs. This exercise strengthens the core while minimizing strain on the lower back.', NULL, false),
('Standing Side Crunches', 'strength', '{"Obliquus externus abdominis"}', '{"Rectus abdominis"}', '{"none (bodyweight exercise)"}', 'Standing side crunches are a dynamic exercise that targets the obliques while improving balance and stability. Stand upright with your feet shoulder-width apart and hands behind your head or holding a dumbbell in one hand. Lean your torso to one side, contracting your obliques, while bringing your elbow toward your hip (or crunching toward the weight if using a dumbbell). Return to the starting position and alternate sides or perform all repetitions on one side before switching.', NULL, false),
('Dumbbell Shoulder Rotations', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', 'Dumbbell shoulder rotations are designed to strengthen the rotator cuff muscles and improve shoulder stability and mobility. - External Rotation: Hold a dumbbell in one hand, keeping your elbow bent at 90 degrees and close to your body. Rotate your forearm outward, away from your body, keeping your elbow stationary. Slowly return to the starting position. - Internal Rotation: Hold a dumbbell in one hand, keeping your elbow bent at 90 degrees and close to your body. Rotate your forearm inward, toward your body, and slowly return to the starting position. Perform the exercise with controlled movements to avoid strain.', NULL, false),
('Plate Pinch Hold', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'The plate pinch hold is a grip strength exercise designed to target the forearms and improve grip endurance. Select one or two weight plates (smooth-edged plates work best) and pinch them together between your thumb and fingers. Hold the plates with your arm straight down by your side or extended slightly in front of you. Maintain the hold for as long as you can, keeping your shoulders relaxed and your grip firm. This exercise can be done for time or repetitions.', NULL, false),
('Reverse Wood Chops', 'strength', '{"Gluteus maximus","Latissimus dorsi"}', '{"Anterior deltoid","Biceps brachii","Obliquus externus abdominis","Quadriceps femoris","Rectus abdominis"}', '{"none (bodyweight exercise)"}', '- Attach a looping resistance band to a rack below knee height - Grip the other end of the band like holding a baseball bat with both hands - Stretch the band facing it - Start with your hands at the side of your hips, knees bent - Rotate your hips while moving your hands towards over the top of your opposite shoulder - Imagine the motion as striking a baseball with a bat', NULL, false),
('Lat Pull DB', 'strength', '{"Latissimus dorsi"}', '{"Gluteus maximus"}', '{"Dumbbell"}', '- Bend upper body forward - Move dumbbells near your body with slightly bent arms towards your back', NULL, false),
('Scapula Pulls', 'strength', '{"Latissimus dorsi","Trapezius"}', '{}', '{"Pull-up bar"}', '- Hang straight on a pull-up bar - Pull shoulder blades together, moving the body slightly up', NULL, false),
('Pin Bench Press BB', 'strength', '{"Pectoralis major","Triceps brachii"}', '{}', '{"Barbell"}', '- Set security pins to about the height of your sticking point - Lower the bar, rest on the pins for 1s while holding tension - Move bar up with maximum force', NULL, false),
('Pin Squat', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Rectus abdominis"}', '{"Barbell"}', '- Set security pins to about the height of your sticking point - Lower the bar, rest on the pins for 2s keeping tension - Stand up with maximum force', NULL, false),
('Clean', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Biceps femoris","Latissimus dorsi","Rectus abdominis"}', '{"Barbell"}', 'Regular olympic lift clean. Pull bar from ground, catch on shoulders performing a front squat.', NULL, false),
('Pin OHP', 'strength', '{"Anterior deltoid","Triceps brachii"}', '{}', '{"Barbell"}', '- Set security pins to the height of your lower chin - Rest bar on pins keeping tension - Raise bar over head', NULL, false),
('Push OHP', 'strength', '{"Anterior deltoid","Gluteus maximus","Quadriceps femoris"}', '{"Triceps brachii"}', '{"Barbell"}', '- Rest bar in front on your shoulders - Bend knees while keeping upper body straight - Extend legs pushing the bar overhead with force', NULL, false),
('Incline OHP DB', 'strength', '{"Anterior deltoid"}', '{"Triceps brachii"}', '{"Dumbbell"}', '- Sit on a bench with 45 degrees incline - Ellbows 45 degrees out - Move dumbbells down until upper arms are parallel to shoulders - Move dumbbells up, meeting overhead', NULL, false),
('Kreis Press DB', 'strength', '{"Anterior deltoid"}', '{"Biceps brachii","Pectoralis major","Rectus abdominis","Triceps brachii"}', '{"Dumbbell"}', '- Sit on a bench with 45 degrees incline - Hold dumbbells overhead - Move dumbbells down as if doing overhead press - Rotate dumbbells palms facing up and extend your arms in front of your body - Move hands together until dumbbells meet, keep arms extended - Reverse the motion until dumbbells are overhead again - This is one repetition', NULL, false),
('Shoulder Raise Side and Front DB', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', '- Stand while holding dumbbells beside body - Keep arms almost fully extended - Without momentum raise dumbbells to the side of your body until shoulder height, palms facing down - Lower dumbbells beside body, palms facing inwards - Immediately raise dumbbells in front of your body until shoulder height, palms facing down - Down again - This is one repetition', NULL, false),
('Incline Chest Press DB', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"Dumbbell"}', '- Bench 45 degrees incline - Hold dumbbells parallel on your chest - Press up until arms extended', NULL, false),
('Jerk OL', 'strength', '{"Anterior deltoid"}', '{"Gluteus maximus","Quadriceps femoris","Triceps brachii"}', '{"Barbell"}', 'Olympic lift jerk - Hold bar in front on shoulders like push press - Bend and extend knees pushing bar up while diving under the bar - Catch bar overhead with straight arms using lunge - Move feet parallel while holding bar in lockout', NULL, false),
('Clean and Jerk OL', 'strength', '{"Anterior deltoid","Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Latissimus dorsi","Rectus abdominis","Trapezius","Triceps brachii"}', '{"Barbell"}', 'Olympic lift clean and jerk. Combination of clean and jerk in one motion.', NULL, false),
('Snatch OL', 'strength', '{"Anterior deltoid","Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Latissimus dorsi"}', '{"Barbell"}', 'Olympic lift snatch - Pull barbell from ground to overhead lockout using a wide grip and overhead squat. - Move bar slowly until cleared knees then explosively extend hips, pull bar up and dive under the bar - Catch bar overhead with straight arms - Push head forward during lockout', NULL, false),
('Seated W Curl', 'strength', '{"Biceps brachii","Brachialis"}', '{}', '{"Bench","Dumbbell"}', '- Sit on bench with 60 degrees incline - Hold dumbbells beside body near the ground, palms facing outwards, arms fully extended - Move dumbbells up using only biceps and without momentum', NULL, false),
('ClimbMill', 'cardio', '{"Quadriceps femoris"}', '{"Biceps femoris","Gluteus maximus"}', '{}', 'The ClimbMill, also known as a stair climber, is a cardio-focused machine that simulates climbing stairs. It provides an effective way to improve endurance while strengthening the lower body. To use the machine, step onto the moving stairs, maintain an upright posture, and use the handrails for balance if needed. Adjust the speed and intensity to match your fitness level. This exercise helps improve cardiovascular health, burns calories, and enhances lower body muscle endurance.', NULL, false),
('Cobra Stretch', 'strength', '{"Rectus abdominis"}', '{"Pectoralis major"}', '{"none (bodyweight exercise)"}', 'The Cobra Stretch is a back extension exercise that helps improve spinal flexibility and relieve lower back tension. To perform, lie face down on the floor with your hands placed under your shoulders. Press your palms into the floor and lift your chest while keeping your hips on the ground. Keep your elbows slightly bent and your shoulders relaxed. Hold the stretch for a few seconds, then slowly lower yourself back down. This exercise is beneficial for improving posture and reducing lower back stiffness.', NULL, false),
('Torso rotation stretch', 'strength', '{"Obliquus externus abdominis"}', '{"Pectoralis major"}', '{"none (bodyweight exercise)"}', 'The torso rotation stretch helps improve spinal mobility and relieves tension in the lower back and obliques. It can be performed standing or seated. - Standing Variation: Stand upright with your feet shoulder-width apart. Place your hands on your hips or extend your arms in front of you. Slowly rotate your torso to one side, keeping your hips stable. Hold for a few seconds, then rotate to the opposite side. - Seated Variation: Sit on a chair with your feet flat on the floor. Place one hand on the outside of your opposite thigh and gently twist your torso toward that side. Hold the stretch before switching sides.', NULL, false),
('Knee to Chest Stretch', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris"}', '{"none (bodyweight exercise)"}', 'The knee to chest stretch is a simple yet effective exercise for relieving lower back tension and improving hip mobility. To perform, lie flat on your back with your legs extended. Bring one knee toward your chest, wrapping your hands around your shin or behind your thigh. Gently pull the knee closer to your chest while keeping the other leg straight on the floor. Hold the stretch for 15-30 seconds, then switch sides. For a deeper stretch, both knees can be pulled toward the chest simultaneously.', NULL, false),
('Towel Superman', 'strength', '{"Latissimus dorsi"}', '{"Anterior deltoid"}', '{}', 'In this exercise, you lie flat on your stomach, hold a towel with your arms extended in front of you, and pull it apart to create tension. Then, you move it forward and back under your stomach. This exercise targets the back and shoulder muscles as well as core stability.', NULL, false),
('Cable Press Around', 'strength', '{"Anterior deltoid","Pectoralis major","Triceps brachii"}', '{"Biceps brachii","Serratus anterior"}', '{}', 'Set the cable pulley at chest height and attach a D-handle bar. Grab the handle with a neutral grip and hold it next to your chest with your elbow fully flexed and tight to your side. Turn away from the pulley so your torso is at 45 degrees. Hold the other side of the functional trainer with your corresponding hand. Assume a staggered stance for better balance. While keeping your chest proud, extend your elbow at 45 degrees across your midline while keeping your arm parallel to the floor. Stop shy of lockout and contract your chest at the top of the range of motion (ROM).', NULL, false),
('Cross-Body Cable Y-Raise', 'strength', '{"Anterior deltoid","Latissimus dorsi","Trapezius"}', '{}', '{}', 'Attach a D-Bar to the cable machine. Perform a motion akin to drawing a sword from across your body.', NULL, false),
('No Leg Drive Dumbbell Chest Press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{"Bench","Dumbbell"}', 'Set up for a normal Dumbbell chest press but lift your leg ups straight or put them on another bench to remove the leg drive.', NULL, false),
('punches', 'strength', '{"Anterior deltoid","Triceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'stand stable and throw normal straight punches', NULL, false),
('Dumbbell Underhand Dead Row', 'strength', '{"Biceps brachii"}', '{"Latissimus dorsi"}', '{"Dumbbell"}', 'The Dumbbell Underhand Dead Row will involve the back, which means you can try a bit heavier weight. The catch is that you need to be able to control the weight for all the reps. - Start by holding a pair of dumbbells with your feet shoulder-wide apart and your knees slightly bent. - Hinge at your hips to lower your torse forward until it''s almost parallel to the floor, keeping your back flat and maintaining a slight bend in your knees. - Exhale as you row the dumbbells to your sides up to chest height, leading with your elbows until your upper arms are just past parallel to the floor and the dumbbells are at ribcage level. - Slowly lower to the starting position and repeat. Keep your back flat all the time.', NULL, false),
('Pause Hack Squats', 'strength', '{"Quadriceps femoris"}', '{"Biceps femoris","Gastrocnemius","Gluteus maximus"}', '{}', 'Hack Squats but with a 1-2s pause at the bottom of the movement. This makes sure that there is no more elastic energy stored in the muscles.', NULL, false),
('Spider Curl', 'strength', '{"Biceps brachii"}', '{}', '{"Incline bench"}', 'To get the most out of DB Spider Curls, you need an adjustable weight bench set at a 45-degree incline. This inclined position allows your arms to hang freely, putting them in an extended start position with elbows slightly in front of your torso, which is the key to maintaining low-level isometric tension throughout the movement pattern. - Lie face-down on an adjustable weight bench with your chest fully supported, holding a pair of dumbbells. - Keep a neutral head position and don't crane your neck. - Let your arms hang straight down with your palms facing forward (for a standard Spider Curl) or palms facing inward for a Hammer Curl exercise variation. - Keep a stable foot position on the floor to maintain balance and control. - Start the curl motion by flexing your biceps muscles and lifting the pair of dumbbells or curl bar toward your shoulders. - Keep your elbow flexion controlled. Your arms should stay locked in position with no unnecessary movement. - Squeeze hard at the top for 1-2 seconds. This is where maximum tension hits the biceps muscle fibers. - Lower the weight under control for 3-4 seconds to keep muscles under tension for the entire range of motion.', NULL, false),
('Calf Raise using Hack Squat Machine', 'strength', '{"Gastrocnemius","Soleus"}', '{}', '{}', 'Ideally using a trapeze addon, Lift the weight up using your calves by getting on your toes.', NULL, false),
('Incline Close Grip Barbell Bench Press', 'strength', '{"Triceps brachii"}', '{"Anterior deltoid","Pectoralis major"}', '{"Barbell"}', 'Narrower grip than regular bench press, just outside shoulder width.', NULL, false),
('Floor Skull Crusher', 'strength', '{"Triceps brachii"}', '{}', '{"SZ-Bar"}', 'Allowing you to safely load more weight than a regular skull crusher, lie on the floor and rest the weight on the floor in between each repetition.', NULL, false),
('Bent over Cable Flye', 'strength', '{"Pectoralis major"}', '{}', '{}', 'Holding your upper body at an approximate 105 degrees angle.', NULL, false),
('1-Arm Half-Kneeling Lat Pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Attach a D-Handle to a high pully. And use your lat muscles to pull the weight single handedly.', NULL, false),
('Kroc Row', 'strength', '{"Latissimus dorsi","Trapezius"}', '{}', '{}', 'Dumbbell rows with looser technique but heavier weight.', NULL, false),
('Cable Shrug-In', 'strength', '{"Trapezius"}', '{}', '{}', 'Attach two D-Handles to two low cables and shrug in using your upper traps.', NULL, false),
('Reverse Cable Flye', 'strength', '{"Anterior deltoid"}', '{"Trapezius"}', '{}', 'Attach D-Handles to two cable pulleys in the upper position. Grab the left on with your right hand and vice-versa.', NULL, false),
('W-Raise', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'This challenging exercise is a variation of reverse crunches that is made up of three parts in which we're basically drawing an upside down 'W' with our legs. Start position is lying face up flat on the floor with legs extended at the low point of the outer leg of the 'W'. Keeping a strong core and legs straight, go up, rise your hips and then slowly lower your legs down halfway. Then, lifting your legs back up to the top, rise your hips again, maintaining that straight line, use your core strength to finally come back all the way down to the other outer leg of the W. Then you reverse the 'W' to return to the start.', NULL, false),
('Black Widow Knee Slides', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{}', 'In this bottom-up rotation exercise movement, you'll cross your knee over and drive it into that opposite elbow. Start in high plank position (or tabletop position) with hands directly beneath your shoulders. Lift the left knee toward the right arm and slide it up the forearm to get more of that posterior pelvic tilt and engagement of the abdominal muscles. Then do the opposite side, bringing your right knee toward your left hand.', NULL, false),
('Butterfly Sit Up', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'In this midrange exercise your arm muscles provide you with a little bit of momentum to help to get you off the ground. You also open them up in overhead position which engages the upper back. Start lying with feet flat on the ground, knees at an angle, arms crossed in towards your chest. Using your ab muscles, bring your upper body off the ground as you open your arms into goal post position, then slowly lower yourself back down to return to starting position.', NULL, false),
('Seated Corkscrew', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'To do this abs and obliques exercise, start with your hands back behind your body and bring your knees in and across, really trying to contract the obliques. Then extend your legs back out to starting position and repeat toward the opposite side of the abs. Beginners might find that they can't even get through the first 45 seconds of this challenging reverse crunches variation. That's ok because it gives you a place to start and something to improve upon.', NULL, false),
('Levitation Crunch', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'For this top down movement, we're trying to move the upper torso without moving the lower torso. Start lying on the ground with feet flat on the floor and crossed arms above your head with hands behind head. Lift upper body up and clear your shoulder blades off the ground and then hold and pause at the top for a one or two count. Try to make the upper abs work and hold that contraction for 10 good quality reps.', NULL, false),
('Sit Up Elbow Thrust', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'This is a top down rotation movement, and it's a bit more explosive, too. Lying with knees bent and feet on the floor, sit up and then drive your left elbow across your entire body toward the right, then come back to center and then finally lower yourself down. Then hit the other side.', NULL, false),
('Lying Triceps Extensions', 'strength', '{"Triceps brachii"}', '{}', '{"Barbell","Dumbbell"}', '- Starting position for this practical triceps exercise is lying on a standard bench holding a barbell or two dumbbells in both hands with an overhand grip, hands at shoulder width apart. - Begin with arms over your upper chest and elbows bent back at about a 45-degree angle. - First bend at the elbows and then allow the upper arm to drop back, bringing the barbell/dumbbells behind your head and down toward the floor. In terms of upper arm position, the barbell/dumbbells should never be fully above your head, but instead behind it, to ensure that you're targeting the triceps. - Keep the shoulder blades tucked under, the elbows tight in toward your head and your core active during this entire movement.', NULL, false),
('Drag Pushdown', 'strength', '{"Triceps brachii"}', '{}', '{"SZ-Bar"}', '- Starting position for this rope pushdown is standing facing a cable machine with the handles of a rope attachment in both hands and feet shoulder width apart. - Hinge forward slightly at the hips maintaining an upright chest and bring the shoulders and elbows behind the body so that when you push down on the cable attachments, you can get a fully contracted triceps long head. - Drag the cable machine rope attachment as close to the body as possible and straighten your elbows until lockout.', NULL, false),
('Dumbbell Cheat Curl', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', '- Starting position is standing with feet shoulder width apart. - Hands should take an underhand or supinated grip on the dumbbells holding them with hands shoulder width apart. - Keeping elbows tucked into your sides throughout the entire movement, use momentum to curl the dumbbells, squeezing your biceps at the top of the movement. - Slowly lower to return to the starting position. Keep the core tight throughout the exercise. Cheating through the concentric curling portion of this challenging exercise gives us a great opportunity to increase time under tension and create eccentric overload with heavier weight when we lower.', NULL, false),
('Bizeps Curls Trifecta', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'This exercise is a mixture of three different curls: the Supinated Cross Body Curl, the Pronated Cross Body Curl and the No Money Curl. You alternate between three curl variations that each accomplish different goals, and you'll keep the set going beyond the usual 8-12 rep range which gives us that intensity. - For the Supinated Cross Body Curl, supinate the forearm with palms facing toward the ceiling and forearms coming across the body. Lift the inner-facing weight of the dumbbell towards your shoulder. - For the Pronated Cross Body Curl, pronate the forearm with palms facing toward the floor (pronated grip or overhand grip) and forearms coming across the body. Lift the inner-facing weight of the dumbbell towards your shoulder. - For the No Money Curl, you'll curl the dumbbell as you outwardly rotate the shoulder. Lift the inner-facing weight of the dumbbell towards your outer side of the shoulder.', NULL, false),
('Omni Cable Cross-over', 'strength', '{"Pectoralis major"}', '{}', '{"SZ-Bar"}', 'Adjust the weights based on the motion. When pulling from top to bottom, increase the weight by 20% to 40% more than the bottom-to-top motion. This accounts for the fact that when operating from top down, the upper chest muscles are naturally weaker than the lower chest muscles. So, adjust your weight stack to compensate. - Position one cable at a high setting and the other at the lowest level setting. Get into a staggered stance in between the cable towers. - For the cable set low, pull it upward and across your body. This effectively targets the upper chest. - For the cable set high, draw it downward and across your body. This will primarily engage the lower chest. Once you're done, swap the positions of the cables. Change the previously high cable to the lowest position and vice versa. Repeat the exercise sequence, ensuring you're targeting both chest regions effectively.', NULL, false),
('Rocking Triceps Pushdown', 'strength', '{"Triceps brachii"}', '{}', '{"SZ-Bar"}', 'Set your feet below the rope and lean your upper body towards the rope. Set one foot back. Push down the rope and lean your entire body back onto the rear foot as you push down to get your hands behind your body. Don''t forget to bring your chest to the front during the pushdown. As you release the rope slowly, lean your body back onto the front foot.', NULL, false),
('Alternating High Cable Row', 'strength', '{"Latissimus dorsi"}', '{}', '{}', '- Start by putting the attachment in a high position on the cable station and step back about 1m from the attachment. Grab the cable pulley handle in your left hand at about head height with your elbow slightly bent. Step back with your left foot. - Pull your elbow joint in toward the torso twisting slightly and perform a single-arm row. Engage the lats as you twist. - Return to the starting position with cable pulley and left foot and grab the cable pulley handle in the right hand. Repeat this motion on the opposite side with your right foot stepped back.', NULL, false),
('Hyper Y W Combo', 'strength', '{"Latissimus dorsi"}', '{}', '{}', '- Use a glute-ham raise or a stability ball for this exercise and a light weight plate in each hand. - Raise your torso to form a straight line with your legs and raise the arms outward slightly beyond a 90-degree angle into a W position to hit the rotator cuff muscles, and then lower back to the starting position. - Then raise up again with arms in a Y position to activate the lower traps.', NULL, false),
('Dumbbell Pullover', 'strength', '{"Latissimus dorsi"}', '{}', '{"Dumbbell"}', '- Starting position is lying across a flat bench perpendicularly with your feet flat on the ground, holding a dumbbell overhead with both hands. - With a slight bend in the elbow, begin lowering the dumbbell over and behind the head with the arm muscles in extended position. - Then reverse the movement bringing the dumbbell back up and over the head. - Keep your abdominal muscles tight and spine stable throughout allow repetitions and don't allow your back to arch up away from the flat bench.', NULL, false),
('Plank Jacks', 'strength', '{"Gluteus maximus","Obliquus externus abdominis","Rectus abdominis"}', '{"Gastrocnemius","Quadriceps femoris"}', '{}', 'Jumping jacks from the plank position.', NULL, false),
('Lying Triceps Kickback', 'strength', '{"Triceps brachii"}', '{}', '{"Dumbbell","Incline bench"}', 'Set the bench to an 60deg angle. Stand still and rest your upper body on the inclined bench, ensuring a nearly straight line of your entire body. Squeeze your shoulder blades together, so that your elbows are located behind your torso with your upper arms nearly parallel to the floor. Lift the dumbbells until your arms form a straight line. Slowly lower the dumbbells back to the initial position. Initial position corresponds to an rectangular position of upper and lower arms.', NULL, false),
('Single-arm cable row', 'strength', '{"Latissimus dorsi"}', '{}', '{"Pull-up bar"}', 'Neutral grip. The single-arm row, also known as the saw row, is an exercise that strengthens the back and the biceps and also improves posture.', NULL, false),
('High Row', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Kneeling down on one leg and pulling cable down while driving elbow into the lats.', NULL, false),
('Bayesian Curl', 'strength', '{"Biceps brachii"}', '{}', '{}', 'Cable curl with stretched shoulder (backwards)', NULL, false),
('DB Upper Chest Variation', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{"Dumbbell"}', 'Dumbbell in hand in a curl fashion, lean body into the arm to help the dumbbell up above the chest, next to the head, to activate chest and delt combo', NULL, false),
('DB Underhand bench press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{"Bench","Dumbbell"}', 'Underhand grip DB, perform a normal bench press movement, keeping the elbows close to the chest', NULL, false),
('Elbows Tucked DB Bench Press', 'strength', '{"Triceps brachii"}', '{"Pectoralis major"}', '{"Bench","Dumbbell"}', 'Elbows Tucked DB Bench Press, chest press movement focusing on the triceps. DB stays parallel with body', NULL, false),
('DB UCV', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{"Dumbbell"}', 'Dumbbell upper chest variance. Curl like movement up above at head level, activating chest and front delts', NULL, false),
('Alternative DB Gorilla rows', 'strength', '{"Latissimus dorsi"}', '{}', '{"Dumbbell"}', 'Slightly bent down and knees to mimic a gorilla position and pull/row up the DBs to the chest. DB stay straight (thumbs pointing up)', NULL, false),
('DB Cross Body Hammer Curls', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Dumbbell cross body biceps curls, works on the braccialis', NULL, false),
('Dumbbell Frog Press', 'strength', '{"Gluteus maximus"}', '{}', '{"Dumbbell"}', 'Similar to hip thrust, but with feet put up together, lifting the butt off the ground in a frog like position.', NULL, false),
('Dumbbell Bradford press', 'strength', '{"Anterior deltoid"}', '{}', '{"Dumbbell"}', 'From a front hold of the DBs in a OHP, press above the head, bring back towards the rear of the shoulders, down, and press back forward.', NULL, false),
('Cable Fly Middle Chest', 'strength', '{"Pectoralis major"}', '{}', '{}', 'Execution - Start position: Arms extended out to your sides (a big "T" shape), feeling a stretch in your chest. - Movement: Bring your hands together in front of your chest in a wide hugging motion. - Focus on squeezing your chest at the center. - Do not lock your elbows or turn it into a press. - Return: Slowly open your arms back to the start, maintaining tension on the chest.', NULL, false),
('Cable Fly Upper Chest', 'strength', '{"Pectoralis major"}', '{}', '{}', 'Execution - Start position: - Arms down and slightly behind your body, elbows slightly bent. - Feel a light stretch across your chest. - Movement: - Bring your hands upward and together in front of your upper chest - roughly at chin to collarbone level. - Use a smooth, controlled motion (avoid jerking). - Squeeze your chest at the top for 1-2 seconds. - Return: - Slowly let your arms move back down and out to the sides, keeping control and tension.', NULL, false),
('High-Incline Smith Machine Press', 'strength', '{"Anterior deltoid","Pectoralis major","Triceps brachii"}', '{}', '{}', 'Set the bench to a 45-60 degrees incline. Touch the upper chest with the bar.', NULL, false),
('Cable Tricep Kickback', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Grab onto the handle, and pull your elbow up and back slightly above your torso. Keep your upper arm to be parallel to the ground for the duration of the set', NULL, false),
('Neutral Grip Lat Pulldown', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Lat pull downs with a neutral grip on the bar.', NULL, false),
('Kong Curl', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'This exercise is somewhat similar to a cable curl and a cable crossover. But instead of a chest/biceps exercise, this exercise targets the brachialis muscle, responsible for that broad arm when viewed from a front view. During the exercise, maintain a pronated forearm position with starting position of approx. 45 degree pronated. Start with slightly bend elbows and alternately curl until your hands (your thumb first) meet your upper middle chest (similar to how Kong hits his chest, thus the name of this exercise).', NULL, false),
('Drop Curl', 'strength', '{"Biceps brachii"}', '{}', '{"Dumbbell"}', 'Drop curls in a modified position at a slow pace effectively engage the brachialis for arm width. Starting position is with both arms in a slight angle towards each other at chest height with a dumbbell in each hand. Lower one dumbbell close to full extended arm position slowly and in a controlled manner during the first half of the curl, then curl it back up to starting position, while the other dumbbell stays at its starting position. Now lower the other dumbbell down. This keeps tension on the brachialis. As we pass the 90deg mark on our way down, the biceps will take over the work.', NULL, false),
('Overhead Cable Tricep Extension', 'strength', '{"Triceps brachii"}', '{}', '{}', 'Use rope handle with your back against the cable machine. Straighten your arms until they are filly extended and reverse the motion resisting on the negative.', NULL, false),
('Lateral Walk', 'strength', '{"Gluteus maximus"}', '{}', '{}', 'Lateral walks, also known as side steps or squat walks, are a type of exercise where you move sideways in a squatting position. They can be performed with or without resistance bands. These exercises strengthen the hip abductors, glutes, and other stabilizing muscles.', NULL, false),
('Leg Press Toe Press', 'strength', '{"Gastrocnemius"}', '{}', '{}', 'Move the leg press using your calves by placing your feet at the bottom of the platform.', NULL, false),
('Handstand', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Handstand free standing by pressing arms into the ground and contracting core and glutes', NULL, false),
('Cable Fly Lower Chest', 'strength', '{"Pectoralis major"}', '{}', '{}', 'Execution - Start position: - Arms extended out to your sides in a "Y" shape. - Feel a stretch in your chest (slight bend in elbows - don't lock them). - Movement: - Bring your hands downward and together in front of your lower chest or upper abs, in a smooth arc motion. - Squeeze your chest hard at the bottom for 1-2 seconds. - Return: - Slowly raise your arms back up along the same path until you feel a good stretch in your chest. - Maintain control - don't let the weights pull you back too quickly.', NULL, false),
('Incline Smith Press', 'strength', '{"Pectoralis major"}', '{}', '{"Incline bench"}', '* Execution * Start position: - Unrack the bar and hold it above your upper chest with arms fully extended. - Keep your shoulder blades retracted and pressed into the bench. - Lowering phase (eccentric): - Slowly bring the bar down to just below your collarbone or upper chest. - Maintain control - don't bounce the bar. - Pressing phase (concentric): - Push the bar upward in a straight line until your arms are fully extended. - Focus on squeezing your upper chest at the top. - Lock and repeat: - Complete your reps, then safely rack the bar back into the hooks.', NULL, false),
('Overhead Triceps Extension', 'strength', '{"Trapezius"}', '{}', '{"SZ-Bar"}', 'Overhead Triceps Extension with EZ Bar - Quick Guide The overhead position emphasizes the long head of the triceps (because it''s stretched under load), the exercise does engage all three triceps heads (long, lateral, and medial) to some degree during extension. - Setup: Sit on a bench (or stand) and hold an EZ bar with a narrow, overhand grip. Lift the bar overhead, arms fully extended. Keep your core tight and elbows close to your head. - Execution: Slowly lower the bar behind your head by bending your elbows until they reach ~90 degrees. Keep elbows pointed forward (not flaring out). - Finish: Extend your arms back up to the starting position, squeezing your triceps at the top. Tips: - Control the movement to avoid straining your shoulders. - Use a moderate weight for full range of motion. - Keep your back straight and avoid arching.', NULL, false),
('Incline Static Hold', 'strength', '{"Pectoralis major"}', '{}', '{"Dumbbell"}', 'Execution - Hold Position: - Lower the dumbbells a few inches above your chest - about the midpoint of a normal incline press. - This is where your upper chest is under maximum tension. - Static Hold: - Hold the position for 20-45 seconds while keeping the chest tight. - Breathe slowly but stay tense - do not relax your chest or shoulders. - End the set: - After the hold, carefully bring the dumbbells down and rest.', NULL, false),
('Pendular hack', 'strength', '{}', '{}', '{}', 'Pendulum hack, made on a pendulum machine', NULL, false),
('Flat Machine Press', 'strength', '{"Pectoralis major"}', '{}', '{"Bench"}', 'Execution - Start position: - Elbows bent at roughly 90 degrees, hands just outside your chest. - Keep wrists straight and aligned with your forearms. - Pressing phase (concentric): - Push the handles forward until your arms are almost fully extended - don't lock out. - Focus on squeezing your chest at the end of the movement. - Returning phase (eccentric): - Slowly bring the handles back toward your chest, feeling the stretch in your pecs. - Maintain tension - don't let the weight stack touch down between reps.', NULL, false),
('Sled Push', 'cardio', '{"Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{"Anterior deltoid","Biceps femoris","Triceps brachii"}', '{}', '- Load the sled with 25% of your maximum load. If you don't know this, choose a weight you can push for 10 minutes with short breaks. Beginners may choose to push the sled with no weight. - Stand behind the sled and grab the poles with a high-grip hand position. - Engage your core muscles and start pushing the sled forward as fast as you can, powering through your entire leg. Extend your hips and knees as you move the sled forward. Your foot stance should resemble your natural running position.', NULL, false),
('Battle Ropes', 'cardio', '{"Biceps femoris","Gluteus maximus","Latissimus dorsi","Obliquus externus abdominis","Quadriceps femoris","Rectus abdominis"}', '{"Anterior deltoid","Biceps brachii","Pectoralis major","Trapezius","Triceps brachii"}', '{}', '- Hold the ends of the rope at arm''s length in front of your hips with your hands shoulder-width apart. - Brace your core and begin alternately raising and lowering each arm explosively. - Keep alternating arms for three to four sets of 1 to 2 minutes.', NULL, false),
('Ball Slams', 'cardio', '{"Latissimus dorsi","Obliquus externus abdominis","Rectus abdominis"}', '{"Anterior deltoid","Gluteus maximus"}', '{}', '- Stand with your feet about shoulder-width apart, your knees and hips slightly bent, holding the ball in both hands at chest height. Engage your core, and keep a good posture. - Extend your knees and drive your hips forward while simultaneously lifting the ball. Aim for being as tall as possible, the ball overhead, arms up, hips slightly forward, and on your toes from the force of your drive. - Use your core and arms to slam the medicine ball straight down between your feet with as much force as possible. Press your hips back and bend your knees to further power the slam. Exhale as you slam the ball down. - Squat down to pick up the ball from the floor, then immediately move into the next slam by repeating the movement. Repeat for reps or time.', NULL, false),
('Ski Machine', 'cardio', '{"Gastrocnemius","Latissimus dorsi","Trapezius","Triceps brachii"}', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris","Rectus abdominis"}', '{}', '- Start standing on the platform with your feet hip-width apart. - Reach overhead to grip the handles with your palms facing in. - Soften your knees, then simultaneously drive your butt back as if you''re closing a door behind you while pulling your arms straight down past your hips until your hands pass by the side of your knees. - Next, bring your arms back overhead while thrusting your hips forward until you''re standing with your arms fully extended. - Repeat for reps, time or distance.', NULL, false),
('Pendulum Squat', 'strength', '{"Quadriceps femoris"}', '{"Biceps femoris","Gluteus maximus"}', '{"none (bodyweight exercise)"}', 'Place your feet in the middle of the plate at about shoulder width. Tense your torso. Keep your neck relaxed.', NULL, false),
('Glute Drive', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris","Quadriceps femoris"}', '{}', 'Lie down on the back pad and strap yourself in with the waistband. Position yout feet shoulder-length apart. They should be slightly splayed.', NULL, false),
('Toes to bar', 'strength', '{}', '{}', '{"Pull-up bar"}', 'The name "Toes to Bar" says it all: This exercise, in which you hang from a pull-up bar, involves bringing your toes toward the bar, pointing toward your face. This really works your abdominal muscles. "Toes to Bar" is popular in functional fitness programs like Freeletics and CrossFit, and is an effective exercise for six-pack training.', NULL, false),
('Lying Dumbbell Curls', 'strength', '{"Biceps brachii"}', '{}', '{"Bench","Dumbbell"}', 'Take a dumbbell in each hand and lie backwards on a bench, similar to a classic chest press. Let your arms hang down at your sides, with the dumbbells possibly touching the floor. Now start to lift the dumbbells upwards until your forearms are perpendicular to the ceiling. Slowly lower the dumbbells until they almost touch the floor again. Keep your ellbows in place to minimize cheating.', NULL, false),
('Cable Curls', 'strength', '{"Biceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Bicep Curls using cables. Can be seated or standing', NULL, false),
('Pull-Ups (Wide Grip)', 'strength', '{"Latissimus dorsi"}', '{}', '{"none (bodyweight exercise)"}', 'Execution - Pulling phase (concentric): - Drive your elbows down and slightly back, pulling your chest toward the bar. - Focus on leading with your chest, not your chin. - Keep your shoulders depressed (avoid shrugging). - Top position: - Chin should clear the bar (or at least reach bar level). - Pause for a brief squeeze in your lats.', NULL, false),
('Barbell Row (Overhand)', 'strength', '{"Latissimus dorsi"}', '{}', '{"Barbell"}', 'Execution - Starting position: - Hold the barbell with arms fully extended toward the floor. - Maintain tension in your lats and back muscles.', NULL, false),
('Barbell Row (Underhand)', 'strength', '{"Latissimus dorsi"}', '{}', '{"Barbell"}', 'Execution - Starting position: - Hold the barbell with arms fully extended toward the floor. - Maintain tension in your lats and back muscles.', NULL, false),
('Delt Stretch', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Stretch your deltoids for a certain period of time.', NULL, false),
('Pull-up Isometric Hold', 'strength', '{"Biceps brachii","Latissimus dorsi","Trapezius"}', '{}', '{"Pull-up bar"}', 'Hold the pull-up movement in any position', NULL, false),
('Barbell Romanian Deadlift (RDL)', 'strength', '{"Latissimus dorsi"}', '{}', '{"Barbell"}', 'Execution - Hinge at the hips: - Push your hips backward, keeping a slight bend in the knees (soft knees). - Lower the barbell along the front of your thighs/shins while maintaining a neutral spine. - Keep the bar close to your body.', NULL, false),
('One-Arm Heavy Row', 'strength', '{"Latissimus dorsi"}', '{}', '{"Dumbbell"}', 'Execution - Rowing phase (concentric): - Pull the dumbbell toward your lower chest or waist, leading with your elbow. - Keep your torso stable - avoid twisting or rotating your shoulders. - Pause at the top and squeeze your lats.', NULL, false),
('Patadas traseras', 'strength', '{"Triceps brachii"}', '{}', '{"Bench","Dumbbell"}', 'The dumbbell kickback is a popular strength training exercise that targets the triceps muscles in the back of your upper arms. It helps strengthen and tone the triceps, contributing to overall arm strength and aesthetics. Among the exercises that work the arm muscles, kickback and its variations are very effective. You can easily apply these exercises with dumbbells, cables or resistance bands.', NULL, false),
('Wide Pull Up', 'strength', '{"Latissimus dorsi"}', '{}', '{"Pull-up bar"}', 'The grip width for a wide grip pull-up is typically wider than shoulder-width apart, which means your hands will be positioned farther apart than they would be for a standard pull-up. This wider grip targets the latissimus dorsi muscles more effectively, making it an excellent exercise for building upper body strength, particularly in the back muscles.', NULL, false),
('Tuck L-sit', 'strength', '{"Rectus abdominis"}', '{"Brachialis","Pectoralis major","Quadriceps femoris","Trapezius","Triceps brachii"}', '{"Bench"}', 'The tuck L-sit is a bodyweight hold where you support yourself on parallel bars, parallettes, or the floor with straight arms while pulling your knees toward your chest. Your hips stay lifted, your spine stays tall, and your feet hover off the ground. The goal is to keep your core tight, shoulders depressed, and arms locked out while maintaining the tucked position. It's a core-intensive, shoulder-stabilizing static hold often used as a progression toward the full L-sit.', NULL, false),
('Archer Pull Up', 'strength', '{"Latissimus dorsi"}', '{"Biceps brachii","Trapezius"}', '{}', 'An archer pull-up is an advanced bodyweight exercise that strengthens your back and biceps, serving as a progression towards a one-arm pull-up. It gets its name from the "bow-drawing" position your body takes at the top.Here''s how to do it:1. Grip: Grasp a pull-up bar with a wider-than-shoulder-width overhand grip.2. Starting Position: Hang with arms fully extended, engaging your core and keeping your shoulder blades pulled down.3. The Pull: Pull your body up towards one hand, similar to a regular pull-up. At the same time, extend the other arm out to the side, keeping it as straight as possible. Your chin should come towards the hand that is pulling.4. Hold & Lower: Briefly hold the top position where one arm is bent and pulling, and the other is extended. Slowly lower yourself back to the starting position with control.5. Alternate: Repeat the movement, pulling up towards the opposite hand.The key to this exercise is to keep the assisting arm as straight as possible to maximise the load on the working arm. This makes it a challenging but effective exercise for unilateral pulling strength.', NULL, false),
('Larsen Press', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"Barbell"}', 'Put your legs up on a separate Bench and press with no leg drive', NULL, false),
('Bulgarian Squat with Dumbbells', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Biceps femoris"}', '{"Dumbbell"}', 'The Bulgarian split squat consists of performing a squat on one leg with the rear foot resting on a raised platform. Elevating your back leg on a bench creates instability and increases the range of motion of the exercise.', NULL, false),
('Stair Master', 'cardio', '{"Biceps femoris","Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'cardio and lower-body strength machine designed to simulate climbing stairs. It provides a low-impact, high-intensity workout that targets the legs, glutes, and core while improving cardiovascular endurance.', NULL, false),
('Butchers Block Stretch', 'strength', '{"Latissimus dorsi"}', '{"Trapezius"}', '{"Bench"}', '- Kneel down with the hands together - Rest the elbows on a bench in front of you and lower the chest down - Keep the elbows bent with good posture and hold', NULL, false),
('Clap Push-UP', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Rectus abdominis","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'The clap push-up is an explosive upper body movement that builds power and fast-twitch muscle strength. It adds a plyometric challenge to the traditional push-up by requiring the hands to leave the ground mid-rep. - Start in a strong push-up position with your hands slightly wider than shoulder-width and core engaged - Lower your body explosively and push off the ground with enough force to lift your hands. - Quickly clap your hands together at chest level before returning them to the floor. - Land with soft elbows to absorb the impact and immediately move into the next rep', NULL, false),
('Sleeper Stretch', 'strength', '{"Anterior deltoid"}', '{"Trapezius"}', '{"none (bodyweight exercise)"}', '- Lie on your side so that you are resting a little weight on your shoulder blade to keep it still - Extend your arm to 90 degrees in front of you, resting on the floor/mat - Lift your hand with your elbow so that your fingers point to the ceiling and your palm points towards your feet - Keeping your elbow still, gently lower your palm toward the floor', NULL, false),
('Bird Dog', 'strength', '{"Rectus abdominis"}', '{"Anterior deltoid","Gluteus maximus"}', '{"none (bodyweight exercise)"}', 'The Bird Dog is a core stability exercise that enhances balance, coordination, and spinal alignment. It's a low-impact movement ideal for strengthening the posterior chain and improving overall functional control. - Begin on all fours with hands under shoulders and knees under hips, keeping your spine neutral. - Extend your right arm forward and left leg backward simultaneously, keeping hips square. - Pause briefly at full extension while engaging your core and glutes. - Return to the starting position and repeat on the opposite side', NULL, false),
('Ab wheel', 'strength', '{"Rectus abdominis"}', '{"Obliquus externus abdominis","Serratus anterior"}', '{"none (bodyweight exercise)"}', '- Starting Position: Kneel on the floor with the ab wheel in front of you. - Grip the Wheel: Hold the handles firmly. - Roll Out: Slowly roll the wheel forward, extending your body while keeping your core tight. - Return: Pull the wheel back towards your knees, maintaining tension in your core.', NULL, false),
('Schwimmen', 'cardio', '{}', '{}', '{}', '- 800m Schwimmen in 20 Minuten', NULL, false),
('Standing Dowel Shoulder press', 'strength', '{}', '{}', '{"Barbell"}', 'Mobility - prone dowel press or standing dowel shoulder press alternating between front andback', NULL, false),
('Snap Down', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Gastrocnemius","Rectus abdominis"}', '{}', 'Begin in a standing position with your arms up over your head and your toes pushing into the ground raising your heels up becoming as tall as you can. From this position, perform a small hop with both feet slightly coming off of the ground. As you land, bend your knees and begin to hinge forward at your hips absorbing the landing. Return to the starting position and repeat. You should feel the muscles in your lower body working. Start with your arms and knees fully straightened out. Keep a stable balance as you land and briefly hold that end position, don't go too fast and become off balanced. Keep your chest up. For a detailed video on landing mechanics, click here: https://youtu.be/RThUCYRDyZw', NULL, false),
('Bretzel stretch', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris","Latissimus dorsi","Pectoralis major"}', '{}', 'How to Perform the Bretzel Stretch Starting Position: Lie on your back on a flat surface, such as a mat. Bend your knees and place your feet flat on the ground. Leg Positioning: Lift your right leg and cross it over your left leg, placing your right foot on the outside of your left knee. Your left leg should remain flat on the ground. Arm Positioning: Extend your left arm out to the side at shoulder height, keeping it straight. Use your right hand to gently pull your right knee towards the floor on the left side of your body. Stretching: As you pull your knee down, try to keep your left shoulder flat on the ground. You should feel a stretch in your hip, lower back, and possibly your chest. Hold the Position: Maintain this position for 20-30 seconds, breathing deeply and relaxing into the stretch. Switch sides and repeat the process.', NULL, false),
('Hip hinge', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{"Gastrocnemius","Quadriceps femoris","Rectus abdominis"}', '{"Barbell"}', 'Hip Hinge Exercise DescriptionThe hip hinge is a fundamental movement pattern that involves bending at the hips while keeping the spine neutral. It is commonly used in exercises like deadlifts, kettlebell swings, and good mornings. To perform a hip hinge: Starting Position: Stand with your feet hip-width apart and a slight bend in your knees. Hinge at the Hips: Push your hips back while maintaining a straight back. Your torso should lean forward, and your chest should stay up. Lowering Phase: Continue to hinge until your torso is nearly parallel to the ground, or until you feel a stretch in your hamstrings. Return to Standing: Drive through your heels and thrust your hips forward to return to the starting position.', NULL, false),
('Bronco', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'Finess test for rugby.5 x shuttle runs of 20m, 40m, and 60m (20yd, 45yd, 65yd/far 45yd mark) Complete as fast as possible', NULL, false),
('Perpendicular Unilateral Landmine Row', 'strength', '{"Anterior deltoid","Trapezius"}', '{}', '{"Barbell"}', 'Using a landmine attachment with the barbell running at 90 degrees to either side, hinge slightly at the hips and grip the barbell by the plate sleeve. Raise the barbell to chest height, with your upper arm parallel to the floor at the top of the movement.', NULL, false),
('Trap press', 'strength', '{"Trapezius"}', '{}', '{"Barbell","Bench","Dumbbell"}', 'Laying flat with arm pointing straight upwards, elbow fully extended, use only your shoulder to raise the weight as high as comfortable and back to rest.', NULL, false),
('Side-laying interior rotation', 'strength', '{"Trapezius"}', '{}', '{"Barbell","Bench","Dumbbell"}', 'Laying on your side and using the arm closest to the bench, maintain a 90 degree bend at the elbow and allow the weight to fall towards the ground past the bench as low as comfortable. Bring the weight up using only rotation of the shoulder to the opposing shoulder.', NULL, false),
('Supine press', 'strength', '{"Trapezius"}', '{}', '{"Barbell","Bench"}', 'Take a close grip and push perpendicular to the bench. Keep back flat.', NULL, false),
('March or jog in place', 'cardio', '{"Biceps femoris","Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{"Anterior deltoid","Biceps brachii","Obliquus externus abdominis","Rectus abdominis","Triceps brachii"}', '{"none (bodyweight exercise)"}', 'Low-impact cardiovascular exercise that simulates running without moving, ideal for warming up, improving endurance, or training in small spaces.', NULL, false),
('Leg and hip stretch', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Latissimus dorsi"}', '{"none (bodyweight exercise)"}', 'Gentle movements to improve the flexibility of the lower body and release tension in the hips.', NULL, false),
('Arm and neck stretch', 'strength', '{"Anterior deltoid","Trapezius","Triceps brachii"}', '{"Latissimus dorsi","Serratus anterior"}', '{"none (bodyweight exercise)"}', 'Relieves tension in the upper body, especially useful for people with office jobs or prolonged postures.', NULL, false),
('Deep breathing (standing or seated)', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'A conscious breathing technique to improve oxygenation, reduce stress and connect with the present moment.', NULL, false),
('Guided or free meditation', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'A mental mindfulness exercise that helps reduce anxiety, improve focus and enhance overall well-being.', NULL, false),
('Smith Machine Split Squat', 'strength', '{"Biceps femoris","Quadriceps femoris"}', '{}', '{"Barbell"}', 'The "Smith Machine Split Squat" is a strength exercise performed on the Smith machine, ideal for targeting the legs and glutes. It involves placing one foot forward and the other back, lowering the body until the front thigh is parallel to the ground while the bar slides vertically along the machine. This exercise helps improve stability, correct muscle imbalances, and reduces stress on the back, providing a safe environment for strength training.', NULL, false),
('Pull-Ups (Neutral Grip)', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Execution - Pulling phase (concentric): - Drive your elbows down and back, pulling your chest toward your hands. - Keep your shoulders depressed and retracted (avoid shrugging). - Focus on squeezing your lats and upper back at the top. - Top position: - Chin should clear or reach the level of your hands. - Pause briefly and contract your lats hard.', NULL, false),
('Reverse Fly Standing', 'strength', '{"Anterior deltoid","Trapezius"}', '{}', '{"Resistance band"}', '- Stand with a good posture holding a cable in each hand opposite the machine - Starting with the hands in front of your chest pull the arms out to your side into the shape of a T with the elbows nearly straight - Slowly release the arms forward to the start - Repeat with the arms moving into the shape of a Y - Repeat with the arms in the shape of a W - Repeat with the arms in the shape of an L by your side', NULL, false),
('Horizontal Shoulder Flexion Stretch', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid"}', '{"none (bodyweight exercise)"}', '- Raise your arm out to the side, placing your hand on a wall or doorway beside you at shoulder height - Turn your body away from your arm to stretch the chest, as far as is comfortable', NULL, false),
('Jalon caballero unialteral', 'strength', '{"Brachialis","Obliquus externus abdominis"}', '{}', '{"Dumbbell"}', 'Pull performed in knight''s stance', NULL, false),
('Dumbbell Scaption', 'strength', '{"Trapezius"}', '{"Anterior deltoid"}', '{"Dumbbell"}', 'Starting position: Stand upright with your feet shoulder-width apart. Hold a dumbbell in each hand with a neutral grip (palms facing each other). Keep a slight bend in your elbows, shoulders relaxed and shoulder blades pulled back. Execution: Slowly raise the dumbbells forward and slightly to the side, at about a 30-45 degrees angle from your body (between a front raise and a lateral raise). Lift until your arms are about shoulder height (do not go overhead). Pause for a second at the top and feel the activation in your shoulders and scapular stabilizers. Lower the dumbbells back down under control to the starting position. Breathing: Inhale as you lower the dumbbells. Exhale as you lift them. Common mistakes: Using dumbbells that are too heavy (causing jerky movements). Lifting above shoulder height (puts unnecessary stress on the shoulder joint). Arching the lower back instead of keeping the movement controlled at the shoulders. Purpose of the exercise: Activates the lower trapezius, serratus anterior, and scapular stabilizers. Helps correct posture and improve shoulder balance.', NULL, false),
('Leg curl with elastic', 'strength', '{"Gastrocnemius"}', '{"Biceps femoris"}', '{"Resistance band"}', 'Standing position: Place the band under your feet in the middle of your foot and grasp it with a hammer grip.', NULL, false),
('Sliding Lateral Lunge', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{"Gastrocnemius","Obliquus externus abdominis"}', '{"Barbell"}', 'Stand upright with your feet hip-width apart, holding a kettlebell close to your chest in goblet position. Place one foot on a slider, gliding disc, or towel. Keep your chest tall and core engaged. Slowly slide the foot outward to the side while bending the opposite knee, lowering your hips into a lateral lunge. Keep the working leg's knee aligned with the toes and avoid letting it collapse inward. The non-working leg remains straight and slides smoothly along the floor. Push through the heel of the bent leg to return to the starting position while maintaining control of the kettlebell.', NULL, false),
('Copenhagen Adduction Exercise', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{"Obliquus externus abdominis","Serratus anterior","Trapezius"}', '{"Bench"}', 'Lie on your side with the elbow placed directly under the shoulder, similar to a side plank position. Place the upper leg on a bench with the inside of the foot or ankle resting on it. Lift your hips and hold your body in a straight line while keeping the lower leg off the floor. The exercise strongly activates the adductors of the upper leg while also challenging the core and hip stabilizers.', NULL, false),
('Arm Raises (T/Y/I)', 'strength', '{"Anterior deltoid","Latissimus dorsi","Serratus anterior","Trapezius"}', '{"Obliquus externus abdominis"}', '{"none (bodyweight exercise)"}', 'Stand upright with feet hip-width apart, core engaged, and arms relaxed at your sides. From this position, perform three different arm raises to target the shoulders and upper back: - T Raise: Lift your arms straight out to the sides until they are parallel to the floor, forming a "T" shape. - Y Raise: Lift your arms upward at about a 45 degrees angle from your body to form a "Y" shape. - I Raise: Raise your arms straight overhead, close together, forming an "I" shape. Maintain a neutral spine, avoid arching your lower back, and move slowly with control. Focus on squeezing your shoulder blades together and keeping your shoulders down away from your ears.', NULL, false),
('Typewriter Pull-ups', 'strength', '{"Biceps brachii","Latissimus dorsi"}', '{"Trapezius"}', '{"none (bodyweight exercise)"}', 'Hang from a pull-up bar with an overhand grip, slightly wider than shoulder-width. Pull yourself up until your chin is above the bar. At the top position, instead of going straight down, shift your body to one side by extending one arm while keeping the other arm bent. Move smoothly from one side to the other, like a typewriter motion, before lowering yourself back down. This exercise increases time under tension and strengthens the lats, biceps, and shoulders while building unilateral pulling strength.', NULL, false),
('Bodyweight Biceps Curl', 'strength', '{"Biceps brachii"}', '{}', '{"none (bodyweight exercise)"}', 'Set up under a straight bar (around waist or chest height). Grip the bar with your palms facing you (supinated grip), hands about shoulder-width apart. Lean back with straight arms so that your body is at an angle to the ground. Keeping your elbows high and close to the bar, pull your upper body toward the bar by flexing your elbows, similar to a biceps curl. Lower yourself back down in a controlled manner. Keep your core tight and movement slow to maximize tension on the biceps.', NULL, false),
('Glute Kickback (Machine)', 'strength', '{"Gluteus maximus"}', '{}', '{}', 'Drive through your heel, not your toes, to hit the glute. Don't hyperextend your lower back at the top.', NULL, false),
('Standing Adduction (Cable)', 'strength', '{}', '{}', '{}', 'Keep your hips square and still, pulling the cable across your opposing leg using only your inner thigh. Don't let your torso lean or twist - no side bending to help the rep.', NULL, false),
('Seated Row (Machine)', 'strength', '{"Latissimus dorsi"}', '{"Anterior deltoid","Trapezius"}', '{}', 'Keep your chest up and squeeze your shoulder blades at the end. Don't hunch forward or round your back during the pull.', NULL, false),
('kettlebell sumo deadlift', 'strength', '{"Biceps femoris","Gluteus maximus","Quadriceps femoris"}', '{}', '{"Kettlebell"}', 'Place your feet wider than shoulder-width apart, pointing your toes outward. Keep your back straight, shoulders back, and chest up. The knees must follow the same direction as the toes and not move forward. When going up, it is advisable to contract your glutes to maximize the effectiveness of the exercise..', NULL, false),
('rubber band glute kickback', 'strength', '{"Gluteus maximus"}', '{}', '{"Resistance band"}', 'A rubber band glute kickback is an exercise performed on hands and knees, where you anchor a resistance band to your foot and kick your heel back and up, squeezing your glute at the top of the movement, while maintaining a stable core and flat back to target and strengthen the gluteal muscles.', NULL, false),
('Cat-Cow', 'strength', '{}', '{}', '{}', 'On all fours. Arch spine up (cat) then drop it down (cow). Breathe with movement.', NULL, false),
('Treadmill Cardio', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'It''s a cardiovascular workout performed on a treadmill to improve endurance, burn calories, and promote heart health. It offers multiple benefits, such as the ability to easily adjust speed and incline, allowing for a variety of workouts, from hill walking to high-intensity interval training (HIIT) and tempo runs. To optimize results, it''s important to vary your workouts. Benefits of Treadmill Cardio: - Improved Cardiovascular Health: Regular aerobic exercise on a treadmill strengthens the heart and lungs, which can help prevent heart disease. - Weight Loss: By burning calories, treadmill training can be an effective tool for weight loss and maintaining a healthy weight. - Muscle Strengthening: It strengthens the muscles in the legs and glutes, helping to prevent muscle loss, which is especially important with age. - Training Flexibility: Allows you to vary speed, incline, and intervals, making your workout more dynamic and adaptable to different fitness levels. Types of Treadmill Training: - Hill Walking: Increasing the incline of the treadmill and walking at a brisk pace can improve endurance and work your leg muscles. - Endurance Jog: A run at a comfortable, steady pace that keeps your heart rate in a target zone (such as Zone 2) to build endurance. - Interval Training: Alternating periods of high intensity (fast running) with periods of low intensity (easy walking or jogging) to maximize calorie burn and cardiovascular improvement. - Tempo Run: A run at a steady, sustained pace that is slightly faster than a normal jog, which challenges your ability to sustain a more intense effort for an extended period.', NULL, false),
('Dumbbell donkey kick', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{}', '{"Dumbbell"}', 'The dumbbell donkey kick is an effective exercise for working the glute and hamstring muscles. This exercise is usually performed on all fours, using a dumbbell to add resistance. The steps for performing it correctly are described below. Starting position: Get on all fours on a mat, with your hands aligned under your shoulders and your knees aligned under your hips. Placing the dumbbell: Take a dumbbell and place it behind the knee of the leg you are going to lift. Make sure it is held securely to prevent it from falling during the exercise. Exercise: Inhale and, as you exhale, lift the leg with the dumbbell upward, keeping the knee bent at a 90-degree angle. Raise the leg until it is parallel to the floor, feeling the contraction in the glutes. Hold the position for one second at the top and then slowly lower the leg back to the starting position. Repetitions: Perform 10 to 15 repetitions per leg, making sure to maintain good form throughout the exercise. Sets: Complete 2 to 3 sets, depending on your fitness level.', NULL, false),
('SMR Glutes (lax ball)', 'strength', '{}', '{}', '{}', 'SMR Glutes (lax ball) Part of: Limber 11 Source: Joe DeFranco Prescription: 30 sec-2 min Type: soft_tissue', NULL, false),
('Stationary bike cardio', 'cardio', '{}', '{}', '{"none (bodyweight exercise)"}', 'Benefits of Stationary Bike Cardio Stationary bike cardio is an excellent form of exercise that offers multiple benefits for health and well-being. Here are some of the most notable ones: Improved Cardiovascular Health Strengthens the heart: Regular exercise helps improve the heart''s efficiency and reduce the risk of cardiovascular disease. Increases circulation: It improves blood flow, which can help lower blood pressure. Calorie Burning and Weight Loss Efficient for burning calories: Depending on the intensity, you can burn between 400 and 600 calories per hour. Helps with weight loss: Combined with a balanced diet, stationary bike cardio can be effective for losing weight. Muscle Strengthening Tones the legs: It mainly works the leg muscles, including the quadriceps, hamstrings and calves. Improves muscular endurance: Over time, you can increase the endurance and strength in your legs. Mental Health Benefits Reduces stress: Exercise releases endorphins, which can improve your mood and reduce stress. Boosts energy: Regular physical activity can raise your energy levels and improve sleep quality.', NULL, false),
('Straight-Arm Pulldown (Cable)', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Keep arms straight but not locked, pulling with your lats, not your shoulders. Don't let your shoulders shrug up during the movement.', NULL, false),
('Seated Dumbbell Calf Raise', 'strength', '{"Gastrocnemius"}', '{}', '{"Dumbbell"}', 'The seated dumbbell calf raise is a targeted exercise for strengthening the lower leg muscles. It follows the same movement pattern as the machine version: you place the weight on your knees, and by extending and flexing your ankles, you move the weight.', NULL, false),
('Side Straight-Arm Pulldown (Cable)', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Keep your torso still, pulling the handle down along your side using the outer lat. Don't twist your body or rotate your torso to cheat the rep.', NULL, false),
('Shoulder Internal Rotation (Cable)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Keep your elbow tucked to your side like it''s superglued there. Don't rotate your torso - only your forearm should move.', NULL, false),
('Shoulder External Rotation (Cable)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Keep elbow fixed at your side and rotate forearm outward smoothly. Don't let your wrist or elbow drift upward - stay in one plane.', NULL, false),
('Side Lateral Raise (Cable)', 'strength', '{"Latissimus dorsi"}', '{}', '{}', 'Lift with your elbows leading, not your hands. Don't shrug your shoulders; keep traps quiet.', NULL, false),
('Front Raise (Cable)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Raise the handle in a slight arc with controlled movement. Don't swing your torso to start the rep.', NULL, false),
('Face pulls with yellow/green band', 'strength', '{"Latissimus dorsi"}', '{"Trapezius"}', '{"Resistance band"}', 'Face pulls with band - standing horizontal pull. Grab the band at face height, pull elbows high and wide towards your face while squeezing shoulder blades together. Trains upper back, rear shoulders and improves posture.', NULL, false),
('Isometric Squat to Failure', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{}', '{"none (bodyweight exercise)"}', 'sometric Squat to Failure: A Strength Training Technique Definition The isometric squat to failure is a variation of the squat exercise where you hold a static squat position at a specific angle, maintaining the position until your muscles can no longer sustain the contraction.', NULL, false),
('Single-Leg Lunge with Kettlebell:', 'strength', '{"Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{}', '{"Kettlebell"}', 'How to do a single-leg kettlebell lunge Preparation: Stand with your feet together. Hold the kettlebell with both hands by the handle, keeping it close to your chest, or hold it with one hand (on the same side as the working leg). Step and Lower: Take a large step forward (or backward, which is safer for your knees) with one leg, lowering your hips until both knees form a 90-degree angle. Focus: Shift your weight onto your front (or bent) leg, keeping your back straight and your torso upright. Return: Push off with your front leg to return to the starting position.', NULL, false),
('Single-leg side glute press', 'strength', '{"Gastrocnemius","Gluteus maximus","Quadriceps femoris"}', '{}', '{"Incline bench"}', 'The Single-Leg Side Glute Press is a leg press machine variation where you angle your body sideways on the pad, placing one foot high and slightly angled to press the weight, powerfully targeting the outer glute (gluteus medius/minimus) and hamstrings for balanced leg development and stability, requiring focus on pushing through the heel and maintaining control without locking out. How to Perform: Setup: Sit in the leg press machine, rotate your body to one hip, placing one foot high on the platform at about a 45-degree angle with toes pointed slightly out/forward. Positioning: Keep your hip, knee, and ankle aligned, and ensure your lower back stays on the pad. Descent: Slowly lower the weight, allowing your knee to bend deeply (near 90 degrees), feeling a stretch in your glute and hamstring. Press: Drive through your heel (not your toes) to press the weight back up, squeezing your glutes and hamstrings, stopping just before your leg fully extends. Control: Avoid bouncing and don''t let your lower back lift off the pad; maintain tension throughout the movement.', NULL, false),
('Assisted chin-ups', 'strength', '{}', '{}', '{}', 'Chin-ups with machine assistance (counterweights)', NULL, false),
('Neutral-grip pull-ups or TRX rows', 'strength', '{"Latissimus dorsi"}', '{"Biceps brachii"}', '{"Pull-up bar"}', '- Pull-Up: Vertical Pull - Focuses more on the Lats (back width). TRX Row: Horizontal Pull - Focuses more on the Rhomboids/Traps (mid-back thickness and posture).', NULL, false),
('Shrimp Squad', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Single leg squad where one leg is behind you.', NULL, false),
('L-Sit Pull-ups', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'L-Sit Pull-ups train both upper body and core muscles.', NULL, false),
('Back Lever', 'strength', '{}', '{}', '{"Pull-up bar","none (bodyweight exercise)"}', 'Hanging from a pull-up bar facing downwards with your arms extended', NULL, false),
('Windshield Wipers', 'strength', '{"Obliquus externus abdominis","Rectus abdominis"}', '{}', '{"Pull-up bar","none (bodyweight exercise)"}', 'Hang from a pull-up bar, raise your legs to the ceiling. Move lower body from left to right with straight legs like a windshield wiper', NULL, false),
('Machine Side Lateral Raises', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'Machine side lateral raises are an isolation exercise for the side (lateral) deltoids, performed on a machine for stability, targeting the outer shoulder by lifting pads or handles out to the sides to shoulder height, then lowering slowly, keeping elbows slightly bent and traps down to focus on the delts. This exercise helps build shoulder width by preventing swinging and providing constant tension, making it great for beginners or as a finisher. How to Perform Machine Lateral Raises Setup: Adjust the seat so your shoulders align with the machine''s pivot point, your chest is against the pad (or back if facing out), and your arms are at a 90-degree angle with the pads/handles. Starting Position: Grip the handles with a relaxed grip, elbows slightly bent, and shoulders down (depressed) away from your ears. Lifting Phase: Exhale and lift your arms out to the sides, moving your upper arms laterally, until they are parallel to the floor. Peak Contraction: Pause briefly at the top, squeezing the side delts, but don''t shrug your shoulders up. Lowering Phase: Inhale and slowly lower the weight back down with control, resisting the weight on the way down.', NULL, false),
('Cable Front Raise with a small bar', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'The Cable Front Raise with a small bar isolates your anterior deltoids (front shoulders) by providing constant tension, requiring you to stand facing away from a low pulley, grab the bar with an overhand grip, and lift it in front of you to shoulder height with slightly bent arms, avoiding swinging and keeping your core tight for controlled movement up and down. Use a light-to-moderate weight, focusing on slow, controlled reps to feel the muscle work, not momentum. How to Perform the Cable Front Raise (Bar) Setup: Attach a small straight bar to a low cable pulley. Set the weight to a light or moderate setting. Starting Position: Stand with your back to the machine, holding the bar with an overhand grip (palms facing down) at hip level, arms extended but not locked. Feet shoulder-width apart, core braced, shoulders back and down. The Lift: Exhale and slowly raise the bar straight up in front of you, keeping a slight bend in your elbows, until your hands reach shoulder height (or slightly below). The Hold: Pause briefly at the top, squeezing your front delts. The Lower: Inhale as you slowly and controllably lower the bar back to the starting position, maintaining tension.', NULL, false),
('Smith machine squat', 'strength', '{"Gluteus maximus","Quadriceps femoris"}', '{}', '{}', 'Technique and Execution The Smith machine squat is a variation of the traditional barbell squat that uses a guided, fixed-path barbell. Here''s a detailed breakdown of the proper technique: Starting Position Foot Placement: Position feet slightly forward of the bar, about shoulder-width apart Bar Position: Rest the bar on your upper trapezius/shoulders, similar to a traditional back squat Stance: Feet can be slightly angled outward for natural hip rotation Squat Movement Unrack the bar by rotating it to release from the safety hooks Slowly lower your body by bending knees and hips Descend until thighs are parallel to the ground (or slightly below) Pause briefly at the bottom of the movement Drive through your heels to return to the starting position Benefits and Considerations Advantages Reduced Balance Requirements: Fixed bar path makes it easier for beginners Controlled Movement: Less risk of improper form compared to free weight squats Isolation: Allows focused leg muscle development', NULL, false),
('Cable pull through', 'strength', '{"Gluteus maximus"}', '{"Biceps femoris","Gastrocnemius","Quadriceps femoris","Soleus"}', '{}', 'The Cable Pull Through is a lower-body exercise that targets the glutes and hamstrings using a "hip hinge" motion. To perform it, attach a rope to the lowest pulley setting, face away from the machine with the rope between your legs, and step forward to create tension. Keeping your back flat and knees slightly soft, push your hips backward as if trying to close a door behind you until you feel a deep stretch in your hamstrings. To finish the rep, explosively drive your hips forward to return to a standing position, squeezing your glutes hard at the top. It is vital to remember that this is not a squat; your knees should not bend deeply, and your arms should remain straight and relaxed, acting only as hooks for the rope. This movement provides constant tension on the glutes while placing less stress on the lower back than a traditional deadlift.', NULL, false),
('Side lateral raise - Front (Cable)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'in a cablerack do a side lateral raise with cable in front of you, with focus in tension on the back of your shoulder.', NULL, false),
('Side lateral raise - Back (Cable)', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'on a cable rack do a side lateral raise with the cable behind you. focus on tension in the front of the shoulder.', NULL, false),
('Shoulder Y-pull cable', 'strength', '{}', '{}', '{}', 'on a cable rack cross the cables and pull elbows to ceiling close to the body.', NULL, false),
('Plank Reach', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Position your body in plank position, keeping your eyes on the ground. Raise one arm in front of you and return it. Repeat with the other arm. Raise and return slowly while keeping your body as still as possible.', NULL, false),
('Reverse crunch', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', '- Lay down - Place your hands near your butt (often slightly in front or under or both) - Raise your legs, but about 70% of the way you should be able to also raise your pelvis - (optional/variable) Hold 1/2 seconds at the top - Go back to starting position', NULL, false),
('Legend Incline Bench Press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{}', 'incline bench press on LeverEdge machine.', NULL, false),
('Single-Leg Deadlift with Dumbbell', 'strength', '{"Biceps femoris","Gluteus maximus"}', '{}', '{"Dumbbell"}', 'Starting Position: Stand upright with a slight bend in your knees, holding a dumbbell in one or both hands. Shift your weight onto your supporting leg (e.g., your right leg) and lift your non-supporting foot slightly off the floor. The Hinge: Keeping your back flat and core engaged, hinge at your hips, pushing your glutes backward. As your torso lowers, extend your non-supporting leg straight back behind you for balance, keeping your hips square to the floor. The dumbbell(s) should lower toward the ground along the line of your supporting leg. Range of Motion: Continue lowering your torso until it is nearly parallel to the floor, or you feel an intense stretch in your supporting hamstring, ensuring your back remains neutral throughout the movement. Return to Start: Pause at the bottom, then contract your glutes and hamstrings to slowly raise your torso back to the starting position. Your non-supporting leg should return in line with the supporting one. Switch Sides: After completing your desired number of repetitions on one side, switch your weight and repeat the movement on the other leg.', NULL, false),
('Single Leg Glute Bridge', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', 'A glute bridge, where you use just one leg at a time.', NULL, false),
('Machine Hip Abduction', 'strength', '{"Gluteus maximus"}', '{}', '{}', 'Technique and Execution Starting Position Seated Positioning: Sit in the machine with back against the pad Leg Placement: Inner thighs against the machine''s padded resistance points Adjust Machine: Set seat position to align your hip joint with the machine''s pivot point Movement Technique Start with legs together or slightly pressed against the inner pads Slowly push legs outward, spreading them apart Move until maximum comfortable lateral range is reached Pause briefly at the outer point of the movement Slowly return to the starting position with controlled movement Biomechanical Breakdown Muscle Engagement Primary Activation: Gluteus Medius (side hip muscle) Stabilization: Engages core and lower back muscles Functional Movement: Mimics lateral leg movement used in walking, sports, and daily activities Benefits Strength and Stability Improves Hip Stability Reduces Risk of Knee Injuries Enhances Lateral Movement Capabilities Targets Often-Neglected Muscle Groups', NULL, false),
('Wrist curl, cable', 'strength', '{}', '{"Biceps brachii"}', '{}', '- Extend your arm down, then slightly lift your forearm - Extend your wrist in a supinated form (palm up) - Adjust cable height so that the cable handle is in your supinated hand - Perform the movement by curling your palms and wrists upwards - (optional/variable) Pause at the top - Slowly return to the starting position', NULL, false),
('Chair dips', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Starting position: Sit down on the front edge of a chair, back straight, hands holding the front edge. Still holding the edge of the chair, arms extended, lift your butt and walk forward slightly so that it is a few inches from the chair. Steps: - Slowly lower your body, keeping the back straight, until your arms are at a right angle. - Raise your body again to the initial position, arms extended. - Repeat.', NULL, false),
('Pec deck rear delt fly', 'strength', '{}', '{}', '{}', 'Seated rear delt fly on pec deck machine (facing the machine and extending arms backwards, the hands should be at the height of the shoulders)', NULL, false),
('Deficit Push ups', 'strength', '{"Pectoralis major"}', '{"Triceps brachii"}', '{"none (bodyweight exercise)"}', 'Pushup on blocks or grips, so you can dip lower than the hands in the decent.', NULL, false),
('Butterfly Stretch', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', '- Sit in a prayer position with the soles of your feet gently pressed together. - Use your hands to slowly pull your feet inwards towards your groin. Hold for as long as required.', NULL, false),
('Frog Stretch', 'strength', '{"Gluteus maximus"}', '{}', '{"none (bodyweight exercise)"}', '- Get on your hands and knees. - Widen your knees outwards, and drop to your elbows. - Without moving your elbows or knees, start to rock forwards and backwards, trying to get your bum closer to your feet.', NULL, false),
('Landmine Rotation', 'strength', '{}', '{}', '{"Barbell"}', 'Start with landmine barbell straight up by using your shoulders to push it up above you. Then, from that position, bring it your side to target your abdominals and return to starting position.', NULL, false),
('Supino inclinado', 'strength', '{}', '{}', '{}', 'Inclinado 90 graus e movimentos leves e precisos', NULL, false),
('unilateral cross body cable pull down', 'strength', '{"Anterior deltoid"}', '{}', '{}', 'on a cable rack place cable high, and with a straight arm pull that cable across you from high to low. focus on tension in back shoulder.', NULL, false),
('Ring Support Hold', 'strength', '{}', '{}', '{}', 'Hold yourself in a support position on gymnastic rings with arms straight at sides. Focus on keeping rings turned out slightly and maintaining hollow body position. This is an isometric hold for chest, shoulders, and triceps.', NULL, false),
('Floor Glider Hamstring Curls', 'strength', '{}', '{}', '{}', 'Lie on back with heels on floor gliders or towels. Lift hips into a bridge, then slide heels toward glutes while keeping hips elevated. Slowly return to the starting position while maintaining the hip bridge.', NULL, false),
('Trap Bar Squat', 'strength', '{"Quadriceps femoris"}', '{"Biceps femoris"}', '{}', 'A combination of squat and deadlift principles with the use of a hex/trap bar, easing stress on the lower back by better centering the weight.', NULL, false),
('ankle dorsiflexion rocks', 'strength', '{"Gastrocnemius","Soleus"}', '{}', '{"none (bodyweight exercise)"}', 'Move your knee forward, keeping your heel on the ground. Hold the position for a couple of seconds and return to the starting position.', NULL, false),
('Lat Pull Down', 'strength', '{"Latissimus dorsi"}', '{"Anterior deltoid","Brachialis","Serratus anterior","Trapezius"}', '{}', 'The lat pull down is an exercise used to build the muscles of the back. While the exercise will primarily target the lats, you will also notice a fair amount of bicep and middle back activation.', NULL, false),
('Parallel Bar Hold', 'strength', '{"Anterior deltoid","Pectoralis major","Triceps brachii"}', '{"Latissimus dorsi","Obliquus externus abdominis","Rectus abdominis"}', '{}', '- Stand between a set of parallel bars. - Place your hands, knuckles outwards, on the bars. - Push down on your hands to lift yourself off the floor. - Hold yourself in this position with your arms straight for the required time.', NULL, false),
('Sphinx', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Lie on your stomach flat, legs extended and the backs of your feet on the ground. Bring your forearms under your shoulders, elbows directly underneath. Then press your hands into the floor to lift your chest. Draw your shoulder blades together, open your collarbones, and direct your gaze forward, while keeping the lower back relaxed.', NULL, false),
('Open Book', 'strength', '{}', '{}', '{"none (bodyweight exercise)"}', 'Basic exercise - Focus: enhances thoracic mobility and spinal segmentation while opening the shoulders and chest. - **Position:**kneeling on the floor with your right side facing a wall. Hips are square and stable, with the right knee down and the left foot forward. Lengthen your spine and align your head comfortably. Begin with your arms relaxed and open in front of your chest, palms facing each other and hands apart. - Inhale to initiate the movement, allowing your left arm -the one farther from the wall- to open outward and backward. Lead the twist from your thoracic spine, rotating your upper back progressively while keeping your pelvis still. - Exhale as you complete the rotation, guiding your left hand toward the wall as your gaze follows your hand. - Return by inhaling and slowly bringing your arm forward, reversing the spinal rotation segment by segment. - Repeat on the opposite side. Progression - **Position:**kneeling on the floor with your right side facing a wall. Left knee down and right foot forward. - Before the basic exercise: inhale, exhalewhile moving the right arm along the wall with a circle upwards and backwards, inhalewhile bringing back the arm. - Basic exercise. - Repeat on the opposite side.', NULL, false),
('Dumbell Tate Press', 'strength', '{"Triceps brachii"}', '{"Anterior deltoid","Pectoralis major"}', '{"Bench","Dumbbell"}', '- Set Up: Lie flat with a dumbbell in each hand. Extend your arms straight up over your chest as if you were at the top of a dumbbell bench press - Starting Position: Position the dumbbells so they are touching or very close together with a pronated grip (palms facing your feet and thumbs facing each other) - Lowering: Without moving your upper arms or shoulders, bend your elbows and flare them outward to the sides. Lower the inner ends of the dumbbells toward the center of your chest - Touch and Pause: Gently touch the dumbbells to your chest. Do not rest the weight on your body; maintain constant tension in your triceps - Press: Forcefully extend your elbows to return the dumbbells to the starting position. Focus on "pushing your pinkies toward the sky" to maximize triceps engagement https://www.youtube.com/watch?v=IgSjoXbpy1M&t=2', NULL, false),
('Chest-Supported Rear Delt Raise', 'strength', '{"Anterior deltoid"}', '{"Trapezius"}', '{"Bench","Dumbbell"}', '"The Y"Position: Set an incline bench to 30-45 degrees. Lie face-down with your chest supported, keeping your head neutral or looking slightly down to avoid neck strain.Grip: Hold light dumbbells with a neutral or thumbs-up grip (thumb pointing to the ceiling).Movement: With straight or slightly bent elbows, raise the dumbbells up and out in a "Y" shape. Focus on moving the shoulders and shoulder blades rather than just lifting the arms.Top Position: Squeeze the shoulder blades together and reach high, ensuring the arms are angled to form a "Y".Control: Lower the dumbbells slowly to the starting position.', NULL, false),
('Band pull-apart with external rotation', 'strength', '{"Anterior deltoid"}', '{}', '{"Resistance band"}', 'Stand tall with your feet shoulder-width apart, chest out, and shoulders back. Hold the resistance band with both hands, palms facing up or facing each other, depending on the band type. Bend your elbows at a 90-degree angle and glue your upper arms to your sides. The band should have some tension in the starting position, with your hands closer together in front of your stomach. Rotate Outward: While keeping your elbows tucked into your sides, slowly move your hands away from each other, stretching the band. Squeeze: Squeeze your shoulder blades together and down as you rotate your hands outward. Range of Motion: Rotate your hands as far outward as you comfortably can without allowing your elbows to leave your sides. Hold: Hold the end position for 1-2 seconds to maximize muscle engagement. Return: Slowly and with control, bring your hands back to the starting position.', NULL, false),
('Double-Leg Abdominal Press', 'strength', '{"Rectus abdominis"}', '{}', '{"Gym mat","none (bodyweight exercise)"}', 'Lie on your back with knees and hips bent at 90 degrees (tabletop). Place your hands on your thighs just above your knees. Push your hands against your knees as hard as possible while using your abs to pull your knees toward your hands. Hold for 10 seconds of maximum effort. Your abs should be shaking.', NULL, false),
('Abdominal Draw-In', 'strength', '{"Rectus abdominis"}', '{}', '{"none (bodyweight exercise)"}', 'Lie on your back with knees bent. Gently pull your belly button toward your spine without moving your hips or holding your breath.', NULL, false),
('Landmine Squat to Press', 'strength', '{"Anterior deltoid","Gluteus maximus","Quadriceps femoris"}', '{"Biceps femoris","Rectus abdominis"}', '{"Barbell"}', 'Bar Position: Anchor one end of a barbell in a landmine attachment or a secure corner. Stance: Stand facing the barbell with feet slightly wider than shoulder-width. Turn your toes out 10-35 degrees to allow for better pelvic movement and depth. Grip: Cup the free end of the barbell with both hands (fingers interlaced or overlapping) and hold it at mid-chest level, just below the collarbone. Descent: Brace your core and sit back into a squat, keeping your chest up and weight on your heels. Depth: Lower until your thighs are at least parallel to the floor. A good reference is when your elbows touch the tops of your thighs or just inside your knees. Posture: Ensure your back remains flat and your spine neutral throughout the movement. Drive: Powerfully drive through your heels to stand up. Use the momentum from your legs to "thrust" the weight upward. Extension: In one fluid motion, press the bar overhead until your arms are fully extended. At the top, your biceps should be near your ears. The "Lean": As you reach the top of the press, lean slightly forward into the bar to encourage proper upward rotation of the shoulder blades and avoid lower back arching. Slowly lower the barbell back to chest height in a controlled manner before immediately beginning the next repetition.', NULL, false),
('Barbell Step Back Lunge', 'strength', '{"Quadriceps femoris"}', '{}', '{"Barbell"}', 'Step 1: Stand with your feet hip-width apart, holding a barbell on your upper back. Step 2: Keep your back straight, chest up, and core engaged. Step 3: Take a step back with one leg and lower your body by bending both knees. Ensure that your back knee nearly touches the ground. Step 4: Push off your back foot to return to the starting position. Step 5: Repeat the movement with the other leg. Continue alternating between legs for the desired repetitions.', NULL, false),
('Hammerstrength Decline Chest Press', 'strength', '{"Pectoralis major"}', '{"Anterior deltoid","Triceps brachii"}', '{}', '- Sit upright in a hammerstrength decline chest press machine while squeezing your shoulder blades together and placing your heels firmly on the ground underneath your knees. - The back pad should be contact with your head, shoulders, and butt at all times. - Grab ahold of the handles with an overhand grip just outside shoulder-width apart just below your chest. - Keeping your core braced by breathing into your stomach and flexing the abdominal muscles, push through your palms to extend your elbows while keeping them at a 45 degree angle from your torso. - Once your arms are fully extended, return to the starting position.', NULL, false),
('Trap-3 Raise', 'strength', '{"Trapezius"}', '{}', '{"none (bodyweight exercise)"}', '- Hinge forwards and bend your knees slightly. Depress and retract the shoulder you will use. Rest the other hand on your knee. - Raise your hand about 15 degrees overhead, maintaining the position of your shoulder.', NULL, false),
('External Rotation Stretch', 'strength', '{"Anterior deltoid","Trapezius"}', '{}', '{"Barbell"}', '- Sit with your feet pressed against each other, and one knee raised all the way out to the side of your body. - Place your elbow on your raised knee, bend it at 90 degrees, and point your hand directly forward, holding your barbell/dumbbell. - Keep your shoulder depressed and retracted, raise your hand until your forearm is vertical, as if you were about to wave at someone like a robot. - Lower your hand to the original position and repeat.', NULL, false),
('Banded Shoulder Drills', 'strength', '{"Anterior deltoid","Pectoralis major","Trapezius"}', '{}', '{"Resistance band"}', '- Attach a resistance band to something solid behind you. Stand away from it, holding it in your hand so it is taut. - See the attached youtube video: https://www.youtube.com/watch?v=zdwEWchSjrI .', NULL, false),
